// MIGRATION HELPER
const migrateState = (oldState: any): AppState => {
    let accounts: Account[] = oldState.categories || oldState.accounts || DEFAULT_ACCOUNTS;
    // Map legacy 'categories' to 'accounts' if needed
    if (oldState.categories && !oldState.accounts) {
        // Simple mapping for migration - in a real app this would be more complex
        accounts = DEFAULT_ACCOUNTS; 
    }

    let parties: Party[] = oldState.entities || oldState.parties || SEED_PARTIES;
    // ensure parties is array
    if(!Array.isArray(parties)) parties = SEED_PARTIES;

    return {
        ...oldState,
        accounts: accounts.length > 0 ? accounts : DEFAULT_ACCOUNTS,
        parties: parties,
        transactions: oldState.transactions || [],
        receivables: oldState.receivables || [],
        assets: oldState.assets || [],
        templates: oldState.templates || [],
        recurring: oldState.recurring || [],
        businessProfile: oldState.businessProfile || { name: 'My Business', address: '', email: '', phone: '' }
    };
};

type Action =
  | { type: 'ADD_TRANSACTION'; payload: Transaction }
  | { type: 'UPDATE_TRANSACTION'; payload: Transaction }
  | { type: 'DELETE_TRANSACTION'; payload: string }
  | { type: 'ADD_ACCOUNT'; payload: Account }
  | { type: 'UPDATE_ACCOUNT'; payload: Account }
  | { type: 'DELETE_ACCOUNT'; payload: string }
  | { type: 'ADD_RECEIVABLE'; payload: Receivable }
  | { type: 'UPDATE_RECEIVABLE'; payload: Receivable }
  | { type: 'DELETE_RECEIVABLE'; payload: string }
  | { type: 'ADD_TEMPLATE'; payload: TransactionTemplate }
  | { type: 'DELETE_TEMPLATE'; payload: string }
  | { type: 'ADD_PARTY'; payload: Party }
  | { type: 'UPDATE_PARTY'; payload: Party }
  | { type: 'DELETE_PARTY'; payload: string }
  | { type: 'ADD_ASSET'; payload: Asset }
  | { type: 'UPDATE_ASSET'; payload: Asset }
  | { type: 'DELETE_ASSET'; payload: string }
  | { type: 'UPDATE_BUSINESS_PROFILE'; payload: BusinessProfile }
  | { type: 'SET_MONTHLY_BUDGET'; payload: MonthlyBudget }
  | { type: 'ADD_RECURRING'; payload: RecurringTransaction }
  | { type: 'UPDATE_RECURRING'; payload: RecurringTransaction }
  | { type: 'DELETE_RECURRING'; payload: string }
  | { type: 'PROCESS_RECURRING_UPDATES'; payload: { transactions: Transaction[], updatedRecurring: RecurringTransaction[] } }
  | { type: 'PROCESS_ASSET_DEPRECIATION'; payload: { transactions: Transaction[], updatedAssets: Asset[] } }
  | { type: 'RESET_DATA' }
  | { type: 'SET_STATE'; payload: any };

const rawState = storageService.load();
const initialState: AppState = rawState ? migrateState(rawState) : {
    transactions: SEED_TRANSACTIONS,
    accounts: DEFAULT_ACCOUNTS,
    receivables: SEED_RECEIVABLES,
    templates: [],
    recurring: [],
    parties: SEED_PARTIES,
    assets: SEED_ASSETS,
    businessProfile: { name: 'My Business', email: '', phone: '', address: '' }
};

const financeReducer = (state: AppState, action: Action): AppState => {
  let newState: AppState;
  const timestamp = new Date().toISOString();
  const withTime = (s: AppState) => ({ ...s, lastUpdated: timestamp });

  switch (action.type) {
    case 'SET_STATE': return migrateState(action.payload);
    case 'ADD_TRANSACTION':
      newState = withTime({ ...state, transactions: [action.payload, ...state.transactions] });
      break;
    case 'UPDATE_TRANSACTION':
      newState = withTime({ ...state, transactions: state.transactions.map(t => t.id === action.payload.id ? action.payload : t) });
      break;
    case 'DELETE_TRANSACTION':
      const txToDelete = state.transactions.find(t => t.id === action.payload);
      let updatedReceivables = state.receivables;
      if (txToDelete && txToDelete.relatedPartyId) {
          const relatedRec = state.receivables.find(r => r.id === txToDelete.relatedPartyId);
          if (relatedRec) {
               if (txToDelete.note?.includes('Accrual')) {
                   updatedReceivables = state.receivables.filter(r => r.id !== txToDelete.relatedPartyId);
               }
               else if (relatedRec.status === 'paid') {
                   updatedReceivables = state.receivables.map(r => 
                       r.id === txToDelete.relatedPartyId ? { ...r, status: 'pending', paidDate: undefined } : r
                   );
               }
          }
      }
      newState = withTime({ 
          ...state, 
          transactions: state.transactions.filter(t => t.id !== action.payload),
          receivables: updatedReceivables
      });
      break;
    case 'ADD_ACCOUNT':
      newState = withTime({ ...state, accounts: [...state.accounts, action.payload] });
      break;
    case 'UPDATE_ACCOUNT':
      newState = withTime({ ...state, accounts: state.accounts.map(c => c.id === action.payload.id ? action.payload : c) });
      break;
    case 'DELETE_ACCOUNT':
      newState = withTime({ ...state, accounts: state.accounts.filter(c => c.id !== action.payload) });
      break;
    case 'ADD_RECEIVABLE':
      newState = withTime({ ...state, receivables: [action.payload, ...state.receivables] });
      break;
    case 'UPDATE_RECEIVABLE':
      newState = withTime({ ...state, receivables: state.receivables.map(r => r.id === action.payload.id ? action.payload : r) });
      break;
    case 'DELETE_RECEIVABLE':
      const recId = action.payload;
      const associatedTxIds = state.transactions.filter(t => t.relatedPartyId === recId).map(t => t.id);
      newState = withTime({ 
          ...state, 
          receivables: state.receivables.filter(r => r.id !== action.payload),
          transactions: state.transactions.filter(t => !associatedTxIds.includes(t.id))
      });
      break;
    case 'ADD_TEMPLATE':
      newState = withTime({ ...state, templates: [...state.templates, action.payload] });
      break;
    case 'DELETE_TEMPLATE':
      newState = withTime({ ...state, templates: state.templates.filter(t => t.id !== action.payload) });
      break;
    case 'ADD_PARTY':
      newState = withTime({ ...state, parties: [...state.parties, action.payload] });
      break;
    case 'UPDATE_PARTY':
      newState = withTime({ ...state, parties: state.parties.map(e => e.id === action.payload.id ? action.payload : e) });
      break;
    case 'DELETE_PARTY':
      newState = withTime({ ...state, parties: state.parties.filter(e => e.id !== action.payload) });
      break;
    case 'ADD_ASSET':
      newState = withTime({ ...state, assets: [...state.assets, action.payload] });
      break;
    case 'UPDATE_ASSET':
      newState = withTime({ ...state, assets: state.assets.map(a => a.id === action.payload.id ? action.payload : a) });
      break;
    case 'DELETE_ASSET':
      newState = withTime({ ...state, assets: state.assets.filter(a => a.id !== action.payload) });
      break;
    case 'UPDATE_BUSINESS_PROFILE':
      newState = withTime({ ...state, businessProfile: action.payload });
      break;
    case 'SET_MONTHLY_BUDGET':
      const budgets = state.monthlyBudgets || [];
      const existingIndex = budgets.findIndex(b => b.monthKey === action.payload.monthKey);
      let newBudgets;
      if (existingIndex >= 0) {
          const existing = budgets[existingIndex];
          newBudgets = [...budgets];
          newBudgets[existingIndex] = action.payload;
      } else {
          newBudgets = [...budgets, action.payload];
      }
      newState = withTime({ ...state, monthlyBudgets: newBudgets });
      break;
    case 'ADD_RECURRING':
      const currentRec = state.recurring || [];
      newState = withTime({ ...state, recurring: [...currentRec, action.payload] });
      break;
    case 'UPDATE_RECURRING':
      newState = withTime({ ...state, recurring: (state.recurring || []).map(r => r.id === action.payload.id ? action.payload : r) });
      break;
    case 'DELETE_RECURRING':
      newState = withTime({ ...state, recurring: (state.recurring || []).filter(r => r.id !== action.payload) });
      break;
    case 'PROCESS_RECURRING_UPDATES':
        newState = withTime({
            ...state,
            transactions: [...action.payload.transactions, ...state.transactions],
            recurring: state.recurring.map(r => {
                const updated = action.payload.updatedRecurring.find(ur => ur.id === r.id);
                return updated || r;
            })
        });
        break;

    case 'PROCESS_ASSET_DEPRECIATION':
        newState = withTime({
            ...state,
            transactions: [...action.payload.transactions, ...state.transactions],
            assets: state.assets.map(a => {
                const updated = action.payload.updatedAssets.find(ua => ua.id === a.id);
                return updated || a;
            })
        });
        break;
    case 'RESET_DATA':
      storageService.clear(); 
      newState = { ...initialState, lastUpdated: new Date(0).toISOString() };
      break;
    default:
      return state;
  }

  storageService.save(newState);
  return newState;
};

interface FinanceContextType {
  state: AppState;
  dispatch: React.Dispatch<Action>;
  syncConfig: SyncConfig;
  updateSyncConfig: (cfg: SyncConfig) => void;
  refreshData: () => Promise<void>;
  pushDataManual: () => Promise<void>;
  syncStatus: 'offline' | 'syncing' | 'synced' | 'error';
  lastError?: string;
  user: User | null;
  authLoading: boolean;
  authMethods: {
      login: (e: string, p: string) => Promise<any>;
      signUp: (e: string, p: string) => Promise<any>;
      signInWithGoogle: () => Promise<any>;
      logout: () => Promise<void>;
  };
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, dispatch] = useReducer(financeReducer, initialState);
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  const [syncConfig, setSyncConfig] = useState<SyncConfig>(() => {
    const saved = storageService.loadSyncConfig();
    return saved || { supabaseUrl: SUPABASE_URL, supabaseKey: SUPABASE_KEY, enabled: true };
  });

  const [syncStatus, setSyncStatus] = useState<'offline' | 'syncing' | 'synced' | 'error'>('offline');
  const [lastError, setLastError] = useState<string | undefined>(undefined);
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  const isRemoteUpdate = useRef(false);
  const isPullingRef = useRef(false); 

  useEffect(() => {
    let timeout: ReturnType<typeof setTimeout>;
    if (syncStatus === 'syncing') {
        timeout = setTimeout(() => {
            console.warn("Sync timed out");
            setSyncStatus(navigator.onLine ? 'synced' : 'offline'); 
            isPullingRef.current = false; 
        }, 10000); 
    }
    return () => clearTimeout(timeout);
  }, [syncStatus]);

  const performPull = useCallback(async (currentUser: User) => {
    if (!navigator.onLine || !currentUser) { setSyncStatus('offline'); return; }
    if (isPullingRef.current) return; 

    isPullingRef.current = true;
    setSyncStatus('syncing');
    setLastError(undefined);

    try {
        const { data, error } = await supabaseService.pullData(currentUser.id);

        if (error) {
            console.warn("Sync Pull Error:", error);
            if (String(error).includes('404') || String(error).includes('406') || String(error).includes('PGRST116')) {
                 console.log("New user detected, pushing seed data.");
                 const { error: pushError } = await supabaseService.pushData(currentUser.id, stateRef.current);
                 if (pushError) setLastError(String(pushError));
                 setSyncStatus('synced');
            } else {
                 setLastError(String(error));
                 setSyncStatus('error');
            }
        } else if (data) {
            isRemoteUpdate.current = true;
            // Ensure migration happens on pull
            dispatch({ type: 'SET_STATE', payload: data });
            console.log("Loaded user data successfully");
            setSyncStatus('synced');
        } else {
             setSyncStatus('synced');
        }
    } catch (e) {
        console.error("Pull execution error:", e);
        setSyncStatus('error');
    } finally {
        isPullingRef.current = false;
    }
  }, []); 

  // AUTH & INITIALIZATION
  useEffect(() => {
    if (syncConfig.supabaseUrl && syncConfig.supabaseKey) {
        supabaseService.updateClient(syncConfig.supabaseUrl, syncConfig.supabaseKey);
    }

    const { data: { subscription } } = supabaseService.auth.onAuthStateChange(async (event, session) => {
        const currentUser = session?.user ?? null;
        setUser(currentUser);
        setAuthLoading(false); 

        if (event === 'SIGNED_IN' && currentUser) {
            performPull(currentUser); 
        } else if (event === 'SIGNED_OUT') {
            dispatch({ type: 'RESET_DATA' });
            setSyncStatus('offline');
            setUser(null);
            isPullingRef.current = false;
        }
    });

    supabaseService.auth.getUser().then((currentUser) => {
        setAuthLoading(false); 
        if (currentUser) {
            setUser(currentUser);
            performPull(currentUser);
        }
    });

    return () => {
        subscription.unsubscribe();
    };
  }, [syncConfig, performPull]); 

  // Check online status
  useEffect(() => {
    const handleOnline = () => { if(user) setSyncStatus('synced'); };
    const handleOffline = () => setSyncStatus('offline');
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
        window.removeEventListener('online', handleOnline);
        window.removeEventListener('offline', handleOffline);
    };
  }, [user]);

  // Automated Checks (Recurring & Depreciation)
  useEffect(() => {
      const recurringRules = state.recurring || [];
      if (recurringRules.length === 0 && !state.assets) return;
      const now = new Date();
      const newRecTransactions: Transaction[] = [];
      const updatedRecurring: RecurringTransaction[] = [];

      recurringRules.forEach(rule => {
          if (rule.active && rule.nextDueDate) {
              const dueDate = parseISO(rule.nextDueDate);
              if (isPast(dueDate)) {
                  newRecTransactions.push({
                      id: Math.random().toString(36).substr(2, 9),
                      date: new Date().toISOString(), 
                      type: rule.type,
                      amount: rule.amount,
                      currency: rule.currency,
                      originalAmount: rule.originalAmount,
                      accountId: rule.accountId,
                      source: rule.source,
                      paymentAccountId: rule.paymentAccountId,
                      relatedPartyId: rule.partyId,
                      note: `Recurring: ${rule.note || 'Auto Transaction'}`
                  });

                  let nextDate = dueDate;
                  if (rule.frequency === 'daily') nextDate = addDays(nextDate, 1);
                  if (rule.frequency === 'weekly') nextDate = addWeeks(nextDate, 1);
                  if (rule.frequency === 'monthly') nextDate = addMonths(nextDate, 1);
                  if (rule.frequency === 'yearly') nextDate = addYears(nextDate, 1);

                  updatedRecurring.push({
                      ...rule,
                      lastRunDate: new Date().toISOString(),
                      nextDueDate: nextDate.toISOString()
                  });
              }
          }
      });

      if (newRecTransactions.length > 0) {
          dispatch({ type: 'PROCESS_RECURRING_UPDATES', payload: { transactions: newRecTransactions, updatedRecurring } });
      }

      // DEPRECIATION LOGIC
      const newDepTransactions: Transaction[] = [];
      const updatedAssets: Asset[] = [];
      // Look for Accounts by code
      const depExpAccount = state.accounts.find(c => c.code === '60900');
      const accumDepAccount = state.accounts.find(c => c.code === '12900');

      if (depExpAccount && accumDepAccount && state.assets) {
          state.assets.forEach(asset => {
              if (asset.value <= 0) return;
              const monthlyAmount = asset.originalValue / (asset.usefulLifeYears * 12);
              let nextRunDate = asset.lastDepreciationDate 
                  ? addMonths(parseISO(asset.lastDepreciationDate), 1)
                  : addMonths(parseISO(asset.purchaseDate), 1); 
              let assetValue = asset.value;
              let lastRun = asset.lastDepreciationDate;
              let hasUpdates = false;

              while (isBefore(nextRunDate, now)) {
                  hasUpdates = true;
                  newDepTransactions.push({
                      id: Math.random().toString(36).substr(2, 9),
                      date: nextRunDate.toISOString(),
                      type: 'expense',
                      accountId: depExpAccount.id, // Debit Expense
                      paymentAccountId: accumDepAccount.id, // Credit Accum Dep
                      amount: monthlyAmount,
                      currency: asset.currency,
                      originalAmount: monthlyAmount,
                      source: 'personal',
                      note: `Auto Depreciation: ${asset.name} (${format(nextRunDate, 'MMM yyyy')})`
                  });
                  assetValue -= monthlyAmount;
                  lastRun = nextRunDate.toISOString();
                  nextRunDate = addMonths(nextRunDate, 1);
                  if (assetValue <= 0) { assetValue = 0; break; }
              }

              if (hasUpdates) {
                  updatedAssets.push({ ...asset, value: Math.max(0, assetValue), lastDepreciationDate: lastRun });
              }
          });

          if (newDepTransactions.length > 0) {
              dispatch({ type: 'PROCESS_ASSET_DEPRECIATION', payload: { transactions: newDepTransactions, updatedAssets } });
          }
      }

  }, [state.accounts, state.assets, state.recurring, state.transactions.length]);

  // Push on state change
  useEffect(() => {
    if (syncStatus === 'offline' || !navigator.onLine || !user) return;
    if (syncStatus === 'syncing') return; 

    if (isRemoteUpdate.current) { isRemoteUpdate.current = false; return; }
    if (syncStatus === 'error') return; 

    const push = async () => {
      if (isPullingRef.current) return; 
      setSyncStatus('syncing');
      setLastError(undefined);
      const { error } = await supabaseService.pushData(user.id, state);
      if (error) {
        setLastError(String(error));
        setSyncStatus('error');
      } else {
        setSyncStatus('synced');
      }
    };
    const timeout = setTimeout(push, 3000); 
    return () => clearTimeout(timeout);
  }, [state]); 

  const pushDataManual = async () => {
      if(!user) return;
      setSyncStatus('syncing');
      const { error } = await supabaseService.pushData(user.id, state);
      if (error) { setSyncStatus('error'); alert("Upload Failed: " + (error.message || error)); } 
      else { setSyncStatus('synced'); alert("Upload Successful!"); }
  }

  const updateSyncConfig = (cfg: SyncConfig) => {
    setSyncConfig(cfg);
    storageService.saveSyncConfig(cfg); 
  };

  const refreshData = async () => {
      if (user) await performPull(user);
  };

  const authMethods = {
      login: (e: string, p: string) => supabaseService.auth.login(e, p),
      signUp: (e: string, p: string) => supabaseService.auth.signUp(e, p),
      signInWithGoogle: () => supabaseService.auth.signInWithGoogle(),
      logout: async () => {
          setUser(null);
          setSyncStatus('offline');
          dispatch({ type: 'RESET_DATA' });
          isPullingRef.current = false;
          try {
            await supabaseService.auth.logout();
          } catch (e) {
            console.error("Supabase logout warning:", e);
          }
      }
  };

  return (
    <FinanceContext.Provider value={{ state, dispatch, syncConfig, updateSyncConfig, refreshData, pushDataManual, syncStatus, lastError, user, authLoading, authMethods }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useMemo, useState } from 'react';
import { AppState } from '../types';
import { format, parseISO, startOfMonth, endOfMonth } from 'date-fns';
import { SearchableSelect } from './ui/SearchableSelect';
import { FileDown, ArrowRight, FileText, Building2, Download, Printer } from 'lucide-react';

interface SOAProps {
  appState: AppState;
}

export const StatementOfAccount: React.FC<SOAProps> = ({ appState }) => {
  const [selectedAccountId, setSelectedAccountId] = useState('');
  const [dateRange, setDateRange] = useState({
    start: format(startOfMonth(new Date()), 'yyyy-MM-dd'),
    end: format(endOfMonth(new Date()), 'yyyy-MM-dd')
  });

  const selectedAccount = appState.accounts.find(c => c.id === selectedAccountId);

  // Filter options to only show posting accounts (GL or Sub-ledger)
  const accountOptions = useMemo(() => {
    return appState.accounts
      .filter(a => a.isPosting)
      .map(c => ({
        id: c.id,
        label: c.name,
        subLabel: c.code,
        color: c.normalBalance === 'debit' ? '#3b82f6' : '#ef4444'
      })).sort((a,b) => a.subLabel.localeCompare(b.subLabel));
  }, [appState.accounts]);

  // Calculation Logic
  const ledgerData = useMemo(() => {
    if (!selectedAccountId) return null;

    // 1. Sort all transactions by date ascending
    const allTxs = [...appState.transactions].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    const startDate = parseISO(dateRange.start);
    const endDate = parseISO(dateRange.end);
    endDate.setHours(23, 59, 59, 999);

    let runningBalance = 0;
    let openingBalance = 0;
    const rows: any[] = [];
    let totalDebits = 0;
    let totalCredits = 0;

    const account = appState.accounts.find(a => a.id === selectedAccountId);
    if(!account) return null;

    // Normal Balance Logic:
    // If Debit Normal: Dr adds, Cr subtracts.
    // If Credit Normal: Cr adds, Dr subtracts.
    const isDrNormal = account.normalBalance === 'debit';

    allTxs.forEach(t => {
      const txDate = parseISO(t.date);
      let debit = 0;
      let credit = 0;
      let isRelevant = false;

      // In the new Transaction Model:
      // accountId = Dr (usually expense or asset increase)
      // paymentAccountId = Cr (usually asset decrease or liability increase)
      // Exception: Income Type implies reversed logic in traditional UI forms, but stored consistently?
      // Let's rely on IDs.

      if (t.accountId === selectedAccountId) {
          // This account was Debited
          debit = t.amount;
          isRelevant = true;
      } else if (t.paymentAccountId === selectedAccountId) {
          // This account was Credited
          credit = t.amount;
          isRelevant = true;
      }

      if (isRelevant) {
        // Calculate impact on balance based on Normal Balance
        let impact = 0;
        if (isDrNormal) {
             impact = debit - credit;
        } else {
             impact = credit - debit;
        }

        if (txDate < startDate) {
          openingBalance += impact;
          runningBalance += impact;
        } else if (txDate <= endDate) {
          runningBalance += impact;
          totalDebits += debit;
          totalCredits += credit;

          rows.push({
            ...t,
            debit,
            credit,
            balance: runningBalance
          });
        }
      }
    });

    return {
      openingBalance,
      rows,
      closingBalance: runningBalance,
      totalDebits,
      totalCredits,
      account
    };

  }, [selectedAccountId, dateRange, appState.transactions, appState.accounts]);

  const handlePrint = () => window.print();

  const formatMoney = (amount: number) => {
      return amount.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  return (
    <div className="space-y-6">
      {/* Control Bar */}
      <div className="no-print bg-gray-900 p-4 rounded-xl border border-gray-800 flex flex-col md:flex-row gap-4 items-end shadow-lg">
        <div className="flex-1 w-full">
          <label className="text-[10px] text-gray-500 uppercase font-bold mb-1 block">Select Ledger Account</label>
          <SearchableSelect 
            options={accountOptions}
            value={selectedAccountId}
            onChange={setSelectedAccountId}
            placeholder="Search GL or Sub-ledger..."
          />
        </div>
        <div className="flex flex-wrap gap-2 items-center w-full md:w-auto">
            <div>
                <label className="text-[10px] text-gray-500 uppercase font-bold mb-1 block">Start Date</label>
                <input 
                    type="date" 
                    className="bg-gray-950 border border-gray-700 text-white text-sm rounded-lg px-3 py-2 outline-none focus:border-primary transition-colors w-full md:w-auto"
                    value={dateRange.start}
                    onChange={e => setDateRange(prev => ({...prev, start: e.target.value}))}
                />
            </div>
            <div className="hidden md:block">
                <ArrowRight className="text-gray-600 mt-6" size={16} />
            </div>
            <div>
                <label className="text-[10px] text-gray-500 uppercase font-bold mb-1 block">End Date</label>
                <input 
                    type="date" 
                    className="bg-gray-950 border border-gray-700 text-white text-sm rounded-lg px-3 py-2 outline-none focus:border-primary transition-colors w-full md:w-auto"
                    value={dateRange.end}
                    onChange={e => setDateRange(prev => ({...prev, end: e.target.value}))}
                />
            </div>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
            <button 
                onClick={handlePrint}
                disabled={!selectedAccountId}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-500 text-white rounded-lg font-bold transition-colors disabled:opacity-50 disabled:cursor-not-allowed h-[42px] shadow-lg shadow-blue-900/20"
            >
                <Printer size={18} /> Print
            </button>
        </div>
      </div>

      {selectedAccount && ledgerData ? (
        <div className="w-full overflow-x-auto pb-6 custom-scrollbar">
            <div id="soa-print-area" className="bg-white text-slate-900 p-8 md:p-12 rounded-xl shadow-2xl min-h-[800px] min-w-[900px] max-w-6xl mx-auto animate-fade-in relative">

                {/* Header */}
                <div className="flex justify-between items-start border-b-2 border-slate-800 pb-6 mb-8">
                    <div className="flex gap-4">
                        <div className="p-3 bg-slate-900 rounded-lg text-white h-fit">
                            <Building2 size={32} />
                        </div>
                        <div>
                            <h1 className="text-3xl font-bold text-slate-900 tracking-tight uppercase">{appState.businessProfile.name}</h1>
                            <div className="text-sm text-slate-600 mt-2 space-y-1">
                                <p>{appState.businessProfile.address}</p>
                                <p>{appState.businessProfile.email}</p>
                                <p>{appState.businessProfile.phone}</p>
                            </div>
                        </div>
                    </div>
                    <div className="text-right">
                        <h2 className="text-2xl font-bold text-slate-800 uppercase tracking-widest mb-2">Statement of Account</h2>
                        <div className="bg-slate-100 p-3 rounded-lg text-sm text-slate-600 border border-slate-200 inline-block text-right">
                             <div className="flex justify-between gap-4"><span className="font-bold">Account:</span> <span>{selectedAccount.name}</span></div>
                             <div className="flex justify-between gap-4"><span className="font-bold">GL Code:</span> <span className="font-mono">{selectedAccount.code}</span></div>
                             <div className="flex justify-between gap-4"><span className="font-bold">Period:</span> <span>{dateRange.start} to {dateRange.end}</span></div>
                        </div>
                    </div>
                </div>

                {/* Summary Cards */}
                <div className="grid grid-cols-4 gap-4 mb-8">
                     <div className="p-4 bg-gray-50 rounded-lg border border-gray-200">
                         <span className="block text-xs font-bold text-gray-500 uppercase">Opening Balance</span>
                         <span className="text-xl font-bold text-slate-700">{formatMoney(ledgerData.openingBalance)}</span>
                     </div>
                     <div className="p-4 bg-emerald-50 rounded-lg border border-emerald-100">
                         <span className="block text-xs font-bold text-emerald-600 uppercase">Total Debits</span>
                         <span className="text-xl font-bold text-emerald-700">+{formatMoney(ledgerData.totalDebits)}</span>
                     </div>
                     <div className="p-4 bg-red-50 rounded-lg border border-red-100">
                         <span className="block text-xs font-bold text-red-600 uppercase">Total Credits</span>
                         <span className="text-xl font-bold text-red-700">-{formatMoney(ledgerData.totalCredits)}</span>
                     </div>
                     <div className="p-4 bg-slate-800 text-white rounded-lg border border-slate-700">
                         <span className="block text-xs font-bold text-slate-400 uppercase">Closing Balance</span>
                         <span className="text-xl font-bold">{formatMoney(ledgerData.closingBalance)}</span>
                     </div>
                </div>

                {/* Table */}
                <table className="w-full text-sm text-left border-collapse">
                    <thead>
                        <tr className="bg-slate-800 text-white uppercase text-xs">
                            <th className="py-3 px-4 border-r border-slate-600">Date</th>
                            <th className="py-3 px-4 border-r border-slate-600 w-1/3">Description</th>
                            <th className="py-3 px-4 border-r border-slate-600 text-right bg-emerald-900">Debit</th>
                            <th className="py-3 px-4 border-r border-slate-600 text-right bg-red-900">Credit</th>
                            <th className="py-3 px-4 text-right">Balance</th>
                        </tr>
                    </thead>
                    <tbody>
                        {/* Opening Balance Row */}
                        <tr className="bg-yellow-50 text-slate-600 font-medium italic border-b border-gray-200">
                             <td className="py-3 px-4">{dateRange.start}</td>
                             <td className="py-3 px-4">Balance Brought Forward</td>
                             <td className="py-3 px-4 text-right">-</td>
                             <td className="py-3 px-4 text-right">-</td>
                             <td className="py-3 px-4 text-right font-bold">{formatMoney(ledgerData.openingBalance)}</td>
                        </tr>

                        {ledgerData.rows.map((row, idx) => (
                            <tr key={idx} className="border-b border-gray-200 hover:bg-gray-50 transition-colors">
                                <td className="py-3 px-4 text-slate-600 font-mono">{row.date.split('T')[0]}</td>
                                <td className="py-3 px-4 text-slate-800 font-medium">{row.note || row.type}</td>
                                <td className="py-3 px-4 text-right font-mono text-emerald-700 font-bold bg-emerald-50/30">
                                    {row.debit > 0 ? formatMoney(row.debit) : ''}
                                </td>
                                <td className="py-3 px-4 text-right font-mono text-red-700 font-bold bg-red-50/30">
                                    {row.credit > 0 ? formatMoney(row.credit) : ''}
                                </td>
                                <td className="py-3 px-4 text-right font-mono font-bold text-slate-900 bg-gray-50">
                                    {formatMoney(row.balance)}
                                </td>
                            </tr>
                        ))}

                        {ledgerData.rows.length === 0 && (
                            <tr><td colSpan={5} className="py-12 text-center text-slate-400 italic">No transactions in this period.</td></tr>
                        )}
                    </tbody>
                    <tfoot className="bg-slate-100 font-bold text-slate-800 border-t-2 border-slate-300">
                        <tr>
                            <td colSpan={2} className="py-4 px-4 text-right uppercase text-xs">Period Totals</td>
                            <td className="py-4 px-4 text-right text-emerald-700">{formatMoney(ledgerData.totalDebits)}</td>
                            <td className="py-4 px-4 text-right text-red-700">{formatMoney(ledgerData.totalCredits)}</td>
                            <td className="py-4 px-4 text-right bg-slate-200">{formatMoney(ledgerData.closingBalance)}</td>
                        </tr>
                    </tfoot>
                </table>

                {/* Footer */}
                <div className="mt-12 pt-6 border-t border-gray-200 text-center text-slate-500 text-xs">
                    This is a computer-generated document. No signature is required. <br/>
                    Generated by Tarmi FinTrack Pro on {format(new Date(), 'yyyy-MM-dd HH:mm')}
                </div>
            </div>
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-20 text-gray-500 bg-gray-900/50 rounded-2xl border border-gray-800 border-dashed">
            <FileText size={48} className="mb-4 opacity-50" />
