                  <span className="text-2xl font-bold text-white">QR {totalSelectedCash.toLocaleString()}</span>
              </div>
              <div className="space-y-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                  {assetBalances.map(acc => (
                      <div key={acc.id} className="flex items-center justify-between p-2 rounded-lg bg-gray-950/50 border border-white/5 cursor-pointer hover:bg-gray-800/50" onClick={() => setCheckedAssets(prev => ({...prev, [acc.id]: !prev[acc.id]}))}>
                          <div className="flex items-center gap-2">
