          {/* BUSINESS PROFIT CARD (GROSS ONLY) */}
          <div className="glass-card p-5 rounded-2xl bg-gray-900 border border-blue-500/20 cursor-pointer transition-all hover:border-blue-500/40" onClick={() => setShowProfitDetails(!showProfitDetails)}>
              <div className="flex justify-between items-start">
                  <div>
