            <button onClick={() => setShowGenericInstruction(false)} className="w-full py-3 bg-gray-800 hover:bg-gray-700 rounded-xl mt-4 text-sm font-bold">Close</button>
            </div>
      </Modal>
    </div>
  );
};

import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Receivable, Transaction, CurrencyCode, RecurrenceFrequency } from '../types';
import { EXCHANGE_RATE_QAR_TO_PHP } from '../constants';
import { format, isPast, addWeeks, addMonths, addYears, addDays } from 'date-fns';
import { Plus, CheckCircle, ArrowDownLeft, Repeat, Trash2, Pencil, HandCoins, FileText } from 'lucide-react';
import { Modal } from '../components/ui/Modal';
import { InvoiceModal } from '../components/InvoiceModal';
import { SearchableSelect } from '../components/ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';

export const Receivables: React.FC = () => {
  const { state, dispatch } = useFinance();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [transactionMode, setTransactionMode] = useState<'invoice' | 'loan'>('invoice');
  const [invoiceData, setInvoiceData] = useState<Receivable | null>(null);

  // Payment Modal State
  const [paymentModalOpen, setPaymentModalOpen] = useState(false);
  const [selectedReceivable, setSelectedReceivable] = useState<Receivable | null>(null);
  const [paymentTargetAccount, setPaymentTargetAccount] = useState('');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [partyId, setPartyId] = useState('');
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState<CurrencyCode>('QAR');
  const [dueDate, setDueDate] = useState('');
  const [notes, setNotes] = useState('');
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');
  const [targetAccountId, setTargetAccountId] = useState(''); // Revenue Account (Invoice) OR Source Account (Loan)

  // Options for Selects
  const customerOptions = state.parties
    .filter(e => e.type === 'customer')
    .map(c => ({ id: c.id, label: c.name }));

  const revenueOptions = state.accounts
    .filter(c => c.class === 'Revenue' && c.isPosting)
    .map(c => ({ id: c.id, label: c.name, subLabel: c.code }));

  const cashAccountOptions = state.accounts
    .filter(c => c.class === 'Assets' && c.isPosting) // Assume Assets can be cash/bank
    .map(c => ({ id: c.id, label: c.name, subLabel: c.code }));

  const openAdd = (mode: 'invoice' | 'loan') => {
      resetForm();
      setTransactionMode(mode);
      setIsModalOpen(true);
      // For Loan, pre-select default bank if available
      if(mode === 'loan') {
          const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank'));
          if(bank) setTargetAccountId(bank.id);
      }
  };

  const openEdit = (item: Receivable) => {
      setEditingId(item.id);
      setTransactionMode(item.subType === 'loan' ? 'loan' : 'invoice');
      setPartyId(item.partyId || '');
      setAmount((item.originalAmount || item.amount).toString());
      setCurrency(item.currency || 'QAR');
      setDueDate(item.dueDate.split('T')[0]);
      setNotes(item.notes || '');
      setIsRecurring(!!item.recurring?.active);
      setRecurFreq(item.recurring?.frequency || 'monthly');
      setTargetAccountId(item.targetAccountId || '');
      setIsModalOpen(true);
  };

  const handleAmountBlur = () => {
      setAmount(evaluateMathExpression(amount));
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmountStr = evaluateMathExpression(amount);
    if (!targetAccountId) {
        alert(transactionMode === 'invoice' ? "Please select a Revenue Account" : "Please select a Source Account (Payout From)");
        return;
    }

    const inputAmount = parseFloat(finalAmountStr);
    if (isNaN(inputAmount)) {
        alert("Invalid amount");
        return;
    }

    const finalAmountQAR = currency === 'PHP' ? inputAmount / EXCHANGE_RATE_QAR_TO_PHP : inputAmount;
    const party = state.parties.find(e => e.id === partyId);
    const newId = editingId || Math.random().toString(36).substr(2, 9);

    const payload: Receivable = {
      id: newId,
      type: 'receivable',
      subType: transactionMode,
      partyId,
      partyName: party?.name || 'Unknown',
      targetAccountId,
      amount: finalAmountQAR,
      originalAmount: inputAmount,
      currency,
      dueDate: new Date(dueDate).toISOString(),
      status: 'pending',
      notes,
      recurring: isRecurring ? {
          active: true,
          amount: inputAmount,
          frequency: recurFreq,
          nextDueDate: dueDate 
      } : undefined
    };

    if (editingId) {
        dispatch({ type: 'UPDATE_RECEIVABLE', payload });
    } else {
        dispatch({ type: 'ADD_RECEIVABLE', payload });

        // Note: 'asset_ar' should ideally be looked up from DEFAULT_ACCOUNTS or state
        const arAccount = state.accounts.find(a => a.name.includes('Accounts Receivable'))?.id || '11200';

        if (transactionMode === 'invoice') {
            const accrualTx: Transaction = {
                id: Math.random().toString(36).substr(2, 9),
                date: new Date().toISOString(),
                type: 'income', // Or revenue
                amount: finalAmountQAR,
                originalAmount: inputAmount,
                currency,
                accountId: targetAccountId, // Revenue Cr (in this logic)
                source: 'side_hustle',
                paymentAccountId: arAccount, // AR Dr
                note: `Accrual: Invoice #${newId.substr(0,4)} - ${notes}`,
                relatedPartyId: partyId
            };
            dispatch({ type: 'ADD_TRANSACTION', payload: accrualTx });
        } else {
            const loanTx: Transaction = {
                id: Math.random().toString(36).substr(2, 9),
                date: new Date().toISOString(),
                type: 'transfer',
                amount: finalAmountQAR,
                originalAmount: inputAmount,
                currency,
                accountId: arAccount, // AR Dr (Asset Increase)
                source: 'personal',
                paymentAccountId: targetAccountId, // Bank Cr (Asset Decrease)
                note: `Personal Loan Given: #${newId.substr(0,4)} - ${notes}`,
                relatedPartyId: partyId
            };
            dispatch({ type: 'ADD_TRANSACTION', payload: loanTx });
        }
    }

    setIsModalOpen(false);
    resetForm();
  };

  const resetForm = () => {
    setEditingId(null); setPartyId(''); setAmount(''); setCurrency('QAR'); setDueDate(''); setNotes(''); setIsRecurring(false); setTargetAccountId('');
  };

  const handleDelete = (id: string) => {
      if(confirm('Delete this receivable? Associated Journal Entries will also be removed.')) {
          dispatch({ type: 'DELETE_RECEIVABLE', payload: id });
      }
  }

  const openPaymentModal = (item: Receivable) => {
      setSelectedReceivable(item);
      setPaymentModalOpen(true);
      const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank'));
      setPaymentTargetAccount(bank ? bank.id : '');
  };

  const handlePaymentSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedReceivable || !paymentTargetAccount) return;

      const item = selectedReceivable;
      const updated: Receivable = { 
          ...item, status: 'paid', paidDate: new Date().toISOString()
      };
      dispatch({ type: 'UPDATE_RECEIVABLE', payload: updated });

      const arAccount = state.accounts.find(a => a.name.includes('Accounts Receivable'))?.id || '11200';

      const paymentTx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: new Date().toISOString(),
          type: 'income', 
          amount: item.amount,
          originalAmount: item.originalAmount,
          currency: item.currency || 'QAR',
          accountId: arAccount, // AR Cr (Asset Decrease - usually credited in income tx logic here as paymentAccountId is Dr)
          // Wait, Transaction model for Income: paymentAccountId is Dr (Asset), accountId is Cr (Revenue/Source).
          // Here we are closing AR. Dr Bank, Cr AR.
          // So: paymentAccountId = Bank, accountId = AR.
          source: item.subType === 'loan' ? 'personal' : 'side_hustle',
          paymentAccountId: paymentTargetAccount, 
          note: `Payment Received: ${item.subType === 'loan' ? 'Loan Repayment' : 'Invoice'} #${item.id.substr(0,4)}`,
          relatedPartyId: item.partyId
      };
      dispatch({ type: 'ADD_TRANSACTION', payload: paymentTx });

      if (item.recurring && item.recurring.active) {
        let nextDate = new Date(item.dueDate);
        if (item.recurring.frequency === 'daily') nextDate = addDays(nextDate, 1);
        if (item.recurring.frequency === 'weekly') nextDate = addWeeks(nextDate, 1);
        if (item.recurring.frequency === 'monthly') nextDate = addMonths(nextDate, 1);
        if (item.recurring.frequency === 'yearly') nextDate = addYears(nextDate, 1);

        const nextItem: Receivable = {
            ...item,
            id: Math.random().toString(36).substr(2, 9),
            dueDate: nextDate.toISOString(),
            status: 'pending',
            paidDate: undefined
        };
        dispatch({ type: 'ADD_RECEIVABLE', payload: nextItem });
        alert(`Recurring item created for ${format(nextDate, 'MMM d, yyyy')}`);
      }

      setPaymentModalOpen(false);
      setSelectedReceivable(null);
  };

  const filteredItems = state.receivables
    .filter(r => r.type === 'receivable' && r.status !== 'paid')
    .sort((a,b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  const totalPending = filteredItems.filter(i => i.status === 'pending').reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h1 className="text-3xl font-bold text-gray-100 tracking-tight">Receivables</h1>
            <p className="text-gray-400 text-sm">Track invoices and personal lending</p>
        </div>
        <div className="flex gap-2">
            <button 
              onClick={() => openAdd('loan')}
              className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-blue-300 border border-blue-900/50 px-4 py-2.5 rounded-xl text-sm font-medium transition-colors"
            >
              <HandCoins size={18} />
              Personal Loan
            </button>
            <button 
              onClick={() => openAdd('invoice')}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2.5 rounded-xl text-sm font-medium transition-colors shadow-lg shadow-emerald-900/30 btn-float"
            >
              <Plus size={18} />
              Add Receivable
            </button>
        </div>
      </div>

      <div className="glass-card border-l-4 border-l-emerald-500 p-6 rounded-2xl flex items-center justify-between">
          <div>
            <p className="text-emerald-400 text-sm font-bold uppercase tracking-wider">Total Pending</p>
            <p className="text-4xl font-bold text-emerald-300 mt-2">QR {totalPending.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
          </div>
          <div className="bg-emerald-500/10 p-4 rounded-xl text-emerald-400 shadow-inner">
            <ArrowDownLeft size={36} />
          </div>
      </div>

      <div className="grid gap-4">
        {filteredItems.map(item => {
          const isOverdue = item.status === 'pending' && isPast(new Date(item.dueDate));
          const isPaid = item.status === 'paid';
          const accountName = state.accounts.find(c => c.id === item.targetAccountId)?.name;

          return (
            <div key={item.id} className={`glass-panel p-5 rounded-xl flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 transition-all hover:bg-gray-800/40 ${isPaid ? 'opacity-50' : ''} group`}>
              <div className="flex items-start gap-4">
                <div className={`p-3 rounded-xl shrink-0 ${item.subType === 'loan' ? 'bg-indigo-500/20 text-indigo-400' : 'bg-blue-500/20 text-blue-400'}`}>
                  {item.subType === 'loan' ? <HandCoins size={20} /> : <ArrowDownLeft size={20} />}
                </div>
                <div>
                  <h3 className="font-bold text-lg text-gray-200 flex items-center gap-2">
                      {item.partyName}
                      {item.recurring?.active && <span title={`Recurring: ${item.recurring.frequency}`}><Repeat size={14} className="text-blue-400" /></span>}
                  </h3>
                  <p className="text-sm text-gray-400">{item.notes}</p>
                  <div className="flex flex-wrap gap-2 items-center mt-1">
                      {item.subType === 'loan' && <span className="text-[10px] uppercase font-bold text-indigo-300 bg-indigo-900/40 px-1.5 py-0.5 rounded">Loan</span>}
                      {accountName && item.subType !== 'loan' && <p className="text-xs text-gray-500">Acc: {accountName}</p>}
                      <span className={`${isOverdue && !isPaid ? 'text-red-400 font-bold bg-red-900/20 px-2 py-0.5 rounded text-sm' : 'text-gray-500 text-sm'}`}>
                        Due {format(new Date(item.dueDate), 'MMM d, yyyy')}
                      </span>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-end">
                <div className="text-right">
                    <span className={`block text-xl font-bold ${item.type === 'receivable' ? 'text-emerald-400' : 'text-gray-200'}`}>
                    QR {item.amount.toLocaleString(undefined, { maximumFractionDigits: 2 })}
                    </span>
                    {item.currency === 'PHP' && <span className="text-xs text-gray-500 font-mono">₱{item.originalAmount?.toLocaleString()}</span>}
                </div>

                <div className="flex items-center gap-2">
                    {!isPaid && (
                        <>
                            <button onClick={() => openEdit(item)} className="p-2 text-gray-500 hover:text-blue-400"><Pencil size={16}/></button>
                            <button onClick={() => handleDelete(item.id)} className="p-2 text-gray-500 hover:text-red-400"><Trash2 size={16}/></button>
                            <button onClick={() => openPaymentModal(item)} className="flex items-center gap-1.5 px-4 py-2.5 bg-emerald-600/20 hover:bg-emerald-600/40 text-emerald-400 rounded-lg border border-emerald-600/50 transition-colors text-sm font-bold"><CheckCircle size={16} /> Receive</button>
                        </>
                    )}
                    {isPaid && <span className="px-3 py-1 bg-emerald-900/30 text-emerald-400 text-xs font-bold rounded-full border border-emerald-900/50">RECEIVED</span>}
                    {item.subType !== 'loan' && (
                        <button onClick={() => setInvoiceData(item)} className="p-2.5 bg-gray-800 text-gray-400 hover:text-white hover:bg-gray-700 rounded-lg transition-colors border border-gray-700"><FileText size={18} /></button>
                    )}
                </div>
              </div>
            </div>
          );
        })}
        {filteredItems.length === 0 && <div className="text-center py-12 text-gray-500 glass-card rounded-xl border border-dashed border-gray-700">No active receivables.</div>}
      </div>

      {/* Creation Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingId ? "Edit Receivable" : (transactionMode === 'loan' ? "New Personal Loan (Lend)" : "New Receivable")}>
        <form onSubmit={handleSave} className="space-y-4">
          <div>
            <label className="block text-xs font-medium text-gray-400 uppercase mb-1">{transactionMode === 'loan' ? 'Borrower Name' : 'Customer'}</label>
            <SearchableSelect
              options={customerOptions}
              value={partyId}
              onChange={setPartyId}
              placeholder="Select Entity..."
              required
            />
          </div>

          {transactionMode === 'invoice' ? (
              <div>
                <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Revenue Account (Credit)</label>
                <SearchableSelect
                  options={revenueOptions}
                  value={targetAccountId}
                  onChange={setTargetAccountId}
                  placeholder="Select Revenue Account..."
                  required
                />
              </div>
          ) : (
              <div>
                <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Payout From (Credit Asset)</label>
                <SearchableSelect
                  options={cashAccountOptions}
                  value={targetAccountId}
                  onChange={setTargetAccountId}
                  placeholder="Select Bank / Cash..."
                  required
                />
                <p className="text-[10px] text-gray-500 mt-1">Money leaves this account immediately.</p>
              </div>
          )}

          <div>
            <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Amount</label>
            <div className="flex gap-2">
                <input 
                    type="text" 
                    inputMode="decimal"
                    className="flex-1 px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white outline-none focus:border-emerald-500" 
                    value={amount} 
                    onChange={e => setAmount(e.target.value)} 
                    onBlur={handleAmountBlur}
                    required 
                    placeholder="0.00" 
                />
                 <select value={currency} onChange={(e) => setCurrency(e.target.value as CurrencyCode)} className="w-24 px-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none font-bold text-center">
                    <option value="QAR">QAR</option>
                    <option value="PHP">PHP</option>
                </select>
            </div>
          </div>
          <div><label className="block text-xs font-medium text-gray-400 uppercase mb-1">Description</label><input type="text" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white outline-none focus:border-emerald-500" value={notes} onChange={e => setNotes(e.target.value)} placeholder={transactionMode === 'loan' ? "e.g. Lent money for rent" : "e.g. Service Invoice #101"} /></div>
          <div><label className="block text-xs font-medium text-gray-400 uppercase mb-1">Due Date</label><input type="date" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white outline-none focus:border-emerald-500" value={dueDate} onChange={e => setDueDate(e.target.value)} required /></div>
          <div className="p-3 bg-gray-900 rounded-lg border border-gray-700">
              <div className="flex items-center gap-2 mb-2"><input type="checkbox" checked={isRecurring} onChange={e => setIsRecurring(e.target.checked)} className="w-4 h-4 rounded bg-gray-800 border-gray-600" /><span className="text-sm font-medium text-gray-300">Recurring?</span></div>
              {isRecurring && (
                  <select className="w-full px-3 py-1.5 bg-gray-800 border border-gray-600 rounded-md text-white text-sm" value={recurFreq} onChange={e => setRecurFreq(e.target.value as RecurrenceFrequency)}>
                      <option value="daily">Daily</option><option value="weekly">Weekly</option><option value="monthly">Monthly</option><option value="yearly">Yearly</option>
                  </select>
              )}
          </div>
          <button className="w-full py-3 bg-emerald-600 text-white rounded-lg font-medium hover:bg-emerald-700 transition-colors">
              {transactionMode === 'invoice' ? 'Save & Record Accrual' : 'Save & Deduct Cash'}
          </button>
        </form>
      </Modal>

      {/* Payment Modal */}
      <Modal isOpen={paymentModalOpen} onClose={() => setPaymentModalOpen(false)} title="Receive Payment">
        <form onSubmit={handlePaymentSubmit} className="space-y-4">
            <div>
                <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Deposit To (Debit)</label>
                <SearchableSelect
                  options={cashAccountOptions}
                  value={paymentTargetAccount}
                  onChange={setPaymentTargetAccount}
                  placeholder="Select Account..."
                  required
                />
                <p className="text-[10px] text-gray-500 mt-2">
                    This will record a transaction: <br/>
                    <span className="text-emerald-400">Dr. {state.accounts.find(c=>c.id===paymentTargetAccount)?.name || 'Bank'}</span> <br/>
                    <span className="text-gray-400">Cr. Accounts Receivable</span>
                </p>
            </div>
            <button className="w-full py-3 bg-emerald-600 text-white rounded-lg font-medium hover:bg-emerald-700 transition-colors">Confirm Payment</button>
        </form>
      </Modal>

      {invoiceData && <InvoiceModal isOpen={!!invoiceData} onClose={() => setInvoiceData(null)} data={invoiceData} appState={state} />}
    </div>
  );
};

import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Receivable, Transaction, CurrencyCode, RecurrenceFrequency } from '../types';
import { EXCHANGE_RATE_QAR_TO_PHP } from '../constants';
import { format, isPast, addDays, addWeeks, addMonths, addYears } from 'date-fns';
import { Plus, CheckCircle, ArrowUpRight, Repeat, Pencil, Trash2, HandCoins } from 'lucide-react';
import { Modal } from '../components/ui/Modal';
import { SearchableSelect } from '../components/ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';

export const Payables: React.FC = () => {
  const { state, dispatch } = useFinance();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [transactionMode, setTransactionMode] = useState<'bill' | 'loan'>('bill');

  // Payment Modal
  const [paymentModalOpen, setPaymentModalOpen] = useState(false);
  const [selectedPayable, setSelectedPayable] = useState<Receivable | null>(null);
  const [paymentSourceAccount, setPaymentSourceAccount] = useState('');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [partyId, setPartyId] = useState('');
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState<CurrencyCode>('QAR');
  const [dueDate, setDueDate] = useState('');
  const [notes, setNotes] = useState('');
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');
  const [targetAccountId, setTargetAccountId] = useState(''); // Expense Account OR Destination Account (Loan)

  // Options
  const merchantOptions = state.parties
    .filter(e => e.type === 'vendor')
    .map(e => ({ id: e.id, label: e.name }));

  const expenseOptions = state.accounts
    .filter(c => c.class === 'Expenses' || c.class === 'Liabilities')
    .map(c => ({ id: c.id, label: c.name, subLabel: c.code }));

  const cashAccountOptions = state.accounts
    .filter(c => c.class === 'Assets')
    .map(c => ({ id: c.id, label: c.name, subLabel: c.code }));

  const openAdd = (mode: 'bill' | 'loan') => {
      resetForm();
      setTransactionMode(mode);
      setIsModalOpen(true);
      if(mode === 'loan') {
          const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank'));
          if(bank) setTargetAccountId(bank.id);
      }
  };

  const openEdit = (item: Receivable) => {
      setEditingId(item.id);
      setTransactionMode(item.subType === 'loan' ? 'loan' : 'bill');
      setPartyId(item.partyId || '');
      setAmount((item.originalAmount || item.amount).toString());
      setCurrency(item.currency || 'QAR');
      setDueDate(item.dueDate.split('T')[0]);
      setNotes(item.notes || '');
      setIsRecurring(!!item.recurring?.active);
      setRecurFreq(item.recurring?.frequency || 'monthly');
      setTargetAccountId(item.targetAccountId || '');
      setIsModalOpen(true);
  };

  const handleAmountBlur = () => {
      setAmount(evaluateMathExpression(amount));
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmountStr = evaluateMathExpression(amount);
    if (!targetAccountId) {
        alert(transactionMode === 'bill' ? "Please select an Expense Account" : "Please select a Deposit Account");
        return;
    }

    const inputAmount = parseFloat(finalAmountStr);
    if (isNaN(inputAmount)) {
        alert("Invalid amount");
        return;
    }

    const finalAmountQAR = currency === 'PHP' ? inputAmount / EXCHANGE_RATE_QAR_TO_PHP : inputAmount;
    const party = state.parties.find(e => e.id === partyId);
    const newId = editingId || Math.random().toString(36).substr(2, 9);

    const payload: Receivable = {
      id: newId,
      type: 'payable',
      subType: transactionMode,
      partyId,
      partyName: party?.name || 'Unknown',
      targetAccountId,
      amount: finalAmountQAR,
      originalAmount: inputAmount,
      currency,
      dueDate: new Date(dueDate).toISOString(),
      status: 'pending',
      notes,
      recurring: isRecurring ? {
          active: true,
          amount: inputAmount,
          frequency: recurFreq,
          nextDueDate: dueDate
      } : undefined
    };

    if (editingId) {
        dispatch({ type: 'UPDATE_RECEIVABLE', payload });
    } else {
        dispatch({ type: 'ADD_RECEIVABLE', payload });

        const apAccount = state.accounts.find(a => a.name.includes('Accounts Payable'))?.id || '21100';

        if (transactionMode === 'bill') {
            const accrualTx: Transaction = {
                id: Math.random().toString(36).substr(2, 9),
                date: new Date().toISOString(),
                type: 'expense',
                amount: finalAmountQAR,
                originalAmount: inputAmount,
                currency,
                accountId: targetAccountId, // Expense Dr
                source: 'personal',
                paymentAccountId: apAccount, // AP Cr
                note: `Accrual: Bill #${newId.substr(0,4)} - ${notes}`,
                relatedPartyId: partyId
            };
            dispatch({ type: 'ADD_TRANSACTION', payload: accrualTx });
        } else {
            const loanTx: Transaction = {
                id: Math.random().toString(36).substr(2, 9),
                date: new Date().toISOString(),
                type: 'transfer',
                amount: finalAmountQAR,
                originalAmount: inputAmount,
                currency,
                accountId: targetAccountId, // Bank Dr (Asset Increase)
                source: 'personal',
                paymentAccountId: apAccount, // AP Cr (Liability Increase)
                note: `Personal Loan Received: #${newId.substr(0,4)} - ${notes}`,
                relatedPartyId: partyId
            };
            dispatch({ type: 'ADD_TRANSACTION', payload: loanTx });
        }
    }

    setIsModalOpen(false);
    resetForm();
  };

  const resetForm = () => {
    setEditingId(null); setPartyId(''); setAmount(''); setCurrency('QAR'); setDueDate(''); setNotes(''); setIsRecurring(false); setTargetAccountId('');
  };

  const handleDelete = (id: string) => {
      if(confirm('Delete this payable? Associated Journal Entries will also be removed.')) dispatch({ type: 'DELETE_RECEIVABLE', payload: id });
  }

  const openPaymentModal = (item: Receivable) => {
      setSelectedPayable(item);
      setPaymentModalOpen(true);
      const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank'));
      setPaymentSourceAccount(bank ? bank.id : '');
  };

  const handlePaymentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPayable || !paymentSourceAccount) return;

    const item = selectedPayable;
    const updated: Receivable = { ...item, status: 'paid', paidDate: new Date().toISOString() };
    dispatch({ type: 'UPDATE_RECEIVABLE', payload: updated });

    const apAccount = state.accounts.find(a => a.name.includes('Accounts Payable'))?.id || '21100';

    const paymentTx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        date: new Date().toISOString(),
        type: 'expense',
        amount: item.amount,
        originalAmount: item.originalAmount,
        currency: item.currency || 'QAR',
        accountId: apAccount, // AP Dr (Liability Decrease)
        source: 'personal',
        paymentAccountId: paymentSourceAccount, // Bank Cr (Asset Decrease)
        note: `Payment: ${item.subType === 'loan' ? 'Loan Repayment' : 'Bill'} #${item.id.substr(0,4)}`,
        relatedPartyId: item.partyId
    };
    dispatch({ type: 'ADD_TRANSACTION', payload: paymentTx });

    if (item.recurring && item.recurring.active) {
        let nextDate = new Date(item.dueDate);
        if (item.recurring.frequency === 'daily') nextDate = addDays(nextDate, 1);
        if (item.recurring.frequency === 'weekly') nextDate = addWeeks(nextDate, 1);
        if (item.recurring.frequency === 'monthly') nextDate = addMonths(nextDate, 1);
        if (item.recurring.frequency === 'yearly') nextDate = addYears(nextDate, 1);

        const nextItem: Receivable = {
            ...item,
            id: Math.random().toString(36).substr(2, 9),
            dueDate: nextDate.toISOString(),
            status: 'pending',
            paidDate: undefined
        };
        dispatch({ type: 'ADD_RECEIVABLE', payload: nextItem });
        alert(`Recurring item created for ${format(nextDate, 'MMM d, yyyy')}`);
    }

    setPaymentModalOpen(false);
    setSelectedPayable(null);
  };

  const filteredItems = state.receivables
    .filter(r => r.type === 'payable' && r.status !== 'paid')
    .sort((a,b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  const totalPending = filteredItems.filter(i => i.status === 'pending').reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h1 className="text-3xl font-bold text-gray-100 tracking-tight">Payables</h1>
            <p className="text-gray-400 text-sm">Track bills and personal borrowing</p>
        </div>
        <div className="flex gap-2">
            <button 
              onClick={() => openAdd('loan')}
              className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-orange-300 border border-orange-900/50 px-4 py-2.5 rounded-xl text-sm font-medium transition-colors"
            >
              <HandCoins size={18} />
              Personal Borrow
            </button>
            <button 
              onClick={() => openAdd('bill')}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2.5 rounded-xl text-sm font-medium transition-colors shadow-lg shadow-emerald-900/30 btn-float"
            >
              <Plus size={18} />
              Add Payable
            </button>
        </div>
      </div>

      <div className="glass-card border-l-4 border-l-orange-500 p-6 rounded-2xl flex items-center justify-between">
          <div>
            <p className="text-orange-400 text-sm font-bold uppercase tracking-wider">Total Pending</p>
            <p className="text-4xl font-bold text-orange-300 mt-2">QR {totalPending.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
          </div>
          <div className="bg-orange-500/10 p-4 rounded-xl text-orange-400 shadow-inner">
            <ArrowUpRight size={36} />
          </div>
      </div>

      <div className="grid gap-4">
        {filteredItems.map(item => {
          const isOverdue = item.status === 'pending' && isPast(new Date(item.dueDate));
          const isPaid = item.status === 'paid';
          const accountName = state.accounts.find(c => c.id === item.targetAccountId)?.name;

          return (
            <div key={item.id} className={`glass-panel p-5 rounded-xl flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 transition-all hover:bg-gray-800/40 ${isPaid ? 'opacity-50' : ''} group`}>
              <div className="flex items-start gap-4">
                <div className={`p-3 rounded-xl shrink-0 ${item.subType === 'loan' ? 'bg-indigo-500/20 text-indigo-400' : 'bg-orange-500/20 text-orange-400'}`}>
                  {item.subType === 'loan' ? <HandCoins size={20} /> : <ArrowUpRight size={20} />}
                </div>
                <div>
                  <h3 className="font-bold text-lg text-gray-200 flex items-center gap-2">
                      {item.partyName}
                      {item.recurring?.active && <span title={`Recurring: ${item.recurring.frequency}`}><Repeat size={14} className="text-orange-400" /></span>}
                  </h3>
                  <p className="text-sm text-gray-400">{item.notes}</p>
                  <div className="flex flex-wrap gap-2 items-center mt-1">
                      {item.subType === 'loan' && <span className="text-[10px] uppercase font-bold text-indigo-300 bg-indigo-900/40 px-1.5 py-0.5 rounded">Borrowing</span>}
                      {accountName && item.subType !== 'loan' && <p className="text-xs text-gray-500">Acc: {accountName}</p>}
                      <span className={`${isOverdue && !isPaid ? 'text-red-400 font-bold bg-red-900/20 px-2 py-0.5 rounded text-sm' : 'text-gray-500 text-sm'}`}>
                        Due {format(new Date(item.dueDate), 'MMM d, yyyy')}
                      </span>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-end">
                <div className="text-right">
                    <span className={`block text-xl font-bold text-gray-200`}>
                    QR {item.amount.toLocaleString(undefined, { maximumFractionDigits: 2 })}
                    </span>
                    {item.currency === 'PHP' && <span className="text-xs text-gray-500 font-mono">₱{item.originalAmount?.toLocaleString()}</span>}
                </div>

                <div className="flex items-center gap-2">
                    {!isPaid && (
                        <>
                            <button onClick={() => openEdit(item)} className="p-2 text-gray-500 hover:text-blue-400"><Pencil size={16}/></button>
                            <button onClick={() => handleDelete(item.id)} className="p-2 text-gray-500 hover:text-red-400"><Trash2 size={16}/></button>
                            <button onClick={() => openPaymentModal(item)} className="flex items-center gap-1.5 px-4 py-2.5 bg-orange-600/20 hover:bg-orange-600/40 text-orange-400 rounded-lg border border-orange-600/50 transition-colors text-sm font-bold"><CheckCircle size={16} /> Pay</button>
                        </>
                    )}
                    {isPaid && <span className="px-3 py-1 bg-orange-900/30 text-orange-400 text-xs font-bold rounded-full border border-orange-900/50">PAID</span>}
                </div>
              </div>
            </div>
          );
        })}
        {filteredItems.length === 0 && <div className="text-center py-12 text-gray-500 glass-card rounded-xl border border-dashed border-gray-700">No active payables.</div>}
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingId ? "Edit Payable" : (transactionMode === 'loan' ? "New Personal Borrowing" : "New Payable")}>
        <form onSubmit={handleSave} className="space-y-4">
          <div>
            <label className="block text-xs font-medium text-gray-400 uppercase mb-1">{transactionMode === 'loan' ? 'Lender' : 'Merchant'}</label>
             <SearchableSelect
               options={merchantOptions}
               value={partyId}
               onChange={setPartyId}
               placeholder="Select Entity..."
               required
             />
          </div>

          {transactionMode === 'bill' ? (
              <div>
                <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Expense Account (Debit)</label>
                <SearchableSelect
                  options={expenseOptions}
                  value={targetAccountId}
                  onChange={setTargetAccountId}
                  placeholder="Select Expense Account..."
                  required
                />
              </div>
          ) : (
              <div>
                <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Deposit To (Debit Asset)</label>
                <SearchableSelect
                  options={cashAccountOptions}
                  value={targetAccountId}
                  onChange={setTargetAccountId}
                  placeholder="Select Bank / Cash..."
                  required
                />
                <p className="text-[10px] text-gray-500 mt-1">Money enters this account immediately.</p>
              </div>
          )}

          <div>
            <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Amount</label>
            <div className="flex gap-2">
                <input 
                    type="text" 
                    inputMode="decimal"
                    className="flex-1 px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white outline-none focus:border-orange-500" 
                    value={amount} 
                    onChange={e => setAmount(e.target.value)} 
                    onBlur={handleAmountBlur}
                    required 
                    placeholder="0.00" 
                />
                 <select value={currency} onChange={(e) => setCurrency(e.target.value as CurrencyCode)} className="w-24 px-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none font-bold text-center">
                    <option value="QAR">QAR</option>
                    <option value="PHP">PHP</option>
                </select>
            </div>
          </div>
          <div><label className="block text-xs font-medium text-gray-400 uppercase mb-1">Description</label><input type="text" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white outline-none focus:border-orange-500" value={notes} onChange={e => setNotes(e.target.value)} placeholder={transactionMode === 'loan' ? "e.g. Borrowed for car" : "e.g. Hosting Bill"} /></div>
          <div><label className="block text-xs font-medium text-gray-400 uppercase mb-1">Due Date</label><input type="date" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white outline-none focus:border-orange-500" value={dueDate} onChange={e => setDueDate(e.target.value)} required /></div>
          <div className="p-3 bg-gray-900 rounded-lg border border-gray-700">
              <div className="flex items-center gap-2 mb-2"><input type="checkbox" checked={isRecurring} onChange={e => setIsRecurring(e.target.checked)} className="w-4 h-4 rounded bg-gray-800 border-gray-600" /><span className="text-sm font-medium text-gray-300">Recurring?</span></div>
              {isRecurring && (
