                      <option value="daily">Daily</option><option value="weekly">Weekly</option><option value="monthly">Monthly</option><option value="yearly">Yearly</option>
                  </select>
              )}
          </div>
          <button className="w-full py-3 bg-orange-600 text-white rounded-lg font-medium hover:bg-orange-700 transition-colors">
              {transactionMode === 'bill' ? 'Save & Record Accrual' : 'Save & Receive Cash'}
          </button>
        </form>
      </Modal>

      {/* Payment Modal */}
      <Modal isOpen={paymentModalOpen} onClose={() => setPaymentModalOpen(false)} title="Pay Bill">
        <form onSubmit={handlePaymentSubmit} className="space-y-4">
            <div>
                <label className="block text-xs font-medium text-gray-400 uppercase mb-1">Pay From (Credit)</label>
                <SearchableSelect
                  options={cashAccountOptions}
                  value={paymentSourceAccount}
