import React, { useMemo, useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, isPast } from 'date-fns';
import { Calendar, FileText, Scale, Users, Download, Activity, Table, ScrollText } from 'lucide-react';
import { StatementOfAccount } from '../components/StatementOfAccount';
import { AccountClass } from '../types';

type ReportTab = 'income_statement' | 'balance_sheet' | 'cash_flow' | 'ar_ap' | 'trial_balance' | 'soa';

const formatCurrency = (amount: number) => {
  return amount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2});
};

export const Reports: React.FC = () => {
  const { state } = useFinance();
  const [activeTab, setActiveTab] = useState<ReportTab>('income_statement');
  const [dateRange, setDateRange] = useState({
    start: format(startOfMonth(new Date()), 'yyyy-MM-dd'),
    end: format(endOfMonth(new Date()), 'yyyy-MM-dd')
  });

  const transactionsInPeriod = useMemo(() => {
    return state.transactions.filter(t => {
      const d = parseISO(t.date);
      const start = parseISO(dateRange.start);
      const end = parseISO(dateRange.end);
      end.setHours(23, 59, 59, 999);
      return isWithinInterval(d, { start, end });
    });
  }, [state.transactions, dateRange]);

  // --- HELPER: Universal Signed Balance (Debit - Credit) ---
  // Returns:
  // Positive for Debit Balances (Assets, Expenses)
  // Negative for Credit Balances (Liabilities, Equity, Revenue)
  const getSignedBalance = useMemo(() => (accountId: string, limitDate?: Date) => {
      const cutoff = limitDate || parseISO(dateRange.end);
      // Set to end of day
      cutoff.setHours(23, 59, 59, 999);

      return state.transactions
          .filter(t => parseISO(t.date) <= cutoff)
          .reduce((bal, t) => {
              let change = 0;
              // Simple Debit/Credit Logic based on Transaction Model
              // accountId is Dr (Debit)
              // paymentAccountId is Cr (Credit)

              if (t.accountId === accountId) change += t.amount;
              if (t.paymentAccountId === accountId) change -= t.amount;

              return bal + change;
          }, 0);
  }, [state.transactions, dateRange.end]);

  // --- 1. INCOME STATEMENT (Detailed) ---
  const incomeStatement = useMemo(() => {
      // Helper to get breakdown for a specific Class
      const getBreakdown = (acClass: AccountClass, codePrefix?: string) => {
          const accounts = state.accounts.filter(c => c.class === acClass && (!codePrefix || c.code.startsWith(codePrefix)));
          const breakdown = accounts.map(c => {
              // Income Statement uses transactions strictly within the period
              const amount = transactionsInPeriod.reduce((sum, t) => {
                  let impact = 0;
                  // For Revenue (Credit Normal): Credit increases (paymentAccountId), Debit decreases (accountId). 
                  // Wait, getSignedBalance logic returns Net Debit. 
                  // For Rev/Exp, we want positive numbers for display usually.

                  // Let's stick to simple accumulation for period logic:
                  if (t.accountId === c.id) impact += t.amount; // Debit
                  if (t.paymentAccountId === c.id) impact -= t.amount; // Credit

                  // If Revenue, result should be Credit - Debit (negate impact)
                  if (acClass === 'Revenue') return sum - impact;
                  // If Expense, result should be Debit - Credit (impact)
                  return sum + impact;
              }, 0);
              return { name: c.name, amount };
          }).filter(i => Math.abs(i.amount) > 0.01);
          return breakdown;
      };

      const revenueBreakdown = getBreakdown('Revenue');
      const totalRevenue = revenueBreakdown.reduce((s, i) => s + i.amount, 0);

      // COGS often starts with 5 in standardized charts
      const cogsBreakdown = getBreakdown('Expenses', '5'); 
      const totalCOGS = cogsBreakdown.reduce((s, i) => s + i.amount, 0);

      // OpEx often starts with 6
      const expenseBreakdown = getBreakdown('Expenses', '6');
      const totalExpenses = expenseBreakdown.reduce((s, i) => s + i.amount, 0);

      const grossProfit = totalRevenue - totalCOGS;
      const netIncome = grossProfit - totalExpenses;

      return { revenueBreakdown, totalRevenue, cogsBreakdown, totalCOGS, expenseBreakdown, totalExpenses, grossProfit, netIncome };
  }, [transactionsInPeriod, state.accounts]);

  // --- 2. BALANCE SHEET (Strict Double Entry) ---
  const balanceSheet = useMemo(() => {
      // 1. ASSETS (Debit Normal -> Positive Signed Balance)
      const currentAssets = state.accounts
          .filter(c => c.class === 'Assets' && c.code.startsWith('11'))
          .map(c => ({ name: c.name, amount: getSignedBalance(c.id) })) 
          .filter(i => Math.abs(i.amount) > 0.01);

      const fixedAssets = state.accounts
          .filter(c => c.class === 'Assets' && c.code.startsWith('12') && !c.name.includes('Accumulated Depreciation'))
          .map(c => ({ name: c.name, amount: getSignedBalance(c.id) }))
          .filter(i => Math.abs(i.amount) > 0.01);

      // Accum Dep is Credit Normal (Contra Asset). Signed Balance will be Negative.
      const accDepAccounts = state.accounts.filter(c => c.name.includes('Accumulated Depreciation'));
      const accDepAmount = accDepAccounts.reduce((s, c) => s + getSignedBalance(c.id), 0);

      const totalAssetsSigned = 
          currentAssets.reduce((s, i) => s + i.amount, 0) + 
          fixedAssets.reduce((s, i) => s + i.amount, 0) + 
          accDepAmount;

      // 2. LIABILITIES (Credit Normal -> Negative Signed Balance)
      const liabilities = state.accounts
          .filter(c => c.class === 'Liabilities')
          .map(c => ({ name: c.name, amount: getSignedBalance(c.id) }))
          .filter(i => Math.abs(i.amount) > 0.01);

      const totalLiabilitiesSigned = liabilities.reduce((s, i) => s + i.amount, 0);

      // 3. EQUITY ACCOUNTS (Credit Normal -> Negative Signed Balance)
      const equityAccounts = state.accounts
          .filter(c => c.class === 'Equity' && !c.name.includes('Retained Earnings'))
          .map(c => ({ name: c.name, amount: getSignedBalance(c.id) }))
          .filter(i => Math.abs(i.amount) > 0.01);

      const totalEquityAccountsSigned = equityAccounts.reduce((s, i) => s + i.amount, 0);

      // 4. RETAINED EARNINGS (Net Income)
      // Sum of Signed Balance of ALL Revenue (Neg) and Expenses (Pos).
      const retainedEarningsSigned = state.accounts
          .filter(c => c.class === 'Revenue' || c.class === 'Expenses')
          .reduce((sum, c) => sum + getSignedBalance(c.id), 0);

      const totalEquitySigned = totalEquityAccountsSigned + retainedEarningsSigned;

      // 5. BALANCE CHECK
      const unbalanced = totalAssetsSigned + totalLiabilitiesSigned + totalEquitySigned;

      return { 
          currentAssets, 
          fixedAssets, 
          accDepAmount, 
          totalAssetsDisplay: totalAssetsSigned, 

          liabilitiesDisplay: liabilities.map(l => ({ ...l, amount: l.amount * -1 })), 
          totalLiabilitiesDisplay: totalLiabilitiesSigned * -1, 

          equityAccountsDisplay: equityAccounts.map(e => ({ ...e, amount: e.amount * -1 })),
          retainedEarningsDisplay: retainedEarningsSigned * -1, 

          totalEquityDisplay: totalEquitySigned * -1,

          totalLiabEquityDisplay: (totalLiabilitiesSigned + totalEquitySigned) * -1,
          unbalanced 
      };
  }, [getSignedBalance, state.accounts]);

  // --- 3. CASH FLOW (Direct Method) ---
  const cashFlow = useMemo(() => {
      // Identifying cash accounts via code or name
      const cashAccountIds = state.accounts
          .filter(c => c.class === 'Assets' && (c.name.match(/Cash|Bank|Wallet/i)))
          .map(c => c.id);

      let cashIn = 0;
      let cashOut = 0;

      transactionsInPeriod.forEach(t => {
          // Cash In: Debit Cash Account
          if (cashAccountIds.includes(t.accountId)) {
              cashIn += t.amount;
          }
          // Cash Out: Credit Cash Account
          if (t.paymentAccountId && cashAccountIds.includes(t.paymentAccountId)) {
              cashOut += t.amount;
          }
      });

      return { cashIn, cashOut, netChange: cashIn - cashOut };
  }, [transactionsInPeriod, state.accounts]);

  // --- 4. AR / AP SUMMARY ---
  const arApSummary = useMemo(() => {
      const receivables = state.receivables.filter(r => r.type === 'receivable' && r.status !== 'paid');
      const payables = state.receivables.filter(r => r.type === 'payable' && r.status !== 'paid');

      const groupItems = (items: typeof receivables) => {
          const grouped: Record<string, { name: string, total: number, overdue: number, count: number }> = {};
          items.forEach(item => {
              const name = item.partyName || 'Unknown';
              if (!grouped[name]) grouped[name] = { name: name, total: 0, overdue: 0, count: 0 };
              grouped[name].total += item.amount;
              grouped[name].count += 1;
              if (isPast(parseISO(item.dueDate))) {
                  grouped[name].overdue += item.amount;
              }
          });
          return Object.values(grouped);
      };

      return {
          ar: groupItems(receivables),
          ap: groupItems(payables),
          totalAr: receivables.reduce((s, i) => s + i.amount, 0),
          totalAp: payables.reduce((s, i) => s + i.amount, 0)
      };
  }, [state.receivables]);

  // --- 5. TRIAL BALANCE ---
  const trialBalance = useMemo(() => {
    const balances: Record<string, { code: string, name: string, debit: number, credit: number }> = {};
    const addEntry = (id: string, name: string, code: string, amount: number, type: 'debit'|'credit') => {
        if(!balances[id]) balances[id] = { code, name, debit: 0, credit: 0 };
        if(type === 'debit') balances[id].debit += amount;
        else balances[id].credit += amount;
    };

    state.transactions.forEach(t => {
        const accDr = state.accounts.find(c => c.id === t.accountId);
        const accCr = state.accounts.find(c => c.id === t.paymentAccountId);

        if (accDr) addEntry(accDr.id, accDr.name, accDr.code, t.amount, 'debit');
        if (accCr) addEntry(accCr.id, accCr.name, accCr.code, t.amount, 'credit');
    });

    return Object.values(balances).sort((a,b) => a.code.localeCompare(b.code));
  }, [state.transactions, state.accounts]);

  const totalDebit = trialBalance.reduce((s, i) => s + i.debit, 0);
  const totalCredit = trialBalance.reduce((s, i) => s + i.credit, 0);

  const printReport = () => window.print();

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 no-print">
            <div>
                <h1 className="text-3xl font-bold text-white tracking-tight">Financial Reports</h1>
                <p className="text-gray-400 text-sm">Statement of financial health</p>
            </div>
