import React, { useState, useRef, useMemo } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Trash2, Plus, LayoutGrid, Book, AlertTriangle, Users, Pencil, Check, X, Cloud, FileUp, FileDown, Upload, Database, Key, Search, FileJson, FileSpreadsheet, ArrowUpRight, ArrowDownLeft, Clock } from 'lucide-react';
import { Account, TransactionType, SourceType, TransactionTemplate, AccountClass, Party, PartyType, RecurrenceFrequency, Transaction, AppState } from '../types';
import { Modal } from '../components/ui/Modal';
import { format, parseISO } from 'date-fns';
import { supabaseService } from '../services/supabase';
import { excelService } from '../services/excel';
import { evaluateMathExpression } from '../utils/mathUtils';

type Tab = 'coa' | 'recurring' | 'templates' | 'parties' | 'sync' | 'profile' | 'danger';

export const Settings: React.FC = () => {
  const { state, dispatch, syncConfig, updateSyncConfig, syncStatus, refreshData, pushDataManual, lastError, user } = useFinance();
  const [activeTab, setActiveTab] = useState<Tab>('coa');

  // Ledger Modal State
  const [viewingLedgerAccountId, setViewingLedgerAccountId] = useState<string | null>(null);

  // Sync State
  const [sbUrl, setSbUrl] = useState(syncConfig.supabaseUrl || '');
  const [sbKey, setSbKey] = useState(syncConfig.supabaseKey || '');

  // Profile State
  const [bizName, setBizName] = useState(state.businessProfile.name);
  const [bizAddress, setBizAddress] = useState(state.businessProfile.address);
  const [bizPhone, setBizPhone] = useState(state.businessProfile.phone);
  const [bizEmail, setBizEmail] = useState(state.businessProfile.email);

  // New Account State
  const [newAccName, setNewAccName] = useState('');
  const [newAccClass, setNewAccClass] = useState<AccountClass>('Expenses');
  const [newAccCode, setNewAccCode] = useState('');

  // COA Search State
  const [coaSearch, setCoaSearch] = useState('');

  // Editing Account State
  const [editingAccId, setEditingAccId] = useState<string | null>(null);
  const [editingAccName, setEditingAccName] = useState('');

  // Editing Party State
  const [editingPartyId, setEditingPartyId] = useState<string | null>(null);
  const [editingPartyName, setEditingPartyName] = useState('');
  const [editingPartyPhone, setEditingPartyPhone] = useState('');

  // Template State
  const [editingTemplateId, setEditingTemplateId] = useState<string | null>(null);
  const [tempName, setTempName] = useState('');
  const [tempAmount, setTempAmount] = useState('');
  const [tempAccountId, setTempAccountId] = useState('');
  const [tempIcon, setTempIcon] = useState('⚡');
  const [tempPartyId, setTempPartyId] = useState('');
  const [tempPaymentAccountId, setTempPaymentAccountId] = useState('');

  // New Party State
  const [partyName, setPartyName] = useState('');
  const [partyType, setPartyType] = useState<PartyType>('vendor');

  // Refs
  const backupInputRef = useRef<HTMLInputElement>(null);
  const excelInputRef = useRef<HTMLInputElement>(null);

  // COA Ledger Filter
  const ledgerTransactions = useMemo(() => {
      if(!viewingLedgerAccountId) return [];
      return state.transactions
        .filter(t => t.accountId === viewingLedgerAccountId || t.paymentAccountId === viewingLedgerAccountId)
        .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
        .slice(0, 50); // Limit to 50
  }, [viewingLedgerAccountId, state.transactions]);

  const viewingAccount = state.accounts.find(c => c.id === viewingLedgerAccountId);
  const viewingAccountName = viewingAccount?.name;
  const viewingAccountClass = viewingAccount?.class;

  // --- Handlers ---
  const handleSaveSync = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanUrl = sbUrl.trim();
    const cleanKey = sbKey.trim();

    setSbUrl(cleanUrl);
    setSbKey(cleanKey);

    updateSyncConfig({
      supabaseUrl: cleanUrl,
      supabaseKey: cleanKey,
      gasWebAppUrl: undefined,
      enabled: !!(cleanUrl && cleanKey)
    });
    alert('Connections Saved');
  };

  const handleSaveProfile = (e: React.FormEvent) => {
    e.preventDefault();
    dispatch({
        type: 'UPDATE_BUSINESS_PROFILE',
        payload: { ...state.businessProfile, name: bizName, address: bizAddress, phone: bizPhone, email: bizEmail }
    });
    alert('Profile Saved');
  };

  const handleBackup = () => {
      const dataStr = JSON.stringify(state, null, 2);
      const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
      const linkElement = document.createElement('a');
      linkElement.setAttribute('href', dataUri);
      linkElement.setAttribute('download', `fintrack_backup_${new Date().toISOString().split('T')[0]}.json`);
      linkElement.click();
  };

  const handleExcelExport = () => {
      excelService.exportDataToExcel(state);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if(!file) return;
      const reader = new FileReader();
      reader.onload = async (event) => {
          try {
              const json = JSON.parse(event.target?.result as string);
              if (json.transactions && json.accounts && confirm("Restore this JSON backup?")) {
                  const newState = { ...json, lastUpdated: new Date().toISOString() };
                  dispatch({ type: 'SET_STATE', payload: newState as AppState });
                  if (user && syncConfig.enabled && syncConfig.supabaseUrl) {
                      await supabaseService.pushData(user.id, newState as AppState);
                  }
                  alert("Restored successfully!");
              }
          } catch (error) { alert("Error parsing JSON"); }
      };
      reader.readAsText(file);
      if(backupInputRef.current) backupInputRef.current.value = '';
  };

  const handleExcelImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if(!file) return;

      if(confirm("Importing from Excel will overwrite the current database. Continue?")) {
        try {
            const data = await excelService.importDataFromExcel(file);
            if (data.transactions && data.accounts) {
                const fullState: AppState = {
                    ...state,
                    ...data,
                    lastUpdated: new Date().toISOString()
                };
                dispatch({ type: 'SET_STATE', payload: fullState });
                if (user && syncConfig.enabled && syncConfig.supabaseUrl) {
                    await supabaseService.pushData(user.id, fullState);
                }
                alert("Excel Import Successful!");
            } else {
                alert("Excel file missing critical sheets (Journal or Chart of Accounts).");
            }
        } catch (error) {
            console.error(error);
            alert("Failed to parse Excel file. Check format.");
        }
      }
      if(excelInputRef.current) excelInputRef.current.value = '';
  };

  const handleAddAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAccName || !newAccCode) return;

    // Determine Normal Balance based on Class
    let normalBalance: 'debit' | 'credit' = 'debit';
    if (['Liabilities', 'Equity', 'Revenue'].includes(newAccClass)) {
        normalBalance = 'credit';
    }

    dispatch({ type: 'ADD_ACCOUNT', payload: {
        id: Math.random().toString(36).substr(2, 9),
        name: newAccName,
        class: newAccClass,
        code: newAccCode,
        level: 'gl',
        normalBalance,
        isPosting: true
    }});
    setNewAccName(''); setNewAccCode('');
  };

  const startEditingAcc = (acc: Account) => {
      setEditingAccId(acc.id); setEditingAccName(acc.name);
  };

  const saveEditingAcc = () => {
      if(editingAccId) {
          const original = state.accounts.find(c => c.id === editingAccId);
          if(original) {
              dispatch({ type: 'UPDATE_ACCOUNT', payload: { ...original, name: editingAccName } });
          }
          setEditingAccId(null);
      }
  };

  const cancelEditingAcc = () => { setEditingAccId(null); };

  const startEditingParty = (e: Party) => { setEditingPartyId(e.id); setEditingPartyName(e.name); setEditingPartyPhone(e.phone || ''); };
  const saveEditingParty = () => {
      if(editingPartyId) {
          const orig = state.parties.find(e => e.id === editingPartyId);
          if(orig) dispatch({ type: 'UPDATE_PARTY', payload: { ...orig, name: editingPartyName, phone: editingPartyPhone }});
          setEditingPartyId(null);
      }
  }

  const handleTempAmountBlur = () => {
      setTempAmount(evaluateMathExpression(tempAmount));
  }

  const handleSaveTemplate = (e: React.FormEvent) => {
      e.preventDefault();
      if(!tempName || !tempAccountId) return;

      const finalAmountStr = evaluateMathExpression(tempAmount);
      const parsedAmount = parseFloat(finalAmountStr);

      const payload: TransactionTemplate = {
          id: editingTemplateId || Math.random().toString(36).substr(2, 9),
          name: tempName, accountId: tempAccountId, amount: isNaN(parsedAmount) ? undefined : parsedAmount,
          currency: 'QAR', icon: tempIcon, color: '#374151', partyId: tempPartyId, paymentAccountId: tempPaymentAccountId
      };
      if(editingTemplateId) {
          dispatch({ type: 'DELETE_TEMPLATE', payload: editingTemplateId });
          dispatch({ type: 'ADD_TEMPLATE', payload });
      } else {
          dispatch({ type: 'ADD_TEMPLATE', payload });
      }
      resetTempForm();
  };

  const startEditingTemplate = (t: TransactionTemplate) => {
      setEditingTemplateId(t.id); setTempName(t.name); setTempAccountId(t.accountId);
      setTempAmount(t.amount?.toString()||''); setTempIcon(t.icon||'');
      setTempPartyId(t.partyId||''); setTempPaymentAccountId(t.paymentAccountId||'');
  }
  const resetTempForm = () => { setEditingTemplateId(null); setTempName(''); setTempAmount(''); setTempAccountId(''); setTempIcon(''); setTempPartyId(''); setTempPaymentAccountId(''); }

  const handleAddParty = (e: React.FormEvent) => {
      e.preventDefault();
      if(!partyName) return;
      dispatch({ type: 'ADD_PARTY', payload: { id: Math.random().toString(36).substr(2, 9), name: partyName, type: partyType }});
      setPartyName('');
  };

  const handleDelete = (type: 'ACCOUNT' | 'TEMPLATE' | 'PARTY' | 'RECURRING', id: string) => {
    if (confirm('Are you sure?')) {
        if(type === 'ACCOUNT') dispatch({ type: 'DELETE_ACCOUNT', payload: id });
        if(type === 'TEMPLATE') dispatch({ type: 'DELETE_TEMPLATE', payload: id });
        if(type === 'PARTY') dispatch({ type: 'DELETE_PARTY', payload: id });
        if(type === 'RECURRING') dispatch({ type: 'DELETE_RECURRING', payload: id });
    }
  };

  const handleReset = () => { if(confirm('WARNING: RESET DATA?')) dispatch({ type: 'RESET_DATA' }); }

  const getAccountBalance = (accId: string, acClass?: AccountClass) => {
      if (acClass === 'Assets') {
          // Check if this account is linked to an Asset object for more detail?
          // Not strictly necessary for balance calculation if transactions are correct.
          // But for fixed assets we might want to sum asset values?
          // Let's stick to Transaction Ledger calculation.
      }

      let dr = 0;
      let cr = 0;

      state.transactions.forEach(t => {
          if (t.accountId === accId) dr += t.amount;
          if (t.paymentAccountId === accId) cr += t.amount;
      });

      // Normal Balance: 
      // Assets/Expenses = Dr Normal (Dr - Cr)
      // Liab/Equity/Rev = Cr Normal (Cr - Dr)
      const isCreditNormal = ['Liabilities', 'Revenue', 'Equity'].includes(acClass || '');
      return isCreditNormal ? (cr - dr) : (dr - cr);
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0">
