                      <div><label className="block text-[10px] text-gray-500 uppercase font-bold mb-1">Label</label><input className="w-full px-3 py-2 bg-gray-950 border border-gray-700 rounded-lg text-white text-sm outline-none focus:border-primary" value={tempName} onChange={e => setTempName(e.target.value)} placeholder="e.g. Coffee" /></div>
                      <div><label className="block text-[10px] text-gray-500 uppercase font-bold mb-1">Account</label>
                          <select className="w-full px-3 py-2 bg-gray-950 border border-gray-700 rounded-lg text-white text-sm outline-none focus:border-primary" value={tempAccountId} onChange={e => setTempAccountId(e.target.value)}>
                              <option value="">Select...</option>
                              {state.accounts.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                          </select>
                      </div>
                      <div>
                        <label className="block text-[10px] text-gray-500 uppercase font-bold mb-1">Amount (Optional)</label>
                        <input 
                            type="text" 
                            inputMode="decimal"
                            className="w-full px-3 py-2 bg-gray-950 border border-gray-700 rounded-lg text-white text-sm outline-none focus:border-primary" 
                            value={tempAmount} 
                            onChange={e => setTempAmount(e.target.value)} 
                            onBlur={handleTempAmountBlur}
                            placeholder="0.00" 
                        />
                      </div>
                      <div><label className="block text-[10px] text-gray-500 uppercase font-bold mb-1">Icon</label><input className="w-full px-3 py-2 bg-gray-950 border border-gray-700 rounded-lg text-white text-sm outline-none focus:border-primary" value={tempIcon} onChange={e => setTempIcon(e.target.value)} placeholder="e.g. ☕" /></div>
                  </div>
                  <div className="flex gap-2 mt-4 justify-end">
                      {editingTemplateId && <button type="button" onClick={resetTempForm} className="px-4 py-2 text-gray-400 text-sm hover:text-white">Cancel</button>}
                      <button className="px-6 py-2 bg-primary text-white rounded-lg text-sm font-bold">{editingTemplateId ? 'Update' : 'Add Shortcut'}</button>
                  </div>
              </form>

              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                  {state.templates.map(t => (
                      <div key={t.id} className="bg-gray-900 border border-gray-800 p-4 rounded-xl flex flex-col items-center justify-center relative group hover:border-primary transition-all">
                          <span className="text-3xl mb-2">{t.icon}</span>
                          <span className="font-bold text-gray-200 text-sm text-center">{t.name}</span>
                          {t.amount && <span className="text-xs text-gray-500 mt-1">QR {t.amount}</span>}

                          <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={() => startEditingTemplate(t)} className="p-1 text-blue-400 hover:bg-blue-900/30 rounded"><Pencil size={12}/></button>
                              <button onClick={() => handleDelete('TEMPLATE', t.id)} className="p-1 text-red-400 hover:bg-red-900/30 rounded"><Trash2 size={12}/></button>
                          </div>
                      </div>
                  ))}
                  {state.templates.length === 0 && <p className="col-span-full text-center text-gray-600 py-10">No shortcuts defined.</p>}
              </div>
          </div>
      )}

      {/* --- DANGER ZONE TAB --- */}
      {activeTab === 'danger' && (
           <div className="bg-red-900/10 border border-red-900/50 p-6 rounded-2xl flex items-center justify-between">
               <div>
                   <h3 className="text-red-500 font-bold text-lg">Reset Data</h3>
                   <p className="text-red-400/60 text-sm">Permanently delete all local data. This cannot be undone.</p>
               </div>
               <button onClick={handleReset} className="flex items-center gap-2 px-5 py-3 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold transition-colors shadow-lg shadow-red-900/20">
                   <Trash2 size={18} /> Reset All
               </button>
           </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
