import React, { useState, useMemo } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, startOfYear, endOfYear } from 'date-fns';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { ChevronLeft, ChevronRight, Settings, Target, CheckSquare, Square } from 'lucide-react';
import { Modal } from '../components/ui/Modal';

export const Budget: React.FC = () => {
  const { state, dispatch } = useFinance();
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [viewMode, setViewMode] = useState<'monthly' | 'yearly'>('monthly');
  const [isManageOpen, setIsManageOpen] = useState(false);

  const budgetKey = viewMode === 'monthly' ? format(selectedDate, 'yyyy-MM') : format(selectedDate, 'yyyy');
  const periodStart = viewMode === 'monthly' ? startOfMonth(selectedDate) : startOfYear(selectedDate);
  const periodEnd = viewMode === 'monthly' ? endOfMonth(selectedDate) : endOfYear(selectedDate);

  // Get existing budget for this period
  const existingBudget = state.monthlyBudgets?.find(b => b.monthKey === budgetKey);
  const categoryLimits: Record<string, number> = existingBudget?.categoryLimits || {};
  const visibleAccountIds = existingBudget?.visibleAccountIds || state.accounts.filter(c => c.class === 'Expenses').map(c => c.id);

  // Calculate actual spending per account for this period
  const actualSpending = useMemo(() => {
    const spending: Record<string, number> = {};
    state.transactions.filter(t => {
      const d = parseISO(t.date);
      return isWithinInterval(d, { start: periodStart, end: periodEnd }) && t.type === 'expense';
    }).forEach(t => {
      spending[t.accountId] = (spending[t.accountId] || 0) + t.amount;
    });
    return spending;
  }, [state.transactions, periodStart, periodEnd]);

  // Expense Accounts
  const allExpenseAccounts = state.accounts.filter(c => c.class === 'Expenses');
  const activeAccounts = allExpenseAccounts.filter(c => visibleAccountIds.includes(c.id));

  // Handlers
  const handleLimitChange = (accId: string, val: string) => {
      const limit = parseFloat(val) || 0;
      const newLimits = { ...categoryLimits, [accId]: limit };

      // Calculate Total from visible
      const totalLimit = Object.entries(newLimits)
        .filter(([id]) => visibleAccountIds.includes(id))
        .reduce((sum, [_, amt]) => sum + (amt as number), 0);

      dispatch({
          type: 'SET_MONTHLY_BUDGET',
          payload: {
              monthKey: budgetKey,
              limit: totalLimit,
              categoryLimits: newLimits,
              visibleAccountIds
          }
      });
  };

  const handleVisibleToggle = (accId: string) => {
      const newVisible = visibleAccountIds.includes(accId) 
        ? visibleAccountIds.filter(id => id !== accId)
        : [...visibleAccountIds, accId];

      const totalLimit = Object.entries(categoryLimits)
        .filter(([id]) => newVisible.includes(id))
        .reduce((sum, [_, amt]) => sum + (amt as number), 0);

      dispatch({
          type: 'SET_MONTHLY_BUDGET',
          payload: {
              monthKey: budgetKey,
              limit: totalLimit,
              categoryLimits,
              visibleAccountIds: newVisible
          }
      });
  };

  const changePeriod = (delta: number) => {
      const newDate = new Date(selectedDate);
      if (viewMode === 'monthly') newDate.setMonth(newDate.getMonth() + delta);
      else newDate.setFullYear(newDate.getFullYear() + delta);
      setSelectedDate(newDate);
  };

  // Stats
  const totalBudget = existingBudget?.limit || 0;
  const totalActual = activeAccounts.reduce((sum, cat) => sum + (actualSpending[cat.id] || 0), 0);
  const remaining = totalBudget - totalActual;
  const percentage = totalBudget > 0 ? (totalActual / totalBudget) * 100 : 0;

  const chartData = [
      { name: 'Used', value: totalActual, color: percentage > 100 ? '#ef4444' : '#3b82f6' },
      { name: 'Remaining', value: Math.max(0, remaining), color: '#1f2937' }
  ];

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-slide-up">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h1 className="text-3xl font-bold text-white tracking-tight">Budget Planner</h1>
            <p className="text-gray-400 text-sm">Allocate funds for {viewMode === 'monthly' ? format(selectedDate, 'MMMM yyyy') : format(selectedDate, 'yyyy')}</p>
        </div>
        <div className="flex items-center gap-4">
            <div className="bg-gray-900 rounded-lg p-1 border border-gray-700 flex">
                <button onClick={() => setViewMode('monthly')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'monthly' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}>Monthly</button>
                <button onClick={() => setViewMode('yearly')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'yearly' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}>Yearly</button>
            </div>
            <div className="flex items-center gap-2 bg-gray-900 rounded-lg p-1 border border-gray-700">
                <button onClick={() => changePeriod(-1)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><ChevronLeft size={20}/></button>
                <span className="font-mono text-sm font-bold w-32 text-center text-white">{viewMode === 'monthly' ? format(selectedDate, 'MMM yyyy') : format(selectedDate, 'yyyy')}</span>
                <button onClick={() => changePeriod(1)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><ChevronRight size={20}/></button>
            </div>
            <button onClick={() => setIsManageOpen(true)} className="p-2.5 bg-gray-800 hover:bg-gray-700 text-white rounded-lg border border-gray-700 transition-colors">
                <Settings size={18} />
            </button>
        </div>
      </div>

      {/* Overview Card */}
      <div className="glass-card p-6 rounded-2xl flex flex-col md:flex-row items-center gap-8 border border-white/5 bg-gray-900/50">
           <div className="relative w-32 h-32 flex-shrink-0">
               <ResponsiveContainer width="100%" height="100%">
                   <PieChart>
                       <Pie data={chartData} innerRadius={35} outerRadius={50} dataKey="value" stroke="none">
                            {chartData.map((entry, index) => <Cell key={index} fill={entry.color} />)}
                       </Pie>
                   </PieChart>
               </ResponsiveContainer>
               <div className="absolute inset-0 flex items-center justify-center flex-col">
                   <span className="text-xs text-gray-500">Spent</span>
                   <span className={`font-bold ${percentage > 100 ? 'text-red-500' : 'text-blue-500'}`}>{percentage.toFixed(0)}%</span>
               </div>
           </div>

           <div className="flex-1 grid grid-cols-2 md:grid-cols-3 gap-6 text-center md:text-left">
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Total Budget</p>
                   <p className="text-2xl font-bold text-white mt-1">QR {totalBudget.toLocaleString()}</p>
               </div>
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Actual Spent</p>
                   <p className={`text-2xl font-bold mt-1 ${totalActual > totalBudget ? 'text-red-400' : 'text-white'}`}>QR {totalActual.toLocaleString()}</p>
               </div>
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Remaining</p>
                   <p className={`text-2xl font-bold mt-1 ${remaining < 0 ? 'text-red-500' : 'text-emerald-400'}`}>QR {remaining.toLocaleString()}</p>
               </div>
           </div>
      </div>

      {/* Category List */}
      <div className="space-y-4">
          <h3 className="text-lg font-bold text-white border-b border-gray-800 pb-2">Category Allocations</h3>
          <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
              {activeAccounts.map(cat => {
                  const limit = categoryLimits[cat.id] || 0;
                  const spent = actualSpending[cat.id] || 0;
                  const catRemaining = limit - spent;
                  const catPercent = limit > 0 ? (spent / limit) * 100 : 0;

                  return (
                      <div key={cat.id} className="bg-gray-950/50 border border-gray-800 p-4 rounded-xl flex flex-col gap-3 group hover:border-gray-700 transition-colors">
                          <div className="flex justify-between items-start">
                              <div className="flex items-center gap-2">
                                  {/* No color in new Account, use generic dot */}
                                  <div className="w-2 h-2 rounded-full bg-blue-500"/>
                                  <span className="font-medium text-gray-300">{cat.name}</span>
                              </div>
                              <div className="flex items-center gap-1 bg-gray-900 rounded-lg border border-gray-800 px-2 py-1 focus-within:border-blue-500 focus-within:ring-1 focus-within:ring-blue-500 transition-all">
                                  <span className="text-xs text-gray-500">QR</span>
                                  <input 
                                    type="number" 
                                    className="w-20 bg-transparent text-right text-sm font-bold text-white outline-none" 
                                    placeholder="0"
                                    value={limit || ''}
                                    onChange={e => handleLimitChange(cat.id, e.target.value)}
                                  />
                              </div>
                          </div>

                          <div className="space-y-1">
                              <div className="flex justify-between text-xs text-gray-500">
                                  <span>Spent: {spent.toLocaleString()}</span>
                                  <span className={catRemaining < 0 ? 'text-red-400' : 'text-emerald-400'}>
                                      {catRemaining >= 0 ? 'Left: ' : 'Over: '} {Math.abs(catRemaining).toLocaleString()}
                                  </span>
                              </div>
                              <div className="h-1.5 bg-gray-800 rounded-full overflow-hidden">
                                  <div 
                                    className={`h-full rounded-full transition-all duration-500 ${catPercent > 100 ? 'bg-red-500' : 'bg-blue-500'}`} 
                                    style={{ width: `${Math.min(catPercent, 100)}%` }}
                                  />
                              </div>
                          </div>
                      </div>
                  );
              })}
              {activeAccounts.length === 0 && <div className="text-gray-500 text-sm col-span-full text-center py-10">No categories selected. Click settings to add some.</div>}
          </div>
      </div>

      <Modal isOpen={isManageOpen} onClose={() => setIsManageOpen(false)} title="Manage Budget Categories">
          <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-2">
              {allExpenseAccounts.map(cat => (
                  <div key={cat.id} className="flex items-center justify-between p-3 bg-gray-900 rounded-xl border border-gray-800 hover:bg-gray-800 cursor-pointer" onClick={() => handleVisibleToggle(cat.id)}>
                      <div className="flex items-center gap-3">
                          <span className="text-sm font-medium text-gray-200">{cat.name}</span>
                      </div>
                      {visibleAccountIds.includes(cat.id) 
                        ? <CheckSquare size={20} className="text-primary" /> 
                        : <Square size={20} className="text-gray-600" />
                      }
                  </div>
              ))}
          </div>
      </Modal>
    </div>
  );
};

import * as XLSX from 'xlsx';
import { AppState, MonthlyBudget, Receivable, Asset, Transaction, Account, Party, RecurringTransaction } from '../types';

export const excelService = {
  /**
   * Export the current AppState to a multi-sheet XLSX file.
   */
  exportDataToExcel: (data: AppState) => {
    const wb = XLSX.utils.book_new();

    // 1. Budget Sheet (Flattened)
    const budgetRows = (data.monthlyBudgets || []).map(b => {
        const row: any = {
            monthKey: b.monthKey,
            limit: b.limit,
            visibleAccountIds: b.visibleAccountIds ? b.visibleAccountIds.join(',') : ''
        };
        // Flatten limits: limit_accId = value
        if (b.categoryLimits) {
            Object.entries(b.categoryLimits).forEach(([accId, amount]) => {
                row[`limit_${accId}`] = amount;
            });
        }
        return row;
    });
    const wsBudget = XLSX.utils.json_to_sheet(budgetRows);
    XLSX.utils.book_append_sheet(wb, wsBudget, "Budget");

    // 2. Receivables (Separated)
    const receivables = data.receivables.filter(r => r.type === 'receivable').map(r => ({
        ...r,
        recurring: r.recurring ? JSON.stringify(r.recurring) : ''
    }));
    const wsRec = XLSX.utils.json_to_sheet(receivables);
    XLSX.utils.book_append_sheet(wb, wsRec, "Receivables");

    // 3. Payables (Separated)
    const payables = data.receivables.filter(r => r.type === 'payable').map(r => ({
        ...r,
        recurring: r.recurring ? JSON.stringify(r.recurring) : ''
    }));
    const wsPay = XLSX.utils.json_to_sheet(payables);
    XLSX.utils.book_append_sheet(wb, wsPay, "Payables");

    // 4. Assets
    const assets = data.assets.map(a => ({
        ...a,
        // Ensure dates are strings
        purchaseDate: a.purchaseDate ? new Date(a.purchaseDate).toISOString() : '',
        lastDepreciationDate: a.lastDepreciationDate ? new Date(a.lastDepreciationDate).toISOString() : ''
    }));
    const wsAssets = XLSX.utils.json_to_sheet(assets);
    XLSX.utils.book_append_sheet(wb, wsAssets, "Assets");

    // 5. Journal (Transactions)
    const journal = data.transactions.map(t => ({
        ...t,
        date: t.date ? new Date(t.date).toISOString() : ''
    }));
    const wsJournal = XLSX.utils.json_to_sheet(journal);
    XLSX.utils.book_append_sheet(wb, wsJournal, "Journal");

    // 6. Chart of Accounts
    const coa = data.accounts.map(c => ({
        ...c
    }));
    const wsCOA = XLSX.utils.json_to_sheet(coa);
    XLSX.utils.book_append_sheet(wb, wsCOA, "Chart of Accounts");

    // 7. Parties
    const wsParties = XLSX.utils.json_to_sheet(data.parties);
    XLSX.utils.book_append_sheet(wb, wsParties, "Parties");

    // 8. Recurring Rules
    const recurring = (data.recurring || []).map(r => ({
        ...r,
        nextDueDate: r.nextDueDate ? new Date(r.nextDueDate).toISOString() : ''
    }));
    const wsRecurring = XLSX.utils.json_to_sheet(recurring);
    XLSX.utils.book_append_sheet(wb, wsRecurring, "Recurring Rules");

    // Generate file
    XLSX.writeFile(wb, `Tarmi_Backup_${new Date().toISOString().split('T')[0]}.xlsx`);
  },

  /**
   * Parse an uploaded Excel file and reconstruct the AppState.
   */
  importDataFromExcel: async (file: File): Promise<Partial<AppState>> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const wb = XLSX.read(data, { type: 'array', cellDates: false }); // keep dates as strings/numbers primarily

                const result: Partial<AppState> = {};

                // Helper to get sheet data
                const getSheet = (name: string) => {
                    const ws = wb.Sheets[name];
                    return ws ? XLSX.utils.sheet_to_json(ws) : [];
                };

                // 1. Parse Budgets (Un-flatten)
                const rawBudgets = getSheet("Budget") as any[];
                result.monthlyBudgets = rawBudgets.map(row => {
                    const budget: MonthlyBudget = {
                        monthKey: row.monthKey,
                        limit: Number(row.limit) || 0,
                        visibleAccountIds: row.visibleAccountIds ? String(row.visibleAccountIds).split(',') : [],
                        categoryLimits: {}
                    };

                    // Extract dynamic limits
                    Object.keys(row).forEach(key => {
                        if (key.startsWith('limit_')) {
                            const accId = key.replace('limit_', '');
                            if (budget.categoryLimits) {
                                budget.categoryLimits[accId] = Number(row[key]);
                            }
                        }
                    });
                    return budget;
                });

                // 2. Parse Receivables & Payables (Merge & Un-stringify)
                const rawRec = getSheet("Receivables") as any[];
                const rawPay = getSheet("Payables") as any[];

                const processReceivable = (row: any, type: 'receivable' | 'payable'): Receivable => {
                    return {
                        id: String(row.id),
                        type: type,
                        partyName: row.partyName,
                        amount: Number(row.amount),
                        currency: row.currency,
                        dueDate: String(row.dueDate),
                        status: row.status,
                        notes: row.notes,
                        targetAccountId: row.targetAccountId,
                        partyId: row.partyId,
                        recurring: row.recurring ? JSON.parse(row.recurring) : undefined
                    } as Receivable;
                };

                const parsedRecs = rawRec.map(r => processReceivable(r, 'receivable'));
                const parsedPays = rawPay.map(r => processReceivable(r, 'payable'));
                result.receivables = [...parsedRecs, ...parsedPays];

                // 3. Assets
                const rawAssets = getSheet("Assets") as any[];
                result.assets = rawAssets.map(row => ({
                    ...row,
                    id: String(row.id),
                    value: Number(row.value),
                    originalValue: Number(row.originalValue),
                    usefulLifeYears: Number(row.usefulLifeYears),
                    // Ensure linkedAccountId is treated as string even if excel makes it a number
                    linkedAccountId: String(row.linkedAccountId)
                })) as Asset[];

                // 4. Journal
                const rawJournal = getSheet("Journal") as any[];
                result.transactions = rawJournal.map(row => ({
                    ...row,
                    id: String(row.id),
                    amount: Number(row.amount),
                    originalAmount: row.originalAmount ? Number(row.originalAmount) : undefined,
                    // Handle Excel making accountId a number if it looks like one
                    accountId: String(row.accountId),
                    paymentAccountId: row.paymentAccountId ? String(row.paymentAccountId) : undefined
                })) as Transaction[];

                // 5. COA
                const rawCOA = getSheet("Chart of Accounts") as any[];
                result.accounts = rawCOA.map(row => ({
                    ...row,
                    id: String(row.id),
                    // Ensure code is string
                    code: String(row.code),
                })) as Account[];

                // 6. Parties
                const rawEnt = getSheet("Parties") as any[];
                result.parties = rawEnt.map(row => ({
                    ...row,
                    id: String(row.id)
                })) as Party[];

                // 7. Recurring Rules
                const rawRecurring = getSheet("Recurring Rules") as any[];
                result.recurring = rawRecurring.map(row => ({
                    ...row,
                    id: String(row.id),
                    active: Boolean(row.active)
                })) as RecurringTransaction[];

                resolve(result);

            } catch (err) {
                console.error("Excel Parse Error:", err);
                reject(err);
            }
        };
        reader.readAsArrayBuffer(file);
    });
  }
};

import { GoogleGenAI } from "@google/genai";
import { AppState } from '../types';
import { format } from 'date-fns';

const AI_KEY = process.env.API_KEY || '';

export const aiService = {
  isEnabled: () => !!AI_KEY,

  /**
   * Generates a financial analysis or answer based on the current app state.
   */
  askCFO: async (query: string, state: AppState): Promise<string> => {
    if (!AI_KEY) return "AI service is not configured (Missing API Key).";

    try {
      const ai = new GoogleGenAI({ apiKey: AI_KEY });

      // 1. Prepare Context (Full Raw Data)
      const context = prepareFinancialContext(state);

      // 2. System Instruction
      const systemInstruction = `
        You are an expert AI CFO for "Tarmi FinTrack".

        DATA STRUCTURE:
        You have access to the full raw database in JSON format:
        1. "accounts": Definitions of income/expense buckets (Chart of Accounts).
        2. "transactions": The ledger of all money movements. (Links to accounts via 'accountId' and 'paymentAccountId').
        3. "receivables": Tracking of debts and money owed.

        RULES:
        - The currency is QAR (Qatari Riyal).
        - Today's date is ${format(new Date(), 'yyyy-MM-dd')}.
        - You must calculate totals dynamically from the "transactions" list.
        - If the user asks for "profit", calculate (Total Revenue - Total Expense).
        - If the user asks about a specific person (e.g., "How much do I owe Arlene?"), check the "receivables" list.
        - Be concise and actionable.
      `;

      // 3. Generate Content
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `
          Context Data:
          ${JSON.stringify(context)}

          User Query:
          ${query}
        `,
        config: {
          systemInstruction: systemInstruction,
          temperature: 0.2, // Lower temperature for better math consistency
        }
      });

      return response.text || "I couldn't generate a response.";
    } catch (error) {
      console.error("AI Error:", error);
      return "Sorry, I encountered an error analyzing your finances. Please try again later.";
    }
  }
};

/**
 * Helper to prepare the raw data feed.
 * Strips UI-specific fields to save tokens while preserving financial integrity.
 */
function prepareFinancialContext(state: AppState) {
  // 1. Accounts: Keep ID, Name, Class
  const accounts = state.accounts.map(c => ({
    id: c.id,
    name: c.name,
    class: c.class,
    code: c.code
  }));

  // 2. Transactions: Keep Date, Type, Amount, Account Links, and Notes
  const transactions = state.transactions.map(t => ({
    date: t.date.split('T')[0], // Simplified Date
    type: t.type,
    amount: t.amount,
    accountId: t.accountId,
    paymentAccountId: t.paymentAccountId,
    note: t.note
  }));

  // 3. Receivables: Keep Name, Amount, Due Date, and Status
  const receivables = state.receivables.map(r => ({
    type: r.type, // 'receivable' (owed to me) or 'payable' (owed by me)
    name: r.partyName,
    amount: r.amount,
    dueDate: r.dueDate.split('T')[0],
    status: r.status, // 'pending', 'paid'
    notes: r.notes
  }));

  return {
    accounts,
    transactions,
    receivables
  };
}

