              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                  {state.templates.map(t => (
                      <div key={t.id} className="bg-gray-900 border border-gray-800 p-4 rounded-xl flex flex-col items-center justify-center relative group hover:border-primary transition-all">
