                              {!node.isSystem && (
                                <button onClick={() => handleDelete('ACCOUNT', node.id)} className="p-1.5 text-gray-600 hover:text-red-400 hover:bg-gray-800 rounded"><Trash2 size={14} /></button>
                              )}
                          </div>
                      </div>
                  </div>
                  {/* Children Recursion */}
                  {(isExpanded || coaSearch) && hasChildren && (
                      <div className="border-l border-gray-800 ml-4">
                          {renderTreeNodes(node.children, depth + 1)}
                      </div>
                  )}
              </div>
          );
      });
  };

  // Flatten accounts for the "Parent" select dropdown
  const flatAccounts = useMemo(() => {
      // We only want Groups to be parents usually
      return state.accounts.filter(a => a.level === 'group' || a.level === 'class' || a.level === 'gl').sort((a,b) => a.code.localeCompare(b.code));
