               <div className="relative"><input type="file" accept=".json" ref={backupInputRef} onChange={handleRestore} className="hidden" id="json-restore"/><label htmlFor="json-restore" className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-200 px-4 py-2 rounded-lg text-sm font-medium border border-gray-700 cursor-pointer"><FileJson size={16} /> Restore</label></div>
