               <div className="relative"><input type="file" accept=".xlsx" ref={excelInputRef} onChange={handleExcelImport} className="hidden" id="excel-restore"/><label htmlFor="excel-restore" className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-200 px-4 py-2 rounded-lg text-sm font-medium border border-gray-700 cursor-pointer"><Upload size={16} /> Import</label></div>
          </div>
      </div>

      <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
          {['coa', 'recurring', 'sync', 'profile', 'parties', 'templates', 'danger'].map(t => (
              <button key={t} onClick={() => setActiveTab(t as Tab)} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors capitalize ${activeTab === t ? 'bg-primary text-white' : 'bg-gray-800 text-gray-400'}`}>
