import React, { useMemo, useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, isPast } from 'date-fns';
import { Calendar, FileText, Scale, Users, Download, Activity, Table, ScrollText } from 'lucide-react';
import { StatementOfAccount } from '../components/StatementOfAccount';
import { buildAccountTree, AccountNode } from '../utils/accountHierarchy';

type ReportTab = 'income_statement' | 'balance_sheet' | 'cash_flow' | 'ar_ap' | 'trial_balance' | 'soa';

const formatCurrency = (amount: number) => {
  return amount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2});
};

export const Reports: React.FC = () => {
  const { state } = useFinance();
  const [activeTab, setActiveTab] = useState<ReportTab>('income_statement');
  const [dateRange, setDateRange] = useState({
    start: format(startOfMonth(new Date()), 'yyyy-MM-dd'),
    end: format(endOfMonth(new Date()), 'yyyy-MM-dd')
  });

  const transactionsInPeriod = useMemo(() => {
    return state.transactions.filter(t => {
      const d = parseISO(t.date);
      const start = parseISO(dateRange.start);
      const end = parseISO(dateRange.end);
      end.setHours(23, 59, 59, 999);
      return isWithinInterval(d, { start, end });
    });
  }, [state.transactions, dateRange]);

  // Build Hierarchy for Balance Sheet (Uses ALL transactions up to end date)
  const balanceSheetTree = useMemo(() => {
      // For Balance Sheet, we need cumulative balance up to End Date.
      // We filter transactions first.
      const endDate = parseISO(dateRange.end);
      endDate.setHours(23, 59, 59, 999);

      const bsTransactions = state.transactions.filter(t => parseISO(t.date) <= endDate);
      return buildAccountTree(state.accounts, bsTransactions);
  }, [state.accounts, state.transactions, dateRange.end]);

  // Flat Calculation for Income Statement (Period Only)
  // Note: IS usually doesn't need full hierarchy traversal unless displaying groups, 
  // but let's stick to simple summation for IS to keep it fast.
  const incomeStatement = useMemo(() => {
      const getPeriodBalance = (accountId: string, type: 'revenue' | 'expense') => {
          let bal = 0;
          transactionsInPeriod.forEach(t => {
              if (t.accountId === accountId) bal += t.amount;
              if (t.paymentAccountId === accountId) bal -= t.amount;
          });
          // Rev: Credit Normal (Cr - Dr). Exp: Debit Normal (Dr - Cr)
          return type === 'revenue' ? (bal * -1) : bal;
      };

      const revenueAccs = state.accounts.filter(c => c.class === 'Revenue');
      const expenseAccs = state.accounts.filter(c => c.class === 'Expenses');

      const revenueBreakdown = revenueAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'revenue') })).filter(i => Math.abs(i.amount) > 0.01);
      const expenseBreakdown = expenseAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'expense') })).filter(i => Math.abs(i.amount) > 0.01);

      const totalRevenue = revenueBreakdown.reduce((s, i) => s + i.amount, 0);
      const totalExpenses = expenseBreakdown.reduce((s, i) => s + i.amount, 0);

      // Separate COGS if needed (based on code)
      const cogs = expenseBreakdown.filter(i => i.name.toLowerCase().includes('cost') || i.name.toLowerCase().includes('cogs'));
      const totalCOGS = cogs.reduce((s, i) => s + i.amount, 0);

      return { revenueBreakdown, totalRevenue, expenseBreakdown, totalExpenses, grossProfit: totalRevenue - totalCOGS, netIncome: totalRevenue - totalExpenses };
  }, [transactionsInPeriod, state.accounts]);

  // Helper to render Tree Rows in Report
  const renderReportNode = (nodes: AccountNode[], indent = 0) => {
      return nodes.map(node => (
          <React.Fragment key={node.id}>
              {node.totalBalance !== 0 && (
                  <div className="flex justify-between py-1 border-b border-gray-100 last:border-0 hover:bg-gray-50">
                      <span className={`pl-${indent * 4} ${node.level === 'group' || node.level === 'class' ? 'font-bold text-gray-800' : 'text-gray-600'} text-sm`}>
                          {node.name}
                      </span>
                      <span className={`text-sm font-mono ${node.level === 'group' ? 'font-bold' : ''}`}>
                          {formatCurrency(node.totalBalance)}
                      </span>
                  </div>
              )}
              {node.children.length > 0 && renderReportNode(node.children, indent + 2)}
          </React.Fragment>
      ));
  };

  const getNodeTotal = (nodes: AccountNode[]) => nodes.reduce((s, n) => s + n.totalBalance, 0);

  // Balance Sheet Totals
  const totalAssets = getNodeTotal(balanceSheetTree['Assets']);
  const totalLiabilities = getNodeTotal(balanceSheetTree['Liabilities']);
  const totalEquity = getNodeTotal(balanceSheetTree['Equity']);

  // Retained Earnings Calculation (Total Income - Total Expenses ALL TIME)
  // This is a simplified calculation. Real RE requires closing periods.
  // Ideally, we sum all Revenue and Expense accounts historically.
  const retainedEarnings = useMemo(() => {
      const endDate = parseISO(dateRange.end);
      endDate.setHours(23, 59, 59, 999);
      let re = 0;
      state.transactions.filter(t => parseISO(t.date) <= endDate).forEach(t => {
          const accDr = state.accounts.find(a => a.id === t.accountId);
          const accCr = state.accounts.find(a => a.id === t.paymentAccountId);

          // Income (Cr) increases RE. Expense (Dr) decreases RE.
          if (accCr?.class === 'Revenue') re += t.amount;
          if (accDr?.class === 'Revenue') re -= t.amount; // Returns/Contra Rev

          if (accDr?.class === 'Expenses') re -= t.amount;
          if (accCr?.class === 'Expenses') re += t.amount; // Reimbursements
      });
      return re;
  }, [state.transactions, state.accounts, dateRange.end]);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        {/* ... (Header & Tab Navigation same as before) ... */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 no-print">
            <div><h1 className="text-3xl font-bold text-white tracking-tight">Financial Reports</h1></div>
            {activeTab !== 'soa' && (
                <div className="flex gap-2 bg-gray-900 p-1 rounded-xl border border-gray-700">
                    <input type="date" value={dateRange.start} onChange={e => setDateRange(prev => ({...prev, start: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                    <span className="text-gray-500">to</span>
                    <input type="date" value={dateRange.end} onChange={e => setDateRange(prev => ({...prev, end: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                </div>
            )}
        </div>

        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar no-print">
            {['income_statement', 'balance_sheet', 'soa'].map(t => (
                <button key={t} onClick={() => setActiveTab(t as ReportTab)} className={`px-4 py-2 rounded-lg text-sm font-medium capitalize ${activeTab === t ? 'bg-primary text-white' : 'bg-gray-800 text-gray-400'}`}>{t.replace('_', ' ')}</button>
            ))}
        </div>

        {activeTab === 'soa' ? <StatementOfAccount appState={state} /> : (
            <div className="glass-card bg-white text-black p-8 rounded-2xl min-h-[600px] shadow-xl">
                <div className="text-center mb-8 border-b border-gray-200 pb-6">
                    <h2 className="text-2xl font-bold text-gray-900 uppercase">{state.businessProfile.name}</h2>
                    <h3 className="text-xl font-medium text-gray-600 mt-2 capitalize">{activeTab.replace('_', ' ')}</h3>
                    <p className="text-sm text-gray-500">As of {dateRange.end}</p>
                </div>

                {activeTab === 'balance_sheet' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-12 max-w-4xl mx-auto">
                        <div>
                            <h4 className="font-bold text-gray-800 border-b-2 border-gray-800 pb-2 mb-4">ASSETS</h4>
                            {renderReportNode(balanceSheetTree['Assets'])}
                            <div className="flex justify-between pt-4 mt-4 font-bold text-lg border-t border-gray-300"><span>TOTAL ASSETS</span><span>{formatCurrency(totalAssets)}</span></div>
                        </div>
                        <div>
                            <h4 className="font-bold text-gray-800 border-b-2 border-gray-800 pb-2 mb-4">LIABILITIES & EQUITY</h4>
                            <div className="mb-6">
                                <h5 className="font-bold text-sm text-gray-500 mb-2 uppercase">Liabilities</h5>
                                {renderReportNode(balanceSheetTree['Liabilities'])}
                                <div className="flex justify-between font-bold text-gray-700 mt-2 pt-2 border-t border-gray-200"><span>Total Liabilities</span><span>{formatCurrency(totalLiabilities)}</span></div>
                            </div>
                            <div>
                                <h5 className="font-bold text-sm text-gray-500 mb-2 uppercase">Equity</h5>
                                {renderReportNode(balanceSheetTree['Equity'])}
                                <div className="flex justify-between py-1 text-sm text-gray-600"><span>Retained Earnings (Calculated)</span><span>{formatCurrency(retainedEarnings)}</span></div>
                                <div className="flex justify-between font-bold text-gray-700 mt-2 pt-2 border-t border-gray-200"><span>Total Equity</span><span>{formatCurrency(totalEquity + retainedEarnings)}</span></div>
                            </div>
                            <div className="flex justify-between pt-4 mt-8 font-bold text-lg border-t border-gray-300"><span>TOTAL LIAB & EQUITY</span><span>{formatCurrency(totalLiabilities + totalEquity + retainedEarnings)}</span></div>
                        </div>
                    </div>
                )}

                {activeTab === 'income_statement' && (
                    <div className="max-w-2xl mx-auto space-y-6">
                        <div><h4 className="font-bold border-b mb-2">REVENUE</h4>{incomeStatement.revenueBreakdown.map(i => <div key={i.name} className="flex justify-between text-sm py-1"><span>{i.name}</span><span>{formatCurrency(i.amount)}</span></div>)}<div className="font-bold flex justify-between mt-2 pt-2 border-t"><span>Total Revenue</span><span>{formatCurrency(incomeStatement.totalRevenue)}</span></div></div>
                        <div><h4 className="font-bold border-b mb-2">EXPENSES</h4>{incomeStatement.expenseBreakdown.map(i => <div key={i.name} className="flex justify-between text-sm py-1"><span>{i.name}</span><span>{formatCurrency(i.amount)}</span></div>)}<div className="font-bold flex justify-between mt-2 pt-2 border-t"><span>Total Expenses</span><span>{formatCurrency(incomeStatement.totalExpenses)}</span></div></div>
                        <div className="bg-gray-900 text-white p-4 rounded-lg flex justify-between font-bold text-xl mt-8"><span>NET INCOME</span><span>{formatCurrency(incomeStatement.netIncome)}</span></div>
                    </div>
                )}
            </div>
        )}
    </div>
  );
};

# Advanced Supabase Setup Guide (Relational Schema)

This guide provides the SQL scripts to transform your Supabase project from a simple JSON document store into a fully normalized, enterprise-grade double-entry accounting database.

**Note:** This schema is designed for scalability, allowing for split transactions, complex reporting, and strict data integrity.

## Prerequisites
1. A [Supabase Project](https://supabase.com/dashboard).
2. Access to the **SQL Editor** in the Supabase Dashboard.

---

## 1. Database Schema Script

Copy and paste the following SQL block into your Supabase SQL Editor and run it.

```sql
-- 1. CLEANUP (Optional - Only run if starting fresh)
-- DROP TABLE IF EXISTS public.journal_lines;
-- DROP TABLE IF EXISTS public.journal_entries;
-- DROP TABLE IF EXISTS public.assets;
-- DROP TABLE IF EXISTS public.receivables;
-- DROP TABLE IF EXISTS public.parties;
-- DROP TABLE IF EXISTS public.accounts;
-- DROP TABLE IF EXISTS public.profiles;
-- DROP TYPE IF EXISTS account_class;
-- DROP TYPE IF EXISTS normal_balance;
-- DROP TYPE IF EXISTS entry_status;

-- 2. EXTENSIONS
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- 3. ENUMS
CREATE TYPE account_class AS ENUM ('Assets', 'Liabilities', 'Equity', 'Revenue', 'Expenses');
CREATE TYPE normal_balance AS ENUM ('debit', 'credit');
CREATE TYPE entry_status AS ENUM ('draft', 'posted', 'archived');
CREATE TYPE party_type AS ENUM ('customer', 'vendor', 'employee', 'other');

-- 4. TABLES

-- PROFILES (Links to Supabase Auth)
CREATE TABLE public.profiles (
    id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,
    business_name TEXT,
    email TEXT,
    currency TEXT DEFAULT 'QAR',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- ACCOUNTS (Chart of Accounts)
CREATE TABLE public.accounts (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    code TEXT NOT NULL,
    name TEXT NOT NULL,
    class account_class NOT NULL,
    parent_id UUID REFERENCES public.accounts(id),
    level TEXT CHECK (level IN ('class', 'group', 'gl', 'sub_ledger')),
    normal_balance normal_balance NOT NULL,
    is_posting BOOLEAN DEFAULT TRUE,
    is_system BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, code) -- Prevent duplicate codes per user
);

-- PARTIES (CRM - Vendors/Customers)
CREATE TABLE public.parties (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    name TEXT NOT NULL,
    type party_type DEFAULT 'other',
    email TEXT,
    phone TEXT,
    tax_id TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- JOURNAL ENTRIES (Transaction Headers)
CREATE TABLE public.journal_entries (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    date DATE NOT NULL DEFAULT CURRENT_DATE,
    reference TEXT, -- Invoice #, Check #
    notes TEXT,
    status entry_status DEFAULT 'posted',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- JOURNAL LINES (Debits and Credits)
CREATE TABLE public.journal_lines (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    entry_id UUID REFERENCES public.journal_entries(id) ON DELETE CASCADE NOT NULL,
    account_id UUID REFERENCES public.accounts(id) NOT NULL,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL, -- Denormalized for RLS performance
    description TEXT,
    debit NUMERIC(15, 2) DEFAULT 0,
    credit NUMERIC(15, 2) DEFAULT 0,
    party_id UUID REFERENCES public.parties(id),
    CHECK (debit >= 0 AND credit >= 0),
    CHECK (debit > 0 OR credit > 0) -- Line must have value
);

-- ASSETS (Fixed Assets Registry)
CREATE TABLE public.assets (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    name TEXT NOT NULL,
    purchase_date DATE NOT NULL,
    cost NUMERIC(15, 2) NOT NULL,
    salvage_value NUMERIC(15, 2) DEFAULT 0,
    useful_life_years INT NOT NULL,
    linked_gl_account_id UUID REFERENCES public.accounts(id),
    status TEXT DEFAULT 'active',
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 5. INDEXES
CREATE INDEX idx_accounts_user ON public.accounts(user_id);
CREATE INDEX idx_entries_user_date ON public.journal_entries(user_id, date);
CREATE INDEX idx_lines_entry ON public.journal_lines(entry_id);
CREATE INDEX idx_lines_account ON public.journal_lines(account_id);

-- 6. ROW LEVEL SECURITY (RLS)
-- Crucial: Ensure users only see their own data

ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.accounts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.parties ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.journal_entries ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.journal_lines ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.assets ENABLE ROW LEVEL SECURITY;

-- Policies
CREATE POLICY "Users can all on own profile" ON public.profiles FOR ALL USING (auth.uid() = id);
CREATE POLICY "Users can all on own accounts" ON public.accounts FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own parties" ON public.parties FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own entries" ON public.journal_entries FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own lines" ON public.journal_lines FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own assets" ON public.assets FOR ALL USING (auth.uid() = user_id);

-- 7. TRIGGER (Auto-create Profile)
CREATE OR REPLACE FUNCTION public.handle_new_user() 
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (id, email)
  VALUES (new.id, new.email);
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE PROCEDURE public.handle_new_user();

```

## 2. Advanced Views & Reporting (Optional)

Run these queries to create helper views that calculate balances automatically on the server side.

### View: Trial Balance (Real-time aggregation)
```sql
CREATE OR REPLACE VIEW view_account_balances AS
SELECT 
    a.id as account_id,
    a.user_id,
    a.code,
    a.name,
    a.class,
    a.normal_balance,
    SUM(COALESCE(jl.debit, 0)) as total_debit,
    SUM(COALESCE(jl.credit, 0)) as total_credit,
    CASE 
        WHEN a.normal_balance = 'debit' THEN SUM(COALESCE(jl.debit, 0)) - SUM(COALESCE(jl.credit, 0))
        ELSE SUM(COALESCE(jl.credit, 0)) - SUM(COALESCE(jl.debit, 0))
    END as net_balance
FROM 
    public.accounts a
LEFT JOIN 
    public.journal_lines jl ON a.id = jl.account_id
GROUP BY 
    a.id, a.user_id;
```

## 3. Connecting the Frontend

This schema represents the "Gold Standard" for accounting apps. The current `Tarmi FinTrack` frontend uses a local-first JSON sync approach.

To fully migrate to this schema, you would need to refactor `services/supabase.ts` to perform specific SQL operations instead of pushing a JSON blob.

**Example: How to insert a transaction using this schema:**

```typescript
const createTransaction = async (txHeader, debitLine, creditLine) => {
  // 1. Insert Header
  const { data: entry, error: entryError } = await supabase
    .from('journal_entries')
    .insert({
      date: txHeader.date,
      notes: txHeader.note,
      user_id: supabase.auth.user().id
    })
    .select()
    .single();

  if (entryError) throw entryError;

  // 2. Insert Lines
  const { error: linesError } = await supabase
    .from('journal_lines')
    .insert([
      {
        entry_id: entry.id,
        account_id: debitLine.accountId,
        debit: debitLine.amount,
        user_id: supabase.auth.user().id
      },
      {
        entry_id: entry.id,
        account_id: creditLine.accountId,
        credit: creditLine.amount,
        user_id: supabase.auth.user().id
      }
    ]);
}
```

import { Account, Transaction, AccountClass } from '../types';

export interface AccountNode extends Account {
  children: AccountNode[];
  totalBalance: number; // Aggregated (Self + Children)
  directBalance: number; // Transactions directly tagged to this account
}

/**
 * Calculates the direct balance of a specific account based on transactions.
 * Returns absolute value for display, but respects normal balance logic internally.
 */
export const calculateDirectBalance = (accountId: string, transactions: Transaction[], normalBalance: 'debit' | 'credit'): number => {
  let dr = 0;
  let cr = 0;

  transactions.forEach(t => {
    if (t.accountId === accountId) dr += t.amount;
    if (t.paymentAccountId === accountId) cr += t.amount;
  });

  // If Debit Normal (Assets/Exp): Balance = Dr - Cr
  // If Credit Normal (Liab/Eq/Rev): Balance = Cr - Dr
  const val = normalBalance === 'debit' ? (dr - cr) : (cr - dr);
  return val; 
};

/**
 * Recursively builds a tree of accounts and aggregates balances.
 * AUTOMATIC FEATURE: Calculates Net Income and adds it to Retained Earnings (Carry Over).
 */
export const buildAccountTree = (
  accounts: Account[], 
  transactions: Transaction[]
): Record<AccountClass, AccountNode[]> => {

  // 1. Calculate Global Net Income (Revenue - Expenses) for Carry Over
  let totalRevenue = 0;
  let totalExpenses = 0;

  // We need a map of account IDs to their class to sum correctly
  const accountClassMap = new Map<string, AccountClass>();
  accounts.forEach(a => accountClassMap.set(a.id, a.class));

  transactions.forEach(t => {
      // Impact on Account ID (Debit side)
      const drClass = accountClassMap.get(t.accountId);
      if (drClass === 'Expenses') totalExpenses += t.amount;
      if (drClass === 'Revenue') totalRevenue -= t.amount; // Revenue is Credit normal, Debit reduces it

      // Impact on Payment Account ID (Credit side)
      const crClass = accountClassMap.get(t.paymentAccountId || '');
      if (crClass === 'Revenue') totalRevenue += t.amount; // Credit increases Revenue
      if (crClass === 'Expenses') totalExpenses -= t.amount; // Credit reduces Expense (Reimbursement)
  });

  const netIncome = totalRevenue - totalExpenses;

  // 2. Initialize Nodes with Direct Balance
  const nodes: Record<string, AccountNode> = {};

  // Identify the target account for Carry Over (Retained Earnings or Opening Balance)
  const retainedEarningsAcc = accounts.find(a => a.code === '32000') || accounts.find(a => a.code === '31000');

  accounts.forEach(acc => {
    let balance = calculateDirectBalance(acc.id, transactions, acc.normalBalance);

    // AUTOMATIC CARRY OVER: Inject Net Income into Retained Earnings
    if (retainedEarningsAcc && acc.id === retainedEarningsAcc.id) {
        // Equity is Credit Normal. Positive Net Income increases Equity.
        // If Net Income is negative (Loss), it reduces Equity.
        balance += netIncome;
    }

    nodes[acc.id] = {
      ...acc,
      children: [],
      directBalance: balance,
      totalBalance: 0
    };
  });

  // 3. Build Tree Structure
  const roots: Record<AccountClass, AccountNode[]> = {
    'Assets': [],
    'Liabilities': [],
    'Equity': [],
    'Revenue': [],
    'Expenses': []
  };

  const orphanNodes: AccountNode[] = [];

  accounts.forEach(acc => {
    const node = nodes[acc.id];
    if (acc.parentId && nodes[acc.parentId]) {
      nodes[acc.parentId].children.push(node);
    } else {
      // It's a root level item (Class or Top Group)
      if (roots[acc.class]) {
        roots[acc.class].push(node);
      } else {
        orphanNodes.push(node);
      }
    }
  });

  // 4. Recursive Aggregation Function
  const aggregate = (node: AccountNode): number => {
    const childSum = node.children.reduce((sum, child) => sum + aggregate(child), 0);
    node.totalBalance = node.directBalance + childSum;
    return node.totalBalance;
  };

  // 5. Trigger Aggregation from Roots
  Object.values(roots).forEach(classList => {
    classList.forEach(rootNode => aggregate(rootNode));
    // Sort by code
    classList.sort((a,b) => a.code.localeCompare(b.code));
  });

  return roots;
};

export const flattenTree = (nodes: AccountNode[]): AccountNode[] => {
    let result: AccountNode[] = [];
    nodes.forEach(node => {
        result.push(node);
        if (node.children.length > 0) {
            result = result.concat(flattenTree(node.children));
        }
    });
    return result;
};

import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Receivable, Transaction, CurrencyCode, RecurrenceFrequency } from '../types';
import { EXCHANGE_RATE_QAR_TO_PHP } from '../constants';
import { format, isPast, addDays, addWeeks, addMonths, addYears } from 'date-fns';
import { Plus, CheckCircle, ArrowUpRight, ArrowDownLeft, Repeat, Pencil, Trash2, HandCoins, FileText, Filter } from 'lucide-react';
import { Modal } from '../components/ui/Modal';
import { SearchableSelect } from '../components/ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';
import { InvoiceModal } from '../components/InvoiceModal';

type Mode = 'receivable' | 'payable';
type SubMode = 'invoice' | 'bill' | 'loan';

export const ApAr: React.FC = () => {
  const { state, dispatch } = useFinance();
  const [activeTab, setActiveTab] = useState<'all' | 'receivable' | 'payable'>('all');

  // Modals
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
  const [invoiceData, setInvoiceData] = useState<Receivable | null>(null);

  // Selection
  const [selectedItem, setSelectedItem] = useState<Receivable | null>(null);

  // Form State
  const [formMode, setFormMode] = useState<Mode>('receivable');
  const [formSubMode, setFormSubMode] = useState<SubMode>('invoice');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [partyId, setPartyId] = useState('');
  const [targetAccountId, setTargetAccountId] = useState('');
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState<CurrencyCode>('QAR');
  const [dueDate, setDueDate] = useState('');
  const [notes, setNotes] = useState('');
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');

  // Payment State
  const [paymentAccountId, setPaymentAccountId] = useState('');

  // --- HELPERS ---

  const getPartyOptions = (mode: Mode) => {
    const type = mode === 'receivable' ? 'customer' : 'vendor';
    return state.parties.filter(p => p.type === type).map(p => ({ id: p.id, label: p.name }));
  };

  const getAccountOptions = (mode: Mode, subMode: SubMode) => {
    if (mode === 'receivable') {
        if (subMode === 'loan') {
            // Money leaving Bank (Credit Asset)
            return state.accounts.filter(a => a.class === 'Assets').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
        }
        // Revenue (Credit Revenue)
        return state.accounts.filter(a => a.class === 'Revenue').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
    } else {
        if (subMode === 'loan') {
             // Money entering Bank (Debit Asset)
             return state.accounts.filter(a => a.class === 'Assets').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
        }
        // Expense (Debit Expense)
        return state.accounts.filter(a => a.class === 'Expenses' || a.class === 'Liabilities').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
    }
  };

  const cashOptions = state.accounts.filter(a => a.class === 'Assets').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));

  // --- ACTIONS ---

  const handleOpenAdd = (mode: Mode, subMode: SubMode) => {
      resetForm();
      setFormMode(mode);
      setFormSubMode(subMode);

      // Auto-select bank for loans
      if (subMode === 'loan') {
          const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank'));
          if (bank) setTargetAccountId(bank.id);
      }

      setIsFormOpen(true);
  };

  const handleOpenEdit = (item: Receivable) => {
      setEditingId(item.id);
      setFormMode(item.type);
      setFormSubMode(item.subType || (item.type === 'receivable' ? 'invoice' : 'bill'));
      setPartyId(item.partyId || '');
      setTargetAccountId(item.targetAccountId || '');
      setAmount((item.originalAmount || item.amount).toString());
      setCurrency(item.currency || 'QAR');
      setDueDate(item.dueDate.split('T')[0]);
      setNotes(item.notes || '');
      setIsRecurring(!!item.recurring?.active);
      setRecurFreq(item.recurring?.frequency || 'monthly');
      setIsFormOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
      e.preventDefault();
      const finalValStr = evaluateMathExpression(amount);
      const val = parseFloat(finalValStr);
      if (isNaN(val) || !partyId || !targetAccountId) {
          alert("Please fill all required fields correctly.");
          return;
      }

      const finalAmountQAR = currency === 'PHP' ? val / EXCHANGE_RATE_QAR_TO_PHP : val;
      const party = state.parties.find(p => p.id === partyId);
      const newId = editingId || Math.random().toString(36).substr(2, 9);

      const payload: Receivable = {
          id: newId,
          type: formMode,
          subType: formSubMode,
          partyId,
          partyName: party?.name || 'Unknown',
          targetAccountId,
          amount: finalAmountQAR,
          originalAmount: val,
          currency,
          dueDate: new Date(dueDate).toISOString(),
          status: 'pending',
          notes,
          recurring: isRecurring ? { active: true, amount: val, frequency: recurFreq, nextDueDate: dueDate } : undefined
      };

      if (editingId) {
          dispatch({ type: 'UPDATE_RECEIVABLE', payload });
      } else {
          dispatch({ type: 'ADD_RECEIVABLE', payload });
          createAccrualTransaction(payload, newId);
      }
      setIsFormOpen(false);
  };

  const createAccrualTransaction = (item: Receivable, id: string) => {
      // Logic to create the underlying GL transaction
      // AR Account (11200) or AP Account (21100)
      const arAcc = state.accounts.find(a => a.name.includes('Accounts Receivable'))?.id || '11200';
      const apAcc = state.accounts.find(a => a.name.includes('Accounts Payable'))?.id || '21100';

      const tx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: new Date().toISOString(),
          currency: item.currency,
          amount: item.amount,
          originalAmount: item.originalAmount,
          relatedPartyId: item.partyId,
          source: item.subType === 'loan' ? 'personal' : (item.type === 'receivable' ? 'side_hustle' : 'personal'),
          note: `Accrual: ${item.subType} #${id.substr(0,4)}`,
          type: item.type === 'receivable' ? (item.subType === 'loan' ? 'transfer' : 'income') : (item.subType === 'loan' ? 'transfer' : 'expense'),

          // MAPPING LOGIC
          // Receivable Invoice: Dr AR, Cr Revenue
          // Receivable Loan: Dr AR, Cr Bank (Money Out)
          // Payable Bill: Dr Expense, Cr AP
          // Payable Loan: Dr Bank (Money In), Cr AP

          accountId: item.type === 'receivable' 
            ? arAcc // Dr AR
            : (item.subType === 'loan' ? item.targetAccountId : item.targetAccountId), // Dr Bank or Expense

          paymentAccountId: item.type === 'receivable'
            ? item.targetAccountId // Cr Revenue or Bank
            : apAcc // Cr AP
      };

      dispatch({ type: 'ADD_TRANSACTION', payload: tx });
  };

  const handleDelete = (id: string) => {
      if(confirm("Delete this record? Associated Journal Entries will be removed.")) {
          dispatch({ type: 'DELETE_RECEIVABLE', payload: id });
      }
  };

  const handleOpenPayment = (item: Receivable) => {
      setSelectedItem(item);
      // Auto-select bank
      const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank'));
      setPaymentAccountId(bank ? bank.id : '');
      setIsPaymentModalOpen(true);
  };

  const handleProcessPayment = (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedItem || !paymentAccountId) return;

      const item = selectedItem;
      dispatch({ type: 'UPDATE_RECEIVABLE', payload: { ...item, status: 'paid', paidDate: new Date().toISOString() } });

      // Create Payment Transaction
      const arAcc = state.accounts.find(a => a.name.includes('Accounts Receivable'))?.id || '11200';
      const apAcc = state.accounts.find(a => a.name.includes('Accounts Payable'))?.id || '21100';

      const tx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: new Date().toISOString(),
          currency: item.currency,
          amount: item.amount,
          originalAmount: item.originalAmount,
          relatedPartyId: item.partyId,
          source: item.subType === 'loan' ? 'personal' : (item.type === 'receivable' ? 'side_hustle' : 'personal'),
          note: `Settlement: ${item.subType} #${item.id.substr(0,4)}`,

          // PAYMENT LOGIC
          // Pay Receivable: Dr Bank, Cr AR
          // Pay Payable: Dr AP, Cr Bank
          type: item.type === 'receivable' ? 'income' : 'expense', // Roughly

          accountId: item.type === 'receivable' ? paymentAccountId : apAcc,
          paymentAccountId: item.type === 'receivable' ? arAcc : paymentAccountId
      };

      dispatch({ type: 'ADD_TRANSACTION', payload: tx });

      // Handle Recurring
      if (item.recurring?.active) {
          let nextDate = new Date(item.dueDate);
          const freq = item.recurring.frequency;
          if (freq === 'daily') nextDate = addDays(nextDate, 1);
          if (freq === 'weekly') nextDate = addWeeks(nextDate, 1);
          if (freq === 'monthly') nextDate = addMonths(nextDate, 1);
          if (freq === 'yearly') nextDate = addYears(nextDate, 1);

          const nextItem: Receivable = {
              ...item,
              id: Math.random().toString(36).substr(2, 9),
              dueDate: nextDate.toISOString(),
              status: 'pending',
              paidDate: undefined
          };
          dispatch({ type: 'ADD_RECEIVABLE', payload: nextItem });
      }

      setIsPaymentModalOpen(false);
  };

  const resetForm = () => {
      setEditingId(null); setPartyId(''); setTargetAccountId(''); setAmount(''); setNotes(''); setIsRecurring(false); setDueDate('');
  };

  // --- RENDER ---

  const filteredList = state.receivables.filter(item => {
      if (item.status === 'paid') return false; // Hide paid
      if (activeTab === 'all') return true;
      return item.type === activeTab;
  }).sort((a,b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  const totalAr = state.receivables.filter(r => r.type === 'receivable' && r.status === 'pending').reduce((s, r) => s + r.amount, 0);
  const totalAp = state.receivables.filter(r => r.type === 'payable' && r.status === 'pending').reduce((s, r) => s + r.amount, 0);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h1 className="text-3xl font-bold text-gray-100 tracking-tight">AP / AR</h1>
                <p className="text-gray-400 text-sm">Manage invoices, bills, and loans</p>
            </div>
            <div className="flex gap-2">
                <button onClick={() => handleOpenAdd('receivable', 'invoice')} className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-3 py-2 rounded-xl text-xs font-bold uppercase transition-colors"><Plus size={16} /> New Invoice</button>
                <button onClick={() => handleOpenAdd('payable', 'bill')} className="flex items-center gap-2 bg-orange-600 hover:bg-orange-700 text-white px-3 py-2 rounded-xl text-xs font-bold uppercase transition-colors"><Plus size={16} /> New Bill</button>
                <button onClick={() => handleOpenAdd('receivable', 'loan')} className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-2 rounded-xl text-xs font-bold uppercase transition-colors"><HandCoins size={16} /> Loan</button>
            </div>
        </div>

        {/* SUMMARY CARDS */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
            <div className="bg-emerald-900/20 border border-emerald-500/30 p-4 rounded-2xl">
                <p className="text-xs font-bold text-emerald-400 uppercase mb-1">Total Receivables</p>
                <p className="text-2xl font-bold text-white">QR {totalAr.toLocaleString()}</p>
                <div className="mt-2 text-[10px] text-gray-400">Expecting In</div>
            </div>
            <div className="bg-orange-900/20 border border-orange-500/30 p-4 rounded-2xl">
                <p className="text-xs font-bold text-orange-400 uppercase mb-1">Total Payables</p>
                <p className="text-2xl font-bold text-white">QR {totalAp.toLocaleString()}</p>
                <div className="mt-2 text-[10px] text-gray-400">Expecting Out</div>
            </div>
             <div className="bg-gray-900/40 border border-gray-800 p-4 rounded-2xl hidden md:block">
                <p className="text-xs font-bold text-gray-400 uppercase mb-1">Net Position</p>
                <p className={`text-2xl font-bold ${(totalAr - totalAp) >= 0 ? 'text-blue-400' : 'text-red-400'}`}>
                    QR {(totalAr - totalAp).toLocaleString()}
                </p>
                <div className="mt-2 text-[10px] text-gray-500">Projected Cashflow Impact</div>
            </div>
        </div>

        {/* TABS */}
        <div className="flex border-b border-gray-800">
             <button onClick={() => setActiveTab('all')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'all' ? 'border-primary text-white' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>All Pending</button>
             <button onClick={() => setActiveTab('receivable')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'receivable' ? 'border-emerald-500 text-emerald-400' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>Receivables</button>
             <button onClick={() => setActiveTab('payable')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'payable' ? 'border-orange-500 text-orange-400' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>Payables</button>
        </div>

        {/* LIST */}
        <div className="grid gap-4">
            {filteredList.map(item => {
                const isOverdue = isPast(new Date(item.dueDate));
                const colorClass = item.type === 'receivable' ? 'text-emerald-400' : 'text-orange-400';
                const bgClass = item.type === 'receivable' ? 'bg-emerald-500/10' : 'bg-orange-500/10';
                const icon = item.subType === 'loan' ? <HandCoins size={20}/> : (item.type === 'receivable' ? <ArrowDownLeft size={20}/> : <ArrowUpRight size={20}/>);
                const accName = state.accounts.find(c => c.id === item.targetAccountId)?.name;

                return (
                    <div key={item.id} className="glass-panel p-5 rounded-xl flex flex-col sm:flex-row sm:items-center justify-between gap-4 group hover:bg-gray-800/40 transition-colors">
                        <div className="flex items-start gap-4">
                             <div className={`p-3 rounded-xl shrink-0 ${bgClass} ${colorClass}`}>
                                 {icon}
                             </div>
                             <div>
                                 <div className="flex items-center gap-2">
                                     <h3 className="font-bold text-gray-200">{item.partyName}</h3>
                                     {item.recurring?.active && <Repeat size={14} className="text-blue-400" />}
                                     <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${item.type === 'receivable' ? 'bg-emerald-900/30 text-emerald-400' : 'bg-orange-900/30 text-orange-400'}`}>{item.subType}</span>
                                 </div>
                                 <p className="text-sm text-gray-400">{item.notes}</p>
                                 <div className="flex items-center gap-3 mt-1.5">
                                      <span className={`text-xs ${isOverdue ? 'text-red-400 font-bold' : 'text-gray-500'}`}>Due {format(new Date(item.dueDate), 'MMM d')}</span>
                                      <span className="text-xs text-gray-600">• {accName}</span>
                                 </div>
                             </div>
                        </div>

                        <div className="flex items-center justify-between sm:justify-end gap-6 w-full sm:w-auto border-t sm:border-t-0 border-gray-800 pt-3 sm:pt-0">
                             <div className="text-right">
                                 <span className={`block text-xl font-bold ${colorClass}`}>
                                    {item.type === 'receivable' ? '+' : '-'} {item.amount.toLocaleString()}
                                 </span>
                                 {item.currency === 'PHP' && <span className="text-xs text-gray-500">₱{item.originalAmount?.toLocaleString()}</span>}
                             </div>
                             <div className="flex gap-1">
                                 <button onClick={() => handleOpenPayment(item)} className={`p-2 rounded-lg transition-colors ${item.type === 'receivable' ? 'bg-emerald-600/20 text-emerald-400 hover:bg-emerald-600/40' : 'bg-orange-600/20 text-orange-400 hover:bg-orange-600/40'}`} title="Settle">
                                     <CheckCircle size={18} />
                                 </button>
                                 <button onClick={() => handleOpenEdit(item)} className="p-2 text-gray-500 hover:text-white hover:bg-gray-800 rounded-lg"><Pencil size={18}/></button>
                                 <button onClick={() => handleDelete(item.id)} className="p-2 text-gray-500 hover:text-red-400 hover:bg-gray-800 rounded-lg"><Trash2 size={18}/></button>
                                 {item.type === 'receivable' && item.subType !== 'loan' && (
                                     <button onClick={() => setInvoiceData(item)} className="p-2 text-gray-500 hover:text-blue-400 hover:bg-gray-800 rounded-lg"><FileText size={18}/></button>
                                 )}
                             </div>
                        </div>
                    </div>
                );
            })}
            {filteredList.length === 0 && <div className="text-center py-12 text-gray-500 border border-dashed border-gray-800 rounded-xl">No active records found.</div>}
        </div>

        {/* CREATE/EDIT MODAL */}
        <Modal isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} title={`${editingId ? 'Edit' : 'New'} ${formSubMode.charAt(0).toUpperCase() + formSubMode.slice(1)}`}>
            <form onSubmit={handleSave} className="space-y-4">
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Entity</label>
                    <SearchableSelect options={getPartyOptions(formMode)} value={partyId} onChange={setPartyId} required placeholder="Select Name..." />
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">
                        {formMode === 'receivable' ? 'Revenue / Source Account' : 'Expense / Asset Account'}
                    </label>
                    <SearchableSelect options={getAccountOptions(formMode, formSubMode)} value={targetAccountId} onChange={setTargetAccountId} required placeholder="Select Account..." />
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Amount</label>
                    <div className="flex gap-2">
                        <input type="text" className="flex-1 px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary" value={amount} onChange={e => setAmount(e.target.value)} onBlur={() => setAmount(evaluateMathExpression(amount))} placeholder="0.00" required />
                        <select className="w-24 px-2 bg-gray-950 border border-gray-700 rounded-xl text-white outline-none" value={currency} onChange={e => setCurrency(e.target.value as CurrencyCode)}>
                            <option value="QAR">QAR</option>
                            <option value="PHP">PHP</option>
                        </select>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                         <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Due Date</label>
                         <input type="date" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary" value={dueDate} onChange={e => setDueDate(e.target.value)} required />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Recurrence</label>
                        <div className="flex items-center gap-2 h-[42px] px-3 bg-gray-900 border border-gray-700 rounded-xl">
                            <input type="checkbox" checked={isRecurring} onChange={e => setIsRecurring(e.target.checked)} className="w-4 h-4 bg-gray-800 border-gray-600 rounded" />
                            <select disabled={!isRecurring} value={recurFreq} onChange={e => setRecurFreq(e.target.value as RecurrenceFrequency)} className="bg-transparent text-xs text-white outline-none disabled:opacity-50">
                                <option value="monthly">Monthly</option>
                                <option value="weekly">Weekly</option>
                                <option value="yearly">Yearly</option>
                            </select>
                        </div>
                    </div>
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Notes</label>
                    <input type="text" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary" value={notes} onChange={e => setNotes(e.target.value)} placeholder="Description..." />
                </div>
                <button className={`w-full py-3 rounded-xl font-bold text-white shadow-lg transition-transform active:scale-[0.98] ${formMode === 'receivable' ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-900/20' : 'bg-orange-600 hover:bg-orange-700 shadow-orange-900/20'}`}>
                    Save Record
                </button>
            </form>
        </Modal>

        {/* PAYMENT MODAL */}
        <Modal isOpen={isPaymentModalOpen} onClose={() => setIsPaymentModalOpen(false)} title={`Settle ${selectedItem?.type === 'receivable' ? 'Invoice' : 'Bill'}`}>
             <form onSubmit={handleProcessPayment} className="space-y-4">
                <div className="p-4 bg-gray-900/50 rounded-xl mb-4 border border-gray-800 text-center">
                    <p className="text-sm text-gray-400">Total Amount</p>
                    <p className="text-2xl font-bold text-white">QR {selectedItem?.amount.toLocaleString()}</p>
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">
                        {selectedItem?.type === 'receivable' ? 'Deposit To (Debit)' : 'Pay From (Credit)'}
                    </label>
                    <SearchableSelect options={cashOptions} value={paymentAccountId} onChange={setPaymentAccountId} required placeholder="Select Cash/Bank..." />
                </div>
                <button className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold shadow-lg shadow-blue-900/20">
                    Confirm Settlement
                </button>
             </form>
        </Modal>

        {/* INVOICE PREVIEW */}
        {invoiceData && <InvoiceModal isOpen={!!invoiceData} onClose={() => setInvoiceData(null)} data={invoiceData} appState={state} />}
    </div>
  );
};

