import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { supabase } from '../services/supabase';
import { Database, CheckCircle, AlertTriangle, Loader2, ArrowRight } from 'lucide-react';
import { Account, Transaction } from '../types';

export const MigrationTool: React.FC = () => {
  const { state, user } = useFinance();
  const [status, setStatus] = useState<'idle' | 'running' | 'success' | 'error'>('idle');
  const [logs, setLogs] = useState<string[]>([]);
  const [progress, setProgress] = useState(0);

  const addLog = (msg: string) => setLogs(prev => [...prev, msg]);

  // Helper to generate UUIDs if crypto.randomUUID is not available
  const generateUUID = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  const runMigration = async () => {
    if (!user) {
        addLog("Error: You must be logged in to Supabase.");
        setStatus('error');
        return;
    }

    if (!confirm("This will overwrite/insert data into your SQL tables. Ensure you have run the Schema SQL first. Continue?")) return;

    setStatus('running');
    setLogs([]);
    setProgress(0);

    try {
        const userId = user.id;

        // 1. MAPPING DICTIONARIES (Old ID -> New UUID)
        const accountMap: Record<string, string> = {};
        const partyMap: Record<string, string> = {};

        // --- STEP 1: PREPARE ACCOUNTS ---
        addLog("Step 1: Transforming Accounts...");
        const sqlAccounts = state.accounts.map(acc => {
            const newId = generateUUID();
            accountMap[acc.id] = newId; // Store mapping
            return {
                id: newId,
                user_id: userId,
                code: acc.code,
                name: acc.name,
                class: acc.class,
                level: acc.level,
                normal_balance: acc.normalBalance,
                is_posting: acc.isPosting,
                is_system: acc.isSystem || false,
                // We resolve parent_id later or now? 
                // Problem: Parent might be further down the list. 
                // We need 2 passes.
            };
        });

        // Resolve Parent IDs
        const finalAccounts = sqlAccounts.map(sqlAcc => {
            const original = state.accounts.find(a => a.code === sqlAcc.code); // Match by code/name as ID changed
            // Actually better to look up by original ID using the index logic or finding source
            // Let's iterate original accounts again to find parent
            const sourceAcc = state.accounts.find(old => accountMap[old.id] === sqlAcc.id);
            let parentId = null;
            if (sourceAcc && sourceAcc.parentId && accountMap[sourceAcc.parentId]) {
                parentId = accountMap[sourceAcc.parentId];
            }
            return { ...sqlAcc, parent_id: parentId };
        });

        const { error: accError } = await supabase.from('accounts').upsert(finalAccounts, { onConflict: 'user_id,code' });
        if (accError) throw new Error(`Account Sync Failed: ${accError.message}`);
        addLog(`✅ Synced ${finalAccounts.length} accounts.`);
        setProgress(20);

        // --- STEP 2: PREPARE PARTIES ---
        addLog("Step 2: Transforming Parties...");
        const sqlParties = state.parties.map(p => {
            const newId = generateUUID();
            partyMap[p.id] = newId;
            return {
                id: newId,
                user_id: userId,
                name: p.name,
                type: p.type,
                phone: p.phone,
                email: p.email
            };
        });

        const { error: partyError } = await supabase.from('parties').upsert(sqlParties);
        if (partyError) throw new Error(`Party Sync Failed: ${partyError.message}`);
        addLog(`✅ Synced ${sqlParties.length} parties.`);
        setProgress(40);

        // --- STEP 3: ASSETS ---
        addLog("Step 3: Transforming Assets...");
        const sqlAssets = state.assets.map(a => ({
            id: generateUUID(), // New ID for asset
            user_id: userId,
            name: a.name,
            cost: a.originalValue,
            purchase_date: a.purchaseDate,
            useful_life_years: a.usefulLifeYears,
            status: 'active',
            linked_gl_account_id: a.linkedAccountId ? accountMap[a.linkedAccountId] : null
        }));

        if (sqlAssets.length > 0) {
            const { error: assetError } = await supabase.from('assets').upsert(sqlAssets);
            if (assetError) throw new Error(`Asset Sync Failed: ${assetError.message}`);
        }
        addLog(`✅ Synced ${sqlAssets.length} assets.`);
        setProgress(60);

        // --- STEP 4: TRANSACTIONS (JOURNAL ENTRIES) ---
        addLog("Step 4: Transforming Journal Entries...");
        const entriesBatch: any[] = [];
        const linesBatch: any[] = [];

        state.transactions.forEach(t => {
            const entryId = generateUUID();

            // Header
            entriesBatch.push({
                id: entryId,
                user_id: userId,
                date: t.date,
                notes: t.note,
                reference: t.relatedPartyId ? `Ref: ${t.relatedPartyId.substring(0,6)}` : null,
                status: 'posted'
            });

            // Lines Logic
            // Account A (The 'accountId' in AppState)
            // If Income: Credit. If Expense: Debit. If Transfer: Debit (Destination).
            const isIncome = t.type === 'income';
            const isExpense = t.type === 'expense';
            const isTransfer = t.type === 'transfer';

            const accIdA = accountMap[t.accountId];
            const accIdB = accountMap[t.paymentAccountId || ''];

            if (accIdA) {
                const lineA: any = {
                    entry_id: entryId,
                    user_id: userId,
                    account_id: accIdA,
                    description: t.note || 'Transaction Line'
                };

                if (isIncome) lineA.credit = t.amount;
                else lineA.debit = t.amount; // Expense or Transfer Destination (Dr)

                if (t.relatedPartyId && partyMap[t.relatedPartyId]) {
                    lineA.party_id = partyMap[t.relatedPartyId];
                }

                linesBatch.push(lineA);
            }

            if (accIdB) {
                const lineB: any = {
                    entry_id: entryId,
                    user_id: userId,
                    account_id: accIdB,
                    description: 'Offset / Payment'
                };

                if (isIncome) lineB.debit = t.amount; // Money In (Dr)
                else lineB.credit = t.amount; // Money Out (Cr) or Transfer Source (Cr)

                linesBatch.push(lineB);
            }
        });

        // Batch Insert Entries
        // Chunking to be safe (e.g. 100 at a time)
        const chunkSize = 100;
        for (let i = 0; i < entriesBatch.length; i += chunkSize) {
            const chunk = entriesBatch.slice(i, i + chunkSize);
            const { error } = await supabase.from('journal_entries').insert(chunk);
            if (error) throw error;
        }
        addLog(`✅ Synced headers for ${entriesBatch.length} transactions.`);
        setProgress(80);

        // Batch Insert Lines
        for (let i = 0; i < linesBatch.length; i += chunkSize) {
            const chunk = linesBatch.slice(i, i + chunkSize);
            const { error } = await supabase.from('journal_lines').insert(chunk);
            if (error) throw error;
        }
        addLog(`✅ Synced ${linesBatch.length} ledger lines.`);

        setProgress(100);
        setStatus('success');
        addLog("🎉 MIGRATION COMPLETE!");

    } catch (e: any) {
        console.error(e);
        addLog(`❌ CRITICAL ERROR: ${e.message}`);
        setStatus('error');
    }
  };

  return (
    <div className="bg-black/40 border border-gray-800 rounded-xl p-6 max-w-2xl mx-auto mt-8">
        <div className="flex items-start gap-4 mb-6">
            <div className="p-3 bg-indigo-500/20 rounded-lg text-indigo-400">
                <Database size={24} />
            </div>
            <div>
                <h2 className="text-xl font-bold text-white">Relational Data Migration</h2>
                <p className="text-sm text-gray-400 mt-1">
                    Push your local JSON data into the advanced Supabase SQL tables (`accounts`, `journal_entries`, etc).
                </p>
            </div>
        </div>

        <div className="bg-gray-900 rounded-lg p-4 mb-6 border border-gray-800 font-mono text-xs max-h-60 overflow-y-auto text-gray-300">
            {logs.length === 0 ? <span className="text-gray-600">Waiting to start...</span> : logs.map((l, i) => <div key={i} className="mb-1">{l}</div>)}
        </div>

        {status === 'running' && (
            <div className="w-full bg-gray-800 rounded-full h-2 mb-6">
                <div className="bg-indigo-500 h-2 rounded-full transition-all duration-300" style={{ width: `${progress}%` }}></div>
            </div>
        )}

        <div className="flex justify-end gap-3">
            {status === 'idle' || status === 'error' ? (
                <button 
                    onClick={runMigration}
                    className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-3 rounded-lg font-bold transition-colors"
                >
                    <ArrowRight size={18} /> Start Migration
                </button>
            ) : status === 'running' ? (
                <button disabled className="flex items-center gap-2 bg-gray-700 text-gray-400 px-6 py-3 rounded-lg font-bold cursor-not-allowed">
                    <Loader2 size={18} className="animate-spin" /> Processing...
                </button>
            ) : (
                <button disabled className="flex items-center gap-2 bg-green-600/20 text-green-400 px-6 py-3 rounded-lg font-bold border border-green-600/50">
                    <CheckCircle size={18} /> Done
                </button>
            )}
        </div>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Trash2, Plus, LayoutGrid, Book, AlertTriangle, Users, Pencil, Check, X, Cloud, FileUp, FileDown, Upload, Database, Key, Search, FileJson, FileSpreadsheet, ArrowUpRight, ArrowDownLeft, Clock, Repeat, Building2, ChevronRight, ChevronDown, Folder, Server } from 'lucide-react';
import { Account, TransactionTemplate, AccountClass, Party, PartyType, AccountLevel, Transaction, AppState } from '../types';
import { Modal } from '../components/ui/Modal';
import { format, parseISO } from 'date-fns';
import { supabaseService } from '../services/supabase';
import { excelService } from '../services/excel';
import { evaluateMathExpression } from '../utils/mathUtils';
import { buildAccountTree, AccountNode, flattenTree } from '../utils/accountHierarchy';
import { MigrationTool } from '../components/MigrationTool';

type Tab = 'coa' | 'recurring' | 'templates' | 'parties' | 'sync' | 'profile' | 'migration' | 'danger';

export const Settings: React.FC = () => {
  const { state, dispatch, syncConfig, updateSyncConfig, syncStatus, refreshData, pushDataManual, lastError, user } = useFinance();
  const [activeTab, setActiveTab] = useState<Tab>('coa');

  // Ledger Modal State
  const [viewingLedgerAccountId, setViewingLedgerAccountId] = useState<string | null>(null);

  // Sync State
  const [sbUrl, setSbUrl] = useState(syncConfig.supabaseUrl || '');
  const [sbKey, setSbKey] = useState(syncConfig.supabaseKey || '');

  // Profile State
  const [bizName, setBizName] = useState(state.businessProfile.name);
  const [bizAddress, setBizAddress] = useState(state.businessProfile.address);
  const [bizPhone, setBizPhone] = useState(state.businessProfile.phone);
  const [bizEmail, setBizEmail] = useState(state.businessProfile.email);

  // New Account State
  const [newAccName, setNewAccName] = useState('');
  const [newAccClass, setNewAccClass] = useState<AccountClass>('Expenses');
  const [newAccCode, setNewAccCode] = useState('');
  const [newAccParent, setNewAccParent] = useState('');
  const [newAccLevel, setNewAccLevel] = useState<AccountLevel>('gl');

  // COA Search State
  const [coaSearch, setCoaSearch] = useState('');
  const [expandedNodes, setExpandedNodes] = useState<Record<string, boolean>>({});

  // Editing Account State
  const [editingAccId, setEditingAccId] = useState<string | null>(null);
  const [editingAccName, setEditingAccName] = useState('');

  // Editing Party State
  const [editingPartyId, setEditingPartyId] = useState<string | null>(null);
  const [editingPartyName, setEditingPartyName] = useState('');
  const [editingPartyPhone, setEditingPartyPhone] = useState('');

  // Template State
  const [editingTemplateId, setEditingTemplateId] = useState<string | null>(null);
  const [tempName, setTempName] = useState('');
  const [tempAmount, setTempAmount] = useState('');
  const [tempAccountId, setTempAccountId] = useState('');
  const [tempIcon, setTempIcon] = useState('⚡');
  const [tempPartyId, setTempPartyId] = useState('');
  const [tempPaymentAccountId, setTempPaymentAccountId] = useState('');

  // New Party State
  const [partyName, setPartyName] = useState('');
  const [partyType, setPartyType] = useState<PartyType>('vendor');

  // Refs
  const backupInputRef = useRef<HTMLInputElement>(null);
  const excelInputRef = useRef<HTMLInputElement>(null);

  // --- HIERARCHY LOGIC ---
  const accountTree = useMemo(() => {
      return buildAccountTree(state.accounts, state.transactions);
  }, [state.accounts, state.transactions]);

  const toggleNode = (id: string) => {
      setExpandedNodes(prev => ({ ...prev, [id]: !prev[id] }));
  };

  // Populate expanded nodes on first load or search
  useMemo(() => {
      if (coaSearch) {
          // If searching, expand all
          const allIds: Record<string, boolean> = {};
          state.accounts.forEach(a => allIds[a.id] = true);
          setExpandedNodes(allIds);
      }
  }, [coaSearch, state.accounts]);

  // --- HANDLERS ---

  const handleAddAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAccName || !newAccCode) return;

    // Determine Normal Balance based on Class
    let normalBalance: 'debit' | 'credit' = 'debit';
    if (['Liabilities', 'Equity', 'Revenue'].includes(newAccClass)) {
        normalBalance = 'credit';
    }

    dispatch({ type: 'ADD_ACCOUNT', payload: {
        id: Math.random().toString(36).substr(2, 9),
        name: newAccName,
        class: newAccClass,
        code: newAccCode,
        level: newAccLevel,
        parentId: newAccParent || undefined,
        normalBalance,
        isPosting: newAccLevel === 'gl' || newAccLevel === 'sub_ledger' // Groups are usually non-posting
    }});
    setNewAccName(''); setNewAccCode('');
  };

  // ... (Keep existing handlers for Sync, Profile, Backup, Restore, Excel, Party, Template, Delete, Reset) ...
  const handleSaveSync = (e: React.FormEvent) => { e.preventDefault(); updateSyncConfig({ supabaseUrl: sbUrl, supabaseKey: sbKey, enabled: !!(sbUrl && sbKey) }); alert('Connections Saved'); };
  const handleSaveProfile = (e: React.FormEvent) => { e.preventDefault(); dispatch({ type: 'UPDATE_BUSINESS_PROFILE', payload: { ...state.businessProfile, name: bizName, address: bizAddress, phone: bizPhone, email: bizEmail } }); alert('Profile Saved'); };
  const handleBackup = () => { const dataStr = JSON.stringify(state, null, 2); const link = document.createElement('a'); link.href = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr); link.download = `backup_${format(new Date(), 'yyyy-MM-dd')}.json`; link.click(); };
  const handleExcelExport = () => excelService.exportDataToExcel(state);
  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if(!file)return; const reader=new FileReader(); reader.onload=async(ev)=>{ try{ const json=JSON.parse(ev.target?.result as string); if(confirm("Restore?")) dispatch({type:'SET_STATE', payload:json}); }catch(err){alert("Invalid JSON");}}; reader.readAsText(file); };
  const handleExcelImport = async (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if(!file)return; if(confirm("Overwrite data?")) { try{ const data=await excelService.importDataFromExcel(file); if(data.transactions) dispatch({type:'SET_STATE', payload:{...state, ...data}}); alert("Imported"); }catch(e){alert("Error");}} };
  const startEditingAcc = (acc: Account) => { setEditingAccId(acc.id); setEditingAccName(acc.name); };
  const saveEditingAcc = () => { if(editingAccId) { const orig = state.accounts.find(c => c.id === editingAccId); if(orig) dispatch({ type: 'UPDATE_ACCOUNT', payload: { ...orig, name: editingAccName } }); setEditingAccId(null); } };
  const cancelEditingAcc = () => { setEditingAccId(null); };
  const startEditingParty = (e: Party) => { setEditingPartyId(e.id); setEditingPartyName(e.name); setEditingPartyPhone(e.phone || ''); };
  const saveEditingParty = () => { if(editingPartyId) { const orig = state.parties.find(e => e.id === editingPartyId); if(orig) dispatch({ type: 'UPDATE_PARTY', payload: { ...orig, name: editingPartyName, phone: editingPartyPhone }}); setEditingPartyId(null); } };
  const handleAddParty = (e: React.FormEvent) => { e.preventDefault(); if(!partyName) return; dispatch({ type: 'ADD_PARTY', payload: { id: Math.random().toString(36).substr(2, 9), name: partyName, type: partyType }}); setPartyName(''); };
  const handleDelete = (type: string, id: string) => { if (confirm('Are you sure?')) { if(type === 'ACCOUNT') dispatch({ type: 'DELETE_ACCOUNT', payload: id }); if(type === 'TEMPLATE') dispatch({ type: 'DELETE_TEMPLATE', payload: id }); if(type === 'PARTY') dispatch({ type: 'DELETE_PARTY', payload: id }); if(type === 'RECURRING') dispatch({ type: 'DELETE_RECURRING', payload: id }); } };
  const handleReset = () => { if(confirm('RESET DATA?')) dispatch({ type: 'RESET_DATA' }); };
  const handleSaveTemplate = (e: React.FormEvent) => { e.preventDefault(); if(!tempName || !tempAccountId) return; const amount = evaluateMathExpression(tempAmount); const payload = { id: editingTemplateId || Math.random().toString(36).substr(2,9), name: tempName, accountId: tempAccountId, amount: parseFloat(amount), icon: tempIcon, currency: 'QAR' as const, partyId: tempPartyId, paymentAccountId: tempPaymentAccountId }; if(editingTemplateId) { dispatch({type:'DELETE_TEMPLATE', payload: editingTemplateId}); dispatch({type:'ADD_TEMPLATE', payload}); } else dispatch({type:'ADD_TEMPLATE', payload}); setEditingTemplateId(null); setTempName(''); setTempAmount(''); };
  const startEditingTemplate = (t: TransactionTemplate) => { setEditingTemplateId(t.id); setTempName(t.name); setTempAccountId(t.accountId); setTempAmount(t.amount?.toString()||''); setTempIcon(t.icon||''); setTempPartyId(t.partyId||''); setTempPaymentAccountId(t.paymentAccountId||''); };
  const resetTempForm = () => { setEditingTemplateId(null); setTempName(''); setTempAmount(''); setTempAccountId(''); setTempIcon(''); setTempPartyId(''); setTempPaymentAccountId(''); };

  // Recursive Tree Renderer
  const renderTreeNodes = (nodes: AccountNode[], depth: number = 0) => {
      return nodes.map(node => {
          // Filter if searching
          if (coaSearch) {
              const match = node.name.toLowerCase().includes(coaSearch.toLowerCase()) || node.code.includes(coaSearch);
              // Simple search: show if match, or if children match
              // For full tree search highlighting, logic needs to be complex. 
              // Simplification: If node matches, show it.
              if (!match && node.children.length === 0) return null;
          }

          const hasChildren = node.children.length > 0;
          const isExpanded = expandedNodes[node.id];
          const isGroup = node.level === 'group' || node.level === 'class';

          return (
              <div key={node.id}>
                  <div 
                    className={`flex items-center justify-between p-3 border-b border-gray-800 hover:bg-gray-800/50 transition-colors ${node.level === 'class' ? 'bg-gray-900/80 font-bold' : ''}`}
                    style={{ paddingLeft: `${depth * 20 + 12}px` }}
                  >
                      <div className="flex items-center gap-3 flex-1 overflow-hidden">
                          {/* Expander */}
                          <div className="w-5 flex justify-center">
                            {hasChildren && (
                                <button onClick={() => toggleNode(node.id)} className="text-gray-500 hover:text-white">
                                    {isExpanded || coaSearch ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                                </button>
                            )}
                          </div>

                          <span className={`font-mono text-xs ${isGroup ? 'text-gray-400' : 'text-gray-500'} w-12 shrink-0`}>{node.code}</span>

                          {/* Name / Edit */}
                          {editingAccId === node.id ? (
                                <div className="flex gap-2 flex-1">
                                    <input className="w-full px-2 py-1 bg-gray-950 border border-blue-500 rounded text-sm text-white" value={editingAccName} onChange={e => setEditingAccName(e.target.value)} autoFocus />
                                    <button onClick={saveEditingAcc} className="text-emerald-500"><Check size={16} /></button>
                                    <button onClick={cancelEditingAcc} className="text-red-500"><X size={16} /></button>
                                </div>
                          ) : (
                              <div className="flex items-center gap-2 truncate">
                                  {isGroup && <Folder size={14} className="text-blue-500/50" />}
