import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { supabase } from '../services/supabase';
import { Database, CheckCircle, AlertTriangle, Loader2, ArrowRight, FileJson } from 'lucide-react';
import { Account, Transaction } from '../types';

export const MigrationTool: React.FC = () => {
  const { state, user } = useFinance();
  const [status, setStatus] = useState<'idle' | 'running' | 'success' | 'error'>('idle');
  const [logs, setLogs] = useState<string[]>([]);
  const [progress, setProgress] = useState(0);
  const [jsonInput, setJsonInput] = useState('');
  const [mode, setMode] = useState<'current' | 'paste'>('paste'); // Default to paste for this use case

  const addLog = (msg: string) => setLogs(prev => [...prev, msg]);

  // Helper to generate UUIDs
  const generateUUID = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  const runMigration = async () => {
    if (!user) {
        addLog("Error: You must be logged in to Supabase.");
        setStatus('error');
        return;
    }

    let sourceData: any = state;

    // 1. Determine Source Data
    if (mode === 'paste') {
        if (!jsonInput.trim()) {
            alert("Please paste your JSON data first.");
            return;
        }
        try {
            sourceData = JSON.parse(jsonInput);
            addLog("✅ JSON parsed successfully.");
        } catch (e) {
            addLog("❌ Invalid JSON format. Please check your text.");
            setStatus('error');
            return;
        }
    }

    if (!confirm("This will overwrite/insert data into your SQL tables. Ensure you have run the Schema SQL first. Continue?")) return;

    setStatus('running');
    setLogs([]);
    setProgress(0);

    try {
        const userId = user.id;

        // 1. MAPPING DICTIONARIES (Old ID -> New UUID)
        const accountMap: Record<string, string> = {};
        const partyMap: Record<string, string> = {};

        // Handle Legacy Data Structures
        const rawAccounts = sourceData.accounts || sourceData.categories || [];
        const rawParties = sourceData.parties || sourceData.entities || [];
        const rawAssets = sourceData.assets || [];
        const rawTransactions = sourceData.transactions || [];

        // --- STEP 1: PREPARE ACCOUNTS ---
        addLog(`Step 1: Transforming ${rawAccounts.length} Accounts...`);
        const sqlAccounts = rawAccounts.map((acc: any) => {
            const newId = generateUUID();
            accountMap[acc.id] = newId; // Store mapping
            return {
                id: newId,
                user_id: userId,
                code: acc.code || acc.glCode?.toString() || '0000', // Handle legacy glCode
                name: acc.name,
                class: acc.class || (acc.type === 'income' ? 'Revenue' : (acc.type === 'expense' ? 'Expenses' : 'Assets')), // Fallback mapping
                level: acc.level || 'gl',
                normal_balance: acc.normalBalance || (['Revenue','Liabilities','Equity'].includes(acc.class) ? 'credit' : 'debit'),
                is_posting: acc.isPosting !== undefined ? acc.isPosting : true,
                is_system: acc.isSystem || false,
            };
        });

        // Resolve Parent IDs
        const finalAccounts = sqlAccounts.map((sqlAcc: any) => {
            const sourceAcc = rawAccounts.find((old: any) => accountMap[old.id] === sqlAcc.id);
            let parentId = null;
            if (sourceAcc && sourceAcc.parentId && accountMap[sourceAcc.parentId]) {
                parentId = accountMap[sourceAcc.parentId];
            }
            return { ...sqlAcc, parent_id: parentId };
        });

        if (finalAccounts.length > 0) {
            const { error: accError } = await supabase.from('accounts').upsert(finalAccounts, { onConflict: 'user_id,code' });
            if (accError) throw new Error(`Account Sync Failed: ${accError.message}`);
            addLog(`✅ Synced ${finalAccounts.length} accounts.`);
        }
        setProgress(20);

        // --- STEP 2: PREPARE PARTIES ---
        addLog(`Step 2: Transforming ${rawParties.length} Parties...`);
        const sqlParties = rawParties.map((p: any) => {
            const newId = generateUUID();
            partyMap[p.id] = newId;
            return {
                id: newId,
                user_id: userId,
                name: p.name,
                type: p.type === 'merchant' ? 'vendor' : (p.type || 'other'), // Handle legacy 'merchant' type
                phone: p.phone,
                email: p.email
            };
        });

        if (sqlParties.length > 0) {
            const { error: partyError } = await supabase.from('parties').upsert(sqlParties);
            if (partyError) throw new Error(`Party Sync Failed: ${partyError.message}`);
            addLog(`✅ Synced ${sqlParties.length} parties.`);
        }
        setProgress(40);

        // --- STEP 3: ASSETS ---
        addLog(`Step 3: Transforming ${rawAssets.length} Assets...`);
        const sqlAssets = rawAssets.map((a: any) => ({
            id: generateUUID(),
            user_id: userId,
            name: a.name,
            cost: a.originalValue || a.value,
            purchase_date: a.purchaseDate,
            useful_life_years: a.usefulLifeYears || 5,
            status: 'active',
            linked_gl_account_id: a.linkedAccountId || a.linkedCategoryId ? accountMap[a.linkedAccountId || a.linkedCategoryId] : null
        }));

        if (sqlAssets.length > 0) {
            const { error: assetError } = await supabase.from('assets').upsert(sqlAssets);
            if (assetError) throw new Error(`Asset Sync Failed: ${assetError.message}`);
            addLog(`✅ Synced ${sqlAssets.length} assets.`);
        }
        setProgress(60);

        // --- STEP 4: TRANSACTIONS (JOURNAL ENTRIES) ---
        addLog(`Step 4: Transforming ${rawTransactions.length} Transactions...`);
        const entriesBatch: any[] = [];
        const linesBatch: any[] = [];

        rawTransactions.forEach((t: any) => {
            const entryId = generateUUID();

            // Header
            entriesBatch.push({
                id: entryId,
                user_id: userId,
                date: t.date,
                notes: t.note,
                reference: t.relatedPartyId ? `Ref: ${t.relatedPartyId.substring(0,6)}` : null,
                status: 'posted'
            });

            // Lines Logic
            const isIncome = t.type === 'income';

            // Map legacy categoryId/entityId to accounts/parties
            const accIdA = accountMap[t.accountId || t.categoryId]; 
            const accIdB = accountMap[t.paymentAccountId || ''];

            const partyRef = t.relatedPartyId || t.entityId || t.relatedEntityId;
            const partyId = partyMap[partyRef];

            // Primary Line (Category/Account)
            if (accIdA) {
                const lineA: any = {
                    entry_id: entryId,
                    user_id: userId,
                    account_id: accIdA,
                    description: t.note || 'Transaction Line'
                };

                if (isIncome) lineA.credit = t.amount;
                else lineA.debit = t.amount; 

                if (partyId) {
                    lineA.party_id = partyId;
                }
                linesBatch.push(lineA);
            }

            // Balancing Line (Payment Source)
            if (accIdB) {
                const lineB: any = {
                    entry_id: entryId,
                    user_id: userId,
                    account_id: accIdB,
                    description: 'Offset / Payment'
                };

                if (isIncome) lineB.debit = t.amount; // Money In
                else lineB.credit = t.amount; // Money Out

                linesBatch.push(lineB);
            }
        });

        // Batch Insert Entries
        const chunkSize = 100;
        if (entriesBatch.length > 0) {
            for (let i = 0; i < entriesBatch.length; i += chunkSize) {
                const chunk = entriesBatch.slice(i, i + chunkSize);
                const { error } = await supabase.from('journal_entries').insert(chunk);
                if (error) throw error;
            }
            addLog(`✅ Synced headers for ${entriesBatch.length} transactions.`);
        }
        setProgress(80);

        // Batch Insert Lines
        if (linesBatch.length > 0) {
            for (let i = 0; i < linesBatch.length; i += chunkSize) {
                const chunk = linesBatch.slice(i, i + chunkSize);
                const { error } = await supabase.from('journal_lines').insert(chunk);
                if (error) throw error;
            }
            addLog(`✅ Synced ${linesBatch.length} ledger lines.`);
        }

        setProgress(100);
        setStatus('success');
        addLog("🎉 MIGRATION COMPLETE! Your JSON data is now in SQL.");

    } catch (e: any) {
        console.error(e);
        addLog(`❌ CRITICAL ERROR: ${e.message}`);
        setStatus('error');
    }
  };

  return (
    <div className="bg-black/40 border border-gray-800 rounded-xl p-6 max-w-2xl mx-auto mt-8">
        <div className="flex items-start gap-4 mb-6">
            <div className="p-3 bg-indigo-500/20 rounded-lg text-indigo-400">
                <Database size={24} />
            </div>
            <div>
                <h2 className="text-xl font-bold text-white">Data Migration Tool</h2>
                <p className="text-sm text-gray-400 mt-1">
                    Migrate legacy JSON data to the new Relational SQL Database.
                </p>
            </div>
        </div>

        {/* Mode Toggle */}
        <div className="flex gap-4 mb-4 border-b border-gray-800 pb-4">
            <label className="flex items-center gap-2 text-sm text-gray-300 cursor-pointer">
                <input 
                    type="radio" 
                    name="mode" 
                    value="paste" 
                    checked={mode === 'paste'} 
                    onChange={() => setMode('paste')}
                    className="text-indigo-500"
                />
                <span>Paste JSON (Recommended)</span>
            </label>
            <label className="flex items-center gap-2 text-sm text-gray-300 cursor-pointer">
                <input 
                    type="radio" 
                    name="mode" 
                    value="current" 
                    checked={mode === 'current'} 
                    onChange={() => setMode('current')}
                    className="text-indigo-500"
                />
                <span>Use Current App Data</span>
            </label>
        </div>

        {mode === 'paste' && (
            <div className="mb-6">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Paste JSON Here</label>
                <textarea 
                    value={jsonInput}
                    onChange={e => setJsonInput(e.target.value)}
                    className="w-full h-40 bg-gray-950 border border-gray-800 rounded-lg p-3 text-xs font-mono text-gray-300 focus:border-indigo-500 outline-none resize-none"
                    placeholder='{"accounts": [], "transactions": [] ...}'
                />
            </div>
        )}

        <div className="bg-gray-900 rounded-lg p-4 mb-6 border border-gray-800 font-mono text-xs max-h-60 overflow-y-auto text-gray-300">
            {logs.length === 0 ? <span className="text-gray-600">Logs will appear here...</span> : logs.map((l, i) => <div key={i} className="mb-1">{l}</div>)}
        </div>

        {status === 'running' && (
            <div className="w-full bg-gray-800 rounded-full h-2 mb-6">
                <div className="bg-indigo-500 h-2 rounded-full transition-all duration-300" style={{ width: `${progress}%` }}></div>
            </div>
        )}

        <div className="flex justify-end gap-3">
            {status === 'idle' || status === 'error' ? (
                <button 
                    onClick={runMigration}
                    className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-3 rounded-lg font-bold transition-colors"
                >
                    <ArrowRight size={18} /> {mode === 'paste' ? 'Parse & Migrate' : 'Start Migration'}
                </button>
            ) : status === 'running' ? (
                <button disabled className="flex items-center gap-2 bg-gray-700 text-gray-400 px-6 py-3 rounded-lg font-bold cursor-not-allowed">
                    <Loader2 size={18} className="animate-spin" /> Processing...
                </button>
            ) : (
                <button disabled className="flex items-center gap-2 bg-green-600/20 text-green-400 px-6 py-3 rounded-lg font-bold border border-green-600/50">
                    <CheckCircle size={18} /> Done
                </button>
            )}
        </div>
    </div>
  );
};

