import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { AppState } from '../types';
import { SUPABASE_URL, SUPABASE_KEY } from '../constants';

// Track current credentials to avoid unnecessary client recreation
let currentUrl = SUPABASE_URL;
let currentKey = SUPABASE_KEY;

// Initialize with defaults
let supabaseClient: SupabaseClient = createClient(currentUrl, currentKey);

export const supabaseService = {
  // Allow updating the client at runtime when settings change
  updateClient: (url: string, key: string) => {
    if (!url || !key) return;

    // SINGLETON CHECK: Only recreate if credentials actually changed
    if (url === currentUrl && key === currentKey) {
        return;
    }

    try {
        console.log("Updating Supabase Client connection...");
        currentUrl = url;
        currentKey = key;
        supabaseClient = createClient(url, key);
    } catch (e) {
        console.error("Failed to update Supabase client", e);
    }
  },

  getClient: () => supabaseClient,

  isConnected: () => true, 

  // --- Auth Methods ---
  auth: {
    login: (email: string, password: string) => supabaseClient.auth.signInWithPassword({ email, password }),
    signUp: (email: string, password: string) => supabaseClient.auth.signUp({ email, password }),
    signInWithGoogle: () => supabaseClient.auth.signInWithOAuth({ provider: 'google' }),
    logout: () => supabaseClient.auth.signOut(),
    getUser: async () => {
        const { data: { user } } = await supabaseClient.auth.getUser();
        return user;
    },
    // Wrapper to ensure we subscribe to the *current* client instance
    onAuthStateChange: (callback: (event: any, session: any) => void) => {
        return supabaseClient.auth.onAuthStateChange(callback);
    }
  },

  // --- Data Methods ---
  pullData: async (userId: string): Promise<{ data: AppState | null; error: any }> => {
    try {
      const { data, error } = await supabaseClient
        .from('fintrack_data')
        .select('data')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
          // Special handling for missing table error (Postgres code 42P01)
          if (error.code === '42P01') {
              console.error("CRITICAL: Table 'fintrack_data' is missing in Supabase.");
              return { data: null, error: "Database setup required. Please create 'fintrack_data' table." };
          }
          throw error;
      }

      if (data && data.data) {
          return { data: data.data as AppState, error: null };
      }

      return { data: null, error: null }; // No data found (Fresh account)
    } catch (e: any) {
      console.warn("Supabase Pull Warning:", e.message); 
      return { data: null, error: e.message };
    }
  },

  pushData: async (userId: string, state: AppState): Promise<{ error: any }> => {
    try {
      const { error } = await supabaseClient
        .from('fintrack_data')
        .upsert({ 
            id: userId, 
            data: state, 
            updated_at: new Date().toISOString() 
        }, { onConflict: 'id' });

      if (error) {
          if (error.code === '42P01') {
              return { error: "Missing table 'fintrack_data'. Please run SQL setup." };
          }
          throw error;
      }

      return { error: null };
    } catch (e: any) {
      console.warn("Supabase Push Warning:", e.message);
      return { error: e.message };
    }
  }
};
