export const supabase = supabaseClient;

import { Account, Transaction, AccountClass } from '../types';

export interface AccountNode extends Account {
  children: AccountNode[];
  totalBalance: number; // Aggregated (Self + Children)
  directBalance: number; // Transactions directly tagged to this account
}

/**
 * Calculates the direct balance of a specific account based on transactions.
 * Returns absolute value for display, but respects normal balance logic internally.
 */
export const calculateDirectBalance = (accountId: string, transactions: Transaction[], normalBalance: 'debit' | 'credit'): number => {
  let dr = 0;
  let cr = 0;

  transactions.forEach(t => {
    if (t.accountId === accountId) dr += t.amount;
    if (t.paymentAccountId === accountId) cr += t.amount;
  });

  // If Debit Normal (Assets/Exp): Balance = Dr - Cr
  // If Credit Normal (Liab/Eq/Rev): Balance = Cr - Dr
  const val = normalBalance === 'debit' ? (dr - cr) : (cr - dr);
  return val; 
};

/**
 * Recursively builds a tree of accounts and aggregates balances.
 */
export const buildAccountTree = (
  accounts: Account[], 
  transactions: Transaction[]
): Record<AccountClass, AccountNode[]> => {

  // 1. Initialize Nodes with Direct Balance
  const nodes: Record<string, AccountNode> = {};

  accounts.forEach(acc => {
    const balance = calculateDirectBalance(acc.id, transactions, acc.normalBalance);

    nodes[acc.id] = {
      ...acc,
      children: [],
      directBalance: balance,
      totalBalance: 0
    };
  });

  // 2. Build Tree Structure
  const roots: Record<AccountClass, AccountNode[]> = {
    'Assets': [],
    'Liabilities': [],
    'Equity': [],
    'Revenue': [],
    'Expenses': []
  };

  const orphanNodes: AccountNode[] = [];

  accounts.forEach(acc => {
    const node = nodes[acc.id];
    if (acc.parentId && nodes[acc.parentId]) {
      nodes[acc.parentId].children.push(node);
    } else {
      // It's a root level item (Class or Top Group)
      if (roots[acc.class]) {
        roots[acc.class].push(node);
      } else {
        orphanNodes.push(node);
      }
    }
  });

  // 3. Recursive Aggregation Function
  const aggregate = (node: AccountNode): number => {
    const childSum = node.children.reduce((sum, child) => sum + aggregate(child), 0);
    node.totalBalance = node.directBalance + childSum;
    return node.totalBalance;
  };

  // 4. Trigger Aggregation from Roots
  Object.values(roots).forEach(classList => {
    classList.forEach(rootNode => aggregate(rootNode));
    // Sort by code
    classList.sort((a,b) => a.code.localeCompare(b.code));
  });

  return roots;
};

export const flattenTree = (nodes: AccountNode[]): AccountNode[] => {
    let result: AccountNode[] = [];
    nodes.forEach(node => {
        result.push(node);
        if (node.children.length > 0) {
            result = result.concat(flattenTree(node.children));
        }
    });
    return result;
};

import React, { useMemo, useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, isPast } from 'date-fns';
import { Calendar, FileText, Scale, Users, Download, Activity, Table, ScrollText } from 'lucide-react';
import { StatementOfAccount } from '../components/StatementOfAccount';
import { buildAccountTree, AccountNode } from '../utils/accountHierarchy';

type ReportTab = 'income_statement' | 'balance_sheet' | 'cash_flow' | 'ar_ap' | 'trial_balance' | 'soa';

const formatCurrency = (amount: number) => {
  return amount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2});
};

export const Reports: React.FC = () => {
  const { state } = useFinance();
  const [activeTab, setActiveTab] = useState<ReportTab>('income_statement');
  const [dateRange, setDateRange] = useState({
    start: format(startOfMonth(new Date()), 'yyyy-MM-dd'),
    end: format(endOfMonth(new Date()), 'yyyy-MM-dd')
  });

  const transactionsInPeriod = useMemo(() => {
    return state.transactions.filter(t => {
      const d = parseISO(t.date);
      const start = parseISO(dateRange.start);
      const end = parseISO(dateRange.end);
      end.setHours(23, 59, 59, 999);
      return isWithinInterval(d, { start, end });
    });
  }, [state.transactions, dateRange]);

  // Build Hierarchy for Balance Sheet (Uses ALL transactions up to end date)
  const balanceSheetTree = useMemo(() => {
      // For Balance Sheet, we need cumulative balance up to End Date.
      // We filter transactions first.
      const endDate = parseISO(dateRange.end);
      endDate.setHours(23, 59, 59, 999);

      const bsTransactions = state.transactions.filter(t => parseISO(t.date) <= endDate);
      return buildAccountTree(state.accounts, bsTransactions);
  }, [state.accounts, state.transactions, dateRange.end]);

  // Flat Calculation for Income Statement (Period Only)
  // Note: IS usually doesn't need full hierarchy traversal unless displaying groups, 
  // but let's stick to simple summation for IS to keep it fast.
  const incomeStatement = useMemo(() => {
      const getPeriodBalance = (accountId: string, type: 'revenue' | 'expense') => {
          let bal = 0;
          transactionsInPeriod.forEach(t => {
              if (t.accountId === accountId) bal += t.amount;
              if (t.paymentAccountId === accountId) bal -= t.amount;
          });
          // Rev: Credit Normal (Cr - Dr). Exp: Debit Normal (Dr - Cr)
          return type === 'revenue' ? (bal * -1) : bal;
      };

      const revenueAccs = state.accounts.filter(c => c.class === 'Revenue');
      const expenseAccs = state.accounts.filter(c => c.class === 'Expenses');

      const revenueBreakdown = revenueAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'revenue') })).filter(i => Math.abs(i.amount) > 0.01);
      const expenseBreakdown = expenseAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'expense') })).filter(i => Math.abs(i.amount) > 0.01);

      const totalRevenue = revenueBreakdown.reduce((s, i) => s + i.amount, 0);
      const totalExpenses = expenseBreakdown.reduce((s, i) => s + i.amount, 0);

      // Separate COGS if needed (based on code)
      const cogs = expenseBreakdown.filter(i => i.name.toLowerCase().includes('cost') || i.name.toLowerCase().includes('cogs'));
      const totalCOGS = cogs.reduce((s, i) => s + i.amount, 0);

      return { revenueBreakdown, totalRevenue, expenseBreakdown, totalExpenses, grossProfit: totalRevenue - totalCOGS, netIncome: totalRevenue - totalExpenses };
  }, [transactionsInPeriod, state.accounts]);

  // Helper to render Tree Rows in Report
  const renderReportNode = (nodes: AccountNode[], indent = 0) => {
      return nodes.map(node => (
          <React.Fragment key={node.id}>
              {node.totalBalance !== 0 && (
                  <div className="flex justify-between py-1 border-b border-gray-100 last:border-0 hover:bg-gray-50">
                      <span className={`pl-${indent * 4} ${node.level === 'group' || node.level === 'class' ? 'font-bold text-gray-800' : 'text-gray-600'} text-sm`}>
                          {node.name}
                      </span>
                      <span className={`text-sm font-mono ${node.level === 'group' ? 'font-bold' : ''}`}>
                          {formatCurrency(node.totalBalance)}
                      </span>
                  </div>
              )}
              {node.children.length > 0 && renderReportNode(node.children, indent + 2)}
          </React.Fragment>
      ));
  };

  const getNodeTotal = (nodes: AccountNode[]) => nodes.reduce((s, n) => s + n.totalBalance, 0);

  // Balance Sheet Totals
  const totalAssets = getNodeTotal(balanceSheetTree['Assets']);
  const totalLiabilities = getNodeTotal(balanceSheetTree['Liabilities']);
  const totalEquity = getNodeTotal(balanceSheetTree['Equity']);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        {/* ... (Header & Tab Navigation same as before) ... */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 no-print">
            <div><h1 className="text-3xl font-bold text-white tracking-tight">Financial Reports</h1></div>
            {activeTab !== 'soa' && (
                <div className="flex gap-2 bg-gray-900 p-1 rounded-xl border border-gray-700">
                    <input type="date" value={dateRange.start} onChange={e => setDateRange(prev => ({...prev, start: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                    <span className="text-gray-500">to</span>
                    <input type="date" value={dateRange.end} onChange={e => setDateRange(prev => ({...prev, end: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                </div>
            )}
        </div>

        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar no-print">
            {['income_statement', 'balance_sheet', 'soa'].map(t => (
                <button key={t} onClick={() => setActiveTab(t as ReportTab)} className={`px-4 py-2 rounded-lg text-sm font-medium capitalize ${activeTab === t ? 'bg-primary text-white' : 'bg-gray-800 text-gray-400'}`}>{t.replace('_', ' ')}</button>
            ))}
        </div>

        {activeTab === 'soa' ? <StatementOfAccount appState={state} /> : (
            <div className="glass-card bg-white text-black p-8 rounded-2xl min-h-[600px] shadow-xl">
                <div className="text-center mb-8 border-b border-gray-200 pb-6">
                    <h2 className="text-2xl font-bold text-gray-900 uppercase">{state.businessProfile.name}</h2>
                    <h3 className="text-xl font-medium text-gray-600 mt-2 capitalize">{activeTab.replace('_', ' ')}</h3>
                    <p className="text-sm text-gray-500">As of {dateRange.end}</p>
                </div>

                {activeTab === 'balance_sheet' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-12 max-w-4xl mx-auto">
                        <div>
                            <h4 className="font-bold text-gray-800 border-b-2 border-gray-800 pb-2 mb-4">ASSETS</h4>
                            {renderReportNode(balanceSheetTree['Assets'])}
                            <div className="flex justify-between pt-4 mt-4 font-bold text-lg border-t border-gray-300"><span>TOTAL ASSETS</span><span>{formatCurrency(totalAssets)}</span></div>
                        </div>
                        <div>
                            <h4 className="font-bold text-gray-800 border-b-2 border-gray-800 pb-2 mb-4">LIABILITIES & EQUITY</h4>
                            <div className="mb-6">
                                <h5 className="font-bold text-sm text-gray-500 mb-2 uppercase">Liabilities</h5>
                                {renderReportNode(balanceSheetTree['Liabilities'])}
                                <div className="flex justify-between font-bold text-gray-700 mt-2 pt-2 border-t border-gray-200"><span>Total Liabilities</span><span>{formatCurrency(totalLiabilities)}</span></div>
                            </div>
                            <div>
                                <h5 className="font-bold text-sm text-gray-500 mb-2 uppercase">Equity</h5>
                                {renderReportNode(balanceSheetTree['Equity'])}
                                <div className="flex justify-between font-bold text-gray-700 mt-2 pt-2 border-t border-gray-200"><span>Total Equity</span><span>{formatCurrency(totalEquity)}</span></div>
                            </div>
                            <div className="flex justify-between pt-4 mt-8 font-bold text-lg border-t border-gray-300"><span>TOTAL LIAB & EQUITY</span><span>{formatCurrency(totalLiabilities + totalEquity)}</span></div>
                        </div>
                    </div>
                )}

                {activeTab === 'income_statement' && (
                    <div className="max-w-2xl mx-auto space-y-6">
                        <div><h4 className="font-bold border-b mb-2">REVENUE</h4>{incomeStatement.revenueBreakdown.map(i => <div key={i.name} className="flex justify-between text-sm py-1"><span>{i.name}</span><span>{formatCurrency(i.amount)}</span></div>)}<div className="font-bold flex justify-between mt-2 pt-2 border-t"><span>Total Revenue</span><span>{formatCurrency(incomeStatement.totalRevenue)}</span></div></div>
                        <div><h4 className="font-bold border-b mb-2">EXPENSES</h4>{incomeStatement.expenseBreakdown.map(i => <div key={i.name} className="flex justify-between text-sm py-1"><span>{i.name}</span><span>{formatCurrency(i.amount)}</span></div>)}<div className="font-bold flex justify-between mt-2 pt-2 border-t"><span>Total Expenses</span><span>{formatCurrency(incomeStatement.totalExpenses)}</span></div></div>
                        <div className="bg-gray-900 text-white p-4 rounded-lg flex justify-between font-bold text-xl mt-8"><span>NET INCOME</span><span>{formatCurrency(incomeStatement.netIncome)}</span></div>
                    </div>
                )}
            </div>
        )}
    </div>
  );
};

