  const balanceSheetTree = useMemo(() => {
      // For Balance Sheet, we need cumulative balance up to End Date.
      const endDate = parseISO(dateRange.end);
      endDate.setHours(23, 59, 59, 999);

      const bsTransactions = state.transactions.filter(t => parseISO(t.date) <= endDate);

      // --- NET INCOME INJECTION ---
      // Calculate Net Income (Total Revenue - Total Expenses) up to this date
      // to inject into "Retained Earnings" so the Balance Sheet balances.
      let totalRevenue = 0;
      let totalExpenses = 0;

      state.accounts.forEach(acc => {
          if (!acc.isPosting) return;
          if (acc.class !== 'Revenue' && acc.class !== 'Expenses') return;

          let dr = 0; 
          let cr = 0;
          bsTransactions.forEach(t => {
             if (t.accountId === acc.id) dr += t.amount;
             if (t.paymentAccountId === acc.id) cr += t.amount;
          });

          if (acc.class === 'Revenue') {
              totalRevenue += (cr - dr); // Credit Normal
          } else {
              totalExpenses += (dr - cr); // Debit Normal
          }
      });

      const netIncome = totalRevenue - totalExpenses;

      // Find Retained Earnings Account (Standard code 32000 or by name)
      const retainedEarningsAcc = state.accounts.find(a => a.code === '32000' || a.name === 'Retained Earnings');

      let modifiedTransactions = [...bsTransactions];

      if (retainedEarningsAcc && Math.abs(netIncome) > 0.001) {
          // Create a virtual transaction to adjust Retained Earnings
          // If Profit (Positive NI): Credit Equity
          // If Loss (Negative NI): Debit Equity
          const isProfit = netIncome > 0;
          const virtualTx: Transaction = {
              id: 'virtual_ni_adjustment',
              date: endDate.toISOString(),
              type: 'income',
              amount: Math.abs(netIncome),
              currency: 'QAR',
              source: 'personal',
              // If Profit: Credit RE (paymentAccountId). If Loss: Debit RE (accountId).
              accountId: isProfit ? 'virtual_contra' : retainedEarningsAcc.id,
              paymentAccountId: isProfit ? retainedEarningsAcc.id : 'virtual_contra'
          };
          modifiedTransactions.push(virtualTx);
      }

      return buildAccountTree(state.accounts, modifiedTransactions);
  }, [state.accounts, state.transactions, dateRange.end]);

  // Flat Calculation for Income Statement (Period Only)
  const incomeStatement = useMemo(() => {
      const getPeriodBalance = (accountId: string, type: 'revenue' | 'expense') => {
          let bal = 0;
          transactionsInPeriod.forEach(t => {
              if (t.accountId === accountId) bal += t.amount;
              if (t.paymentAccountId === accountId) bal -= t.amount;
          });
          // Rev: Credit Normal (Cr - Dr). Exp: Debit Normal (Dr - Cr)
          return type === 'revenue' ? (bal * -1) : bal;
      };

      const revenueAccs = state.accounts.filter(c => c.class === 'Revenue');
      const expenseAccs = state.accounts.filter(c => c.class === 'Expenses');

      const revenueBreakdown = revenueAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'revenue') })).filter(i => Math.abs(i.amount) > 0.01);
      const expenseBreakdown = expenseAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'expense') })).filter(i => Math.abs(i.amount) > 0.01);

      const totalRevenue = revenueBreakdown.reduce((s, i) => s + i.amount, 0);
      const totalExpenses = expenseBreakdown.reduce((s, i) => s + i.amount, 0);

      // Separate COGS if needed (based on code)
      const cogs = expenseBreakdown.filter(i => i.name.toLowerCase().includes('cost') || i.name.toLowerCase().includes('cogs'));
      const totalCOGS = cogs.reduce((s, i) => s + i.amount, 0);

      return { revenueBreakdown, totalRevenue, expenseBreakdown, totalExpenses, grossProfit: totalRevenue - totalCOGS, netIncome: totalRevenue - totalExpenses };
  }, [transactionsInPeriod, state.accounts]);

  // Helper to render Tree Rows in Report
  const renderReportNode = (nodes: AccountNode[], indent = 0) => {
      return nodes.map(node => (
          <React.Fragment key={node.id}>
              {node.totalBalance !== 0 && (
                  <div className="flex justify-between py-1 border-b border-gray-100 last:border-0 hover:bg-gray-50">
                      <span className={`pl-${indent * 4} ${node.level === 'group' || node.level === 'class' ? 'font-bold text-gray-800' : 'text-gray-600'} text-sm`}>
                          {node.name}
                      </span>
                      <span className={`text-sm font-mono ${node.level === 'group' ? 'font-bold' : ''}`}>
                          {formatCurrency(node.totalBalance)}
                      </span>
                  </div>
              )}
              {node.children.length > 0 && renderReportNode(node.children, indent + 2)}
          </React.Fragment>
      ));
  };

  const getNodeTotal = (nodes: AccountNode[]) => nodes.reduce((s, n) => s + n.totalBalance, 0);

  // Balance Sheet Totals
  const totalAssets = getNodeTotal(balanceSheetTree['Assets']);
  const totalLiabilities = getNodeTotal(balanceSheetTree['Liabilities']);
  const totalEquity = getNodeTotal(balanceSheetTree['Equity']);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        {/* ... (Header & Tab Navigation same as before) ... */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 no-print">
            <div><h1 className="text-3xl font-bold text-white tracking-tight">Financial Reports</h1></div>
            {activeTab !== 'soa' && (
                <div className="flex gap-2 bg-gray-900 p-1 rounded-xl border border-gray-700">
                    <input type="date" value={dateRange.start} onChange={e => setDateRange(prev => ({...prev, start: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                    <span className="text-gray-500">to</span>
                    <input type="date" value={dateRange.end} onChange={e => setDateRange(prev => ({...prev, end: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                </div>
            )}
        </div>

        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar no-print">
            {['income_statement', 'balance_sheet', 'soa'].map(t => (
                <button key={t} onClick={() => setActiveTab(t as ReportTab)} className={`px-4 py-2 rounded-lg text-sm font-medium capitalize ${activeTab === t ? 'bg-primary text-white' : 'bg-gray-800 text-gray-400'}`}>{t.replace('_', ' ')}</button>
            ))}
        </div>

        {activeTab === 'soa' ? <StatementOfAccount appState={state} /> : (
            <div className="glass-card bg-white text-black p-8 rounded-2xl min-h-[600px] shadow-xl">
                <div className="text-center mb-8 border-b border-gray-200 pb-6">
                    <h2 className="text-2xl font-bold text-gray-900 uppercase">{state.businessProfile.name}</h2>
                    <h3 className="text-xl font-medium text-gray-600 mt-2 capitalize">{activeTab.replace('_', ' ')}</h3>
                    <p className="text-sm text-gray-500">As of {dateRange.end}</p>
                </div>

                {activeTab === 'balance_sheet' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-12 max-w-4xl mx-auto">
                        <div>
                            <h4 className="font-bold text-gray-800 border-b-2 border-gray-800 pb-2 mb-4">ASSETS</h4>
                            {renderReportNode(balanceSheetTree['Assets'])}
                            <div className="flex justify-between pt-4 mt-4 font-bold text-lg border-t border-gray-300"><span>TOTAL ASSETS</span><span>{formatCurrency(totalAssets)}</span></div>
                        </div>
                        <div>
                            <h4 className="font-bold text-gray-800 border-b-2 border-gray-800 pb-2 mb-4">LIABILITIES & EQUITY</h4>
                            <div className="mb-6">
                                <h5 className="font-bold text-sm text-gray-500 mb-2 uppercase">Liabilities</h5>
                                {renderReportNode(balanceSheetTree['Liabilities'])}
                                <div className="flex justify-between font-bold text-gray-700 mt-2 pt-2 border-t border-gray-200"><span>Total Liabilities</span><span>{formatCurrency(totalLiabilities)}</span></div>
                            </div>
                            <div>
                                <h5 className="font-bold text-sm text-gray-500 mb-2 uppercase">Equity</h5>
                                {renderReportNode(balanceSheetTree['Equity'])}
                                <div className="flex justify-between font-bold text-gray-700 mt-2 pt-2 border-t border-gray-200"><span>Total Equity</span><span>{formatCurrency(totalEquity)}</span></div>
                            </div>
                            <div className="flex justify-between pt-4 mt-8 font-bold text-lg border-t border-gray-300"><span>TOTAL LIAB & EQUITY</span><span>{formatCurrency(totalLiabilities + totalEquity)}</span></div>
                        </div>
                    </div>
                )}

                {activeTab === 'income_statement' && (
                    <div className="max-w-2xl mx-auto space-y-6">
                        <div><h4 className="font-bold border-b mb-2">REVENUE</h4>{incomeStatement.revenueBreakdown.map(i => <div key={i.name} className="flex justify-between text-sm py-1"><span>{i.name}</span><span>{formatCurrency(i.amount)}</span></div>)}<div className="font-bold flex justify-between mt-2 pt-2 border-t"><span>Total Revenue</span><span>{formatCurrency(incomeStatement.totalRevenue)}</span></div></div>
                        <div><h4 className="font-bold border-b mb-2">EXPENSES</h4>{incomeStatement.expenseBreakdown.map(i => <div key={i.name} className="flex justify-between text-sm py-1"><span>{i.name}</span><span>{formatCurrency(i.amount)}</span></div>)}<div className="font-bold flex justify-between mt-2 pt-2 border-t"><span>Total Expenses</span><span>{formatCurrency(incomeStatement.totalExpenses)}</span></div></div>
                        <div className="bg-gray-900 text-white p-4 rounded-lg flex justify-between font-bold text-xl mt-8"><span>NET INCOME</span><span>{formatCurrency(incomeStatement.netIncome)}</span></div>
                    </div>
                )}
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useFinance } from '../context/FinanceContext';
import { TransactionType, SourceType, Transaction, CurrencyCode, RecurrenceFrequency, RecurringTransaction } from '../types';
import { EXCHANGE_RATE_QAR_TO_PHP } from '../constants';
import { Check, ArrowRightLeft, LayoutGrid, List, Save, ArrowRight, Repeat } from 'lucide-react';
import { addDays, addMonths, addWeeks, addYears } from 'date-fns';
import { SearchableSelect } from './ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';

interface TransactionFormProps {
  onComplete: () => void;
  initialType?: TransactionType;
  initialData?: Transaction | null;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onComplete, initialType = 'expense', initialData }) => {
  const { state, dispatch } = useFinance();
  const [type, setType] = useState<TransactionType>(initialData?.type || initialType);
  const [amount, setAmount] = useState(initialData ? (initialData.originalAmount || initialData.amount).toString() : '');
  const [currency, setCurrency] = useState<CurrencyCode>(initialData?.currency || 'QAR');
  const [accountId, setAccountId] = useState(initialData?.accountId || '');
  const [source, setSource] = useState<SourceType>(initialData?.source || 'personal');
  const [paymentAccountId, setPaymentAccountId] = useState(initialData?.paymentAccountId || '');
  const [date, setDate] = useState(initialData ? initialData.date.split('T')[0] : new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState(initialData?.note || '');
  const [partyId, setPartyId] = useState(initialData?.relatedPartyId || '');

  // Recurrence State
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');

  const [viewMode, setViewMode] = useState<'form' | 'pos'>('pos');

  useEffect(() => {
    if (initialData) {
        setViewMode('form');
        // If editing an existing Income transaction, we might need to swap back for display if the DB stored them as Dr/Cr correctly
        // But for simplicity in this context, we assume user is editing via this form which expects classification in accountId
        if (initialData.type === 'income' && !state.accounts.find(a => a.id === initialData.accountId)?.class.includes('Revenue')) {
             // Heuristic: If accountId is NOT Revenue (e.g. it's Asset), it was stored as Dr (Bank). 
             // We want to display Revenue in the main select, so we swap back for UI.
             setAccountId(initialData.paymentAccountId || '');
             setPaymentAccountId(initialData.accountId);
        }
    } else {
        const isMobile = window.innerWidth < 768;
        if(isMobile) setViewMode('pos');
    }
  }, [initialData, state.accounts]);

  // AUTO-SET DEFAULT PAYMENT ACCOUNT
  useEffect(() => {
      if (initialData) return; 
      // Assuming 'Cash & Cash Equivalents' or similar parent ID in DEFAULT_ACCOUNTS
      // Searching by name/class for now since IDs might vary if user edited
      const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank'));
      const cash = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('cash'));

      if (type === 'expense') {
          if (bank) setPaymentAccountId(bank.id);
      } else if (type === 'income') {
          if (cash) setPaymentAccountId(cash.id);
      } else if (type === 'transfer') {
          if (bank) setPaymentAccountId(bank.id);
      }
  }, [type, state.accounts, initialData]);

  // DATA TRANSFORMATION FOR SEARCHABLE SELECT
  // We need to map Account Class to Transaction Type roughly for filtering
  const availableAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          if (type === 'transfer') return true; 

          if (type === 'expense') return c.class === 'Expenses' || c.class === 'Liabilities' || c.class === 'Assets'; // buying assets or paying liabilities
          if (type === 'income') return c.class === 'Revenue' || c.class === 'Equity';

          return true;
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code,
          color: undefined // Account doesn't have color prop in new types, can add later
      }));

  const availableParties = state.parties
      .filter(e => e.type === (type === 'income' ? 'customer' : 'vendor')) // Mapping vendor to expense/transfer
      .map(e => ({ id: e.id, label: e.name }));

  const transferSourceAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          if (type === 'transfer') return true;
          // Typically cash accounts
          return c.class === 'Assets'; 
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code
      }));

  const handleAccountChange = (id: string) => {
    setAccountId(id);
    // Logic to auto-detect source based on account could go here if needed
  };

  const handleTemplateClick = (templateId: string) => {
      const t = state.templates.find(temp => temp.id === templateId);
      if(!t) return;

      const acc = state.accounts.find(c => c.id === t.accountId);
      if(acc) {
        // Simple heuristic for type
        const targetType = (acc.class === 'Assets' || acc.class === 'Liabilities') ? 'expense' : (acc.class === 'Revenue' ? 'income' : 'expense');
        setType(targetType as TransactionType);
        setAccountId(acc.id);
        if (t.source) setSource(t.source);
      }

      if(t.amount) setAmount(t.amount.toString());
      setCurrency(t.currency);
      if(t.note) setNote(t.note);
      if(t.partyId) setPartyId(t.partyId);
      if(t.paymentAccountId) setPaymentAccountId(t.paymentAccountId);

      setViewMode('form'); 
  };

  const handleAmountBlur = () => {
      setAmount(evaluateMathExpression(amount));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmountStr = evaluateMathExpression(amount);

    if (!finalAmountStr || !accountId) return;

    if (type === 'transfer' && !paymentAccountId) {
        alert("Please select a 'From' account.");
        return;
    }
    if (type === 'transfer' && accountId === paymentAccountId) {
        alert("From and To accounts cannot be the same.");
        return;
    }

    const inputAmount = parseFloat(finalAmountStr);
    if (isNaN(inputAmount)) {
        alert("Invalid amount");
        return;
    }

    const finalAmountQAR = currency === 'PHP' ? inputAmount / EXCHANGE_RATE_QAR_TO_PHP : inputAmount;

    // --- CRITICAL ACCOUNTING LOGIC ---
    // The Database Invariant is: accountId = DEBIT, paymentAccountId = CREDIT.
    // However, the UI fields change meaning based on transaction type.

    let finalDebitAccount = accountId;
    let finalCreditAccount = paymentAccountId;

    if (type === 'income') {
        // UI: accountId = Revenue (Credit Source)
        // UI: paymentAccountId = Bank/Asset (Debit Destination)
        // Action: SWAP them to match DB Invariant (Dr Asset, Cr Revenue)
        finalDebitAccount = paymentAccountId; // Bank becomes Dr
        finalCreditAccount = accountId;      // Revenue becomes Cr
    } 
    // Expense: UI accountId = Expense (Dr), paymentAccountId = Bank (Cr). Matches DB.
    // Transfer: UI accountId = Destination (Dr), paymentAccountId = Source (Cr). Matches DB.

    // 1. Create the Transaction (Immediate)
    const transactionData: Transaction = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      date: new Date(date).toISOString(),
      type,
      amount: finalAmountQAR,
      originalAmount: inputAmount,
      currency: currency,
      accountId: finalDebitAccount, // DEBIT
      source,
      paymentAccountId: finalCreditAccount || undefined, // CREDIT
      note,
      relatedPartyId: partyId || undefined
    };

    if (initialData) {
        dispatch({ type: 'UPDATE_TRANSACTION', payload: transactionData });
    } else {
        dispatch({ type: 'ADD_TRANSACTION', payload: transactionData });

        // 2. Handle Recurring Rule Creation
        if (isRecurring) {
            let nextDate = new Date(date);
            if (recurFreq === 'daily') nextDate = addDays(nextDate, 1);
            if (recurFreq === 'weekly') nextDate = addWeeks(nextDate, 1);
            if (recurFreq === 'monthly') nextDate = addMonths(nextDate, 1);
            if (recurFreq === 'yearly') nextDate = addYears(nextDate, 1);

            const recurringRule: RecurringTransaction = {
                id: Math.random().toString(36).substr(2, 9),
                active: true,
                type,
                accountId: finalDebitAccount, // Use the correct Dr
                amount: finalAmountQAR,
                originalAmount: inputAmount,
                currency,
                source,
                paymentAccountId: finalCreditAccount || undefined, // Use the correct Cr
                partyId: partyId || undefined,
                note: note,
                frequency: recurFreq,
                nextDueDate: nextDate.toISOString()
            };

            dispatch({ type: 'ADD_RECURRING', payload: recurringRule });
            alert(`Recurring rule created. Next due: ${nextDate.toDateString()}`);
        }
    }
    onComplete();
  };

  return (
    <div className="space-y-4">
        {!initialData && (
            <div className="flex justify-end mb-2">
                <button 
                    onClick={() => setViewMode(viewMode === 'form' ? 'pos' : 'form')}
                    className="text-xs flex items-center gap-1.5 text-primary hover:text-blue-400 font-bold px-4 py-2.5 bg-gray-800 rounded-xl border border-gray-700 glass-card btn-float active:scale-95"
                >
                    {viewMode === 'form' ? <><LayoutGrid size={16} /> Use Shortcuts</> : <><List size={16} /> Manual Entry</>}
                </button>
            </div>
        )}

        {viewMode === 'pos' && !initialData ? (
            <div className="grid grid-cols-2 gap-3 max-h-[60vh] overflow-y-auto no-scrollbar pb-4">
                {state.templates.length === 0 && (
                    <div className="col-span-2 text-center py-12 text-gray-500 text-sm border border-dashed border-gray-700 rounded-2xl flex flex-col items-center gap-3">
                        <LayoutGrid size={32} className="opacity-20" />
                        <div>No shortcuts configured.<br/>Add them in Settings.</div>
                    </div>
                )}
                {state.templates.map(t => (
                    <button
                        key={t.id}
                        onClick={() => handleTemplateClick(t.id)}
                        className="flex flex-col items-center justify-center p-5 bg-gray-800/60 backdrop-blur-md border border-gray-700 hover:border-primary hover:bg-gray-800/80 rounded-2xl transition-all active:scale-95 btn-float group"
                    >
                        <span className="text-4xl mb-3 group-hover:scale-110 transition-transform">{t.icon || '⚡'}</span>
                        <span className="text-sm font-bold text-gray-100 tracking-tight">{t.name}</span>
                        {t.amount && (
                          <span className="text-[10px] text-gold-500/80 font-mono mt-1 px-1.5 py-0.5 bg-gold-500/5 rounded border border-gold-500/10">
                            {t.currency === 'QAR' ? 'QR' : '₱'}{t.amount.toLocaleString()}
                          </span>
                        )}
                    </button>
                ))}
            </div>
        ) : (
            <form onSubmit={handleSubmit} className="space-y-5 animate-fade-in">
                <div className="grid grid-cols-3 gap-2 p-1.5 bg-gray-900/50 rounded-2xl border border-gray-700">
                    <button type="button" onClick={() => { setType('expense'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'expense' ? 'bg-gray-700 text-red-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Expense</button>
                    <button type="button" onClick={() => { setType('income'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'income' ? 'bg-gray-700 text-emerald-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Income</button>
                    <button type="button" onClick={() => { setType('transfer'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'transfer' ? 'bg-gray-700 text-blue-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Transfer</button>
                </div>

                <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Amount Entry</label>
                    <div className="flex gap-2">
                        <div className="relative flex-1">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gold-500 text-xl font-bold">{currency === 'QAR' ? 'QR' : '₱'}</span>
                        <input 
                            type="text" 
                            inputMode="decimal"
                            value={amount} 
                            onChange={(e) => setAmount(e.target.value)} 
                            onBlur={handleAmountBlur}
                            className="w-full pl-12 pr-4 py-4 text-3xl font-bold text-white bg-gray-950 border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary focus:border-transparent outline-none placeholder-gray-800" 
                            placeholder="0.00" 
                            required 
                            autoFocus 
                        />
                        </div>
                        <div className="w-24">
                            <select value={currency} onChange={(e) => setCurrency(e.target.value as CurrencyCode)} className="w-full h-full px-2 bg-gray-950 text-white border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary outline-none font-bold text-center appearance-none">
                                <option value="QAR">QAR</option>
                                <option value="PHP">PHP</option>
                            </select>
                        </div>
                    </div>
                    {currency === 'PHP' && amount && !isNaN(parseFloat(amount)) && (
                        <div className="mt-2 text-[10px] text-gray-500 flex items-center gap-1 ml-2"><ArrowRightLeft size={10} /><span>Converted: ~{ (parseFloat(amount) / EXCHANGE_RATE_QAR_TO_PHP).toFixed(2) } QAR</span></div>
                    )}
                </div>

                {type === 'transfer' ? (
                     <div className="grid grid-cols-1 gap-5 p-5 bg-blue-900/10 border border-blue-500/20 rounded-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-3 opacity-5">
                          <ArrowRightLeft size={64} className="text-blue-500" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">From Account (Credit)</label>
                            <SearchableSelect
                                options={transferSourceAccounts}
                                value={paymentAccountId}
                                onChange={setPaymentAccountId}
                                placeholder="Select Source..."
                                required
                            />
                        </div>
                        <div className="flex justify-center -my-3 relative z-10">
                            <div className="bg-gray-900 border border-blue-500/30 p-2 rounded-full shadow-lg">
                              <ArrowRight className="text-blue-500 rotate-90" size={16} />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">To Account (Debit)</label>
