        <div className="max-w-2xl bg-gray-900 p-6 rounded-2xl border border-gray-800">
            <h3 className="text-lg font-bold text-white mb-4">Cloud Sync (Supabase)</h3>

            <div className="mb-6">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Project URL</label>
                <input className="w-full px-4 py-2 bg-gray-950 border border-gray-700 rounded text-white focus:border-primary outline-none" value={sbUrl} onChange={e => setSbUrl(e.target.value)} placeholder="https://xyz.supabase.co" />
            </div>

            <div className="mb-6">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Anon Key</label>
                <input className="w-full px-4 py-2 bg-gray-950 border border-gray-700 rounded text-white focus:border-primary outline-none" type="password" value={sbKey} onChange={e => setSbKey(e.target.value)} placeholder="eyJh..." />
            </div>

            <button onClick={handleSaveSync} className="bg-primary text-white px-6 py-2 rounded font-bold mb-6">Save Connection</button>

            {/* Manual Controls */}
            {syncConfig.enabled && (
                <div className="border-t border-gray-800 pt-6">
                    <h4 className="text-sm font-bold text-gray-400 mb-4 uppercase">Manual Controls</h4>

                    <div className="flex gap-4">
                        <button 
                            onClick={async () => {
                                if(confirm('Download data from cloud? This might overwrite local unsaved changes.')) {
                                    await refreshData();
                                }
                            }} 
                            className="flex-1 flex items-center justify-center gap-2 bg-gray-800 hover:bg-gray-700 text-blue-400 border border-blue-900/30 px-4 py-3 rounded-lg font-medium transition-colors"
                        >
                            <RefreshCw size={18} /> Force Pull
                        </button>

                        <button 
                            onClick={async () => {
                                if(confirm('Upload local data to cloud? This will overwrite the cloud backup.')) {
                                    await pushDataManual();
                                }
                            }}
                            className="flex-1 flex items-center justify-center gap-2 bg-gray-800 hover:bg-gray-700 text-green-400 border border-green-900/30 px-4 py-3 rounded-lg font-medium transition-colors"
                        >
                            <UploadCloud size={18} /> Force Push
                        </button>
                    </div>

                    {lastError && (
                        <div className="mt-4 p-4 bg-red-900/20 border border-red-900/50 rounded-lg text-red-300 text-xs">
                            <strong className="block mb-1 text-red-200">Sync Error:</strong>
                            {lastError}
                            {String(lastError).includes('fintrack_data') && (
                                <div className="mt-3">
                                    <button onClick={() => setShowSql(!showSql)} className="text-blue-300 underline hover:text-blue-200">
                                        Click here for Database Setup instructions
                                    </button>
                                </div>
                            )}
                        </div>
                    )}

                    {/* Database Setup Helper */}
                    <div className="mt-8 border-t border-gray-800 pt-6">
                        <button 
                             onClick={() => setShowSql(!showSql)}
                             className="text-xs text-gray-500 hover:text-gray-300 flex items-center gap-2 uppercase font-bold tracking-wider"
                        >
                            {showSql ? <ChevronDown size={14}/> : <ChevronRight size={14}/>} Database Setup (Missing Table?)
                        </button>

                        {showSql && (
                            <div className="mt-4 bg-gray-950 p-4 rounded-xl border border-gray-800">
                                <p className="text-sm text-gray-400 mb-3">
                                    If you see a "Missing Table" error, run this SQL in your Supabase SQL Editor to create the required table for JSON sync.
                                </p>
                                <div className="relative group">
                                    <pre className="text-[10px] font-mono text-green-400 bg-black p-3 rounded-lg overflow-x-auto">
                                        {SYNC_SQL}
                                    </pre>
                                    <button 
                                        onClick={() => navigator.clipboard.writeText(SYNC_SQL)} 
                                        className="absolute top-2 right-2 p-1 bg-gray-800 text-gray-400 rounded hover:text-white opacity-0 group-hover:opacity-100 transition-opacity"
                                        title="Copy SQL"
                                    >
                                        <Copy size={14} />
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
      )}

      {activeTab === 'profile' && <div className="max-w-xl bg-gray-900 p-6 rounded-2xl border border-gray-800"><h3 className="text-lg font-bold text-white mb-4">Profile</h3><input className="w-full mb-3 px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded" value={bizName} onChange={e => setBizName(e.target.value)} /><button onClick={handleSaveProfile} className="bg-primary text-white px-6 py-2 rounded">Save</button></div>}
      {activeTab === 'migration' && <MigrationTool />}
      {activeTab === 'recurring' && <div className="text-gray-400 p-4">Manage Recurring Transactions here...</div>}
      {activeTab === 'parties' && <div className="text-gray-400 p-4">Manage Vendors/Customers here...</div>}
      {activeTab === 'templates' && <div className="text-gray-400 p-4">Manage Shortcuts here...</div>}
      {activeTab === 'danger' && <div className="p-4"><button onClick={handleReset} className="bg-red-600 text-white px-6 py-2 rounded">Reset All Data</button></div>}
    </div>
  );
};

# Supabase Setup Guide

This guide provides the SQL scripts to set up your Supabase project.

There are two ways to store data in Tarmi FinTrack:
1. **JSON Sync (Default)**: Stores the entire app state in a single JSON blob. Simplest for offline-first sync.
2. **Relational Schema (Advanced)**: Stores data in normalized tables (Transactions, Accounts, etc.) for analytics.

## 1. Required Setup (JSON Sync)

**You MUST run this SQL block** to enable the core sync functionality of the app. Without this, the app will return "Missing Table" errors.

Copy and paste this into the Supabase SQL Editor:

```sql
-- 1. Create the main data storage table for the app
CREATE TABLE IF NOT EXISTS public.fintrack_data (
    id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,
    data JSONB NOT NULL,
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 2. Enable Row Level Security (RLS)
ALTER TABLE public.fintrack_data ENABLE ROW LEVEL SECURITY;

-- 3. Create Policy: Allow users to manage ONLY their own data
CREATE POLICY "Users can manage own data" ON public.fintrack_data
    FOR ALL
    USING (auth.uid() = id)
    WITH CHECK (auth.uid() = id);
```

---

## 2. Advanced Setup (Relational Schema)

**Optional:** Only run this if you intend to use the "Migration Tool" to convert your data into a relational format for connecting to external BI tools (like PowerBI or Tableau). This is NOT required for the main app to function.

```sql
-- 1. CLEANUP (Optional - Only run if starting fresh)
-- DROP TABLE IF EXISTS public.journal_lines;
-- DROP TABLE IF EXISTS public.journal_entries;
-- DROP TABLE IF EXISTS public.assets;
-- DROP TABLE IF EXISTS public.receivables;
-- DROP TABLE IF EXISTS public.parties;
-- DROP TABLE IF EXISTS public.accounts;
-- DROP TABLE IF EXISTS public.profiles;
-- DROP TYPE IF EXISTS account_class;
-- DROP TYPE IF EXISTS normal_balance;
-- DROP TYPE IF EXISTS entry_status;

-- 2. EXTENSIONS
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- 3. ENUMS
CREATE TYPE account_class AS ENUM ('Assets', 'Liabilities', 'Equity', 'Revenue', 'Expenses');
CREATE TYPE normal_balance AS ENUM ('debit', 'credit');
CREATE TYPE entry_status AS ENUM ('draft', 'posted', 'archived');
CREATE TYPE party_type AS ENUM ('customer', 'vendor', 'employee', 'other');

-- 4. TABLES

-- PROFILES (Links to Supabase Auth)
CREATE TABLE public.profiles (
    id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,
    business_name TEXT,
    email TEXT,
    currency TEXT DEFAULT 'QAR',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- ACCOUNTS (Chart of Accounts)
CREATE TABLE public.accounts (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    code TEXT NOT NULL,
    name TEXT NOT NULL,
    class account_class NOT NULL,
    parent_id UUID REFERENCES public.accounts(id),
    level TEXT CHECK (level IN ('class', 'group', 'gl', 'sub_ledger')),
    normal_balance normal_balance NOT NULL,
    is_posting BOOLEAN DEFAULT TRUE,
    is_system BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, code) -- Prevent duplicate codes per user
);

-- PARTIES (CRM - Vendors/Customers)
CREATE TABLE public.parties (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    name TEXT NOT NULL,
    type party_type DEFAULT 'other',
    email TEXT,
    phone TEXT,
    tax_id TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- JOURNAL ENTRIES (Transaction Headers)
CREATE TABLE public.journal_entries (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    date DATE NOT NULL DEFAULT CURRENT_DATE,
    reference TEXT, -- Invoice #, Check #
    notes TEXT,
    status entry_status DEFAULT 'posted',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- JOURNAL LINES (Debits and Credits)
CREATE TABLE public.journal_lines (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    entry_id UUID REFERENCES public.journal_entries(id) ON DELETE CASCADE NOT NULL,
    account_id UUID REFERENCES public.accounts(id) NOT NULL,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL, -- Denormalized for RLS performance
    description TEXT,
    debit NUMERIC(15, 2) DEFAULT 0,
    credit NUMERIC(15, 2) DEFAULT 0,
    party_id UUID REFERENCES public.parties(id),
    CHECK (debit >= 0 AND credit >= 0),
    CHECK (debit > 0 OR credit > 0) -- Line must have value
);

-- ASSETS (Fixed Assets Registry)
CREATE TABLE public.assets (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    name TEXT NOT NULL,
    purchase_date DATE NOT NULL,
    cost NUMERIC(15, 2) NOT NULL,
    salvage_value NUMERIC(15, 2) DEFAULT 0,
    useful_life_years INT NOT NULL,
    linked_gl_account_id UUID REFERENCES public.accounts(id),
    status TEXT DEFAULT 'active',
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 5. INDEXES
CREATE INDEX idx_accounts_user ON public.accounts(user_id);
CREATE INDEX idx_entries_user_date ON public.journal_entries(user_id, date);
CREATE INDEX idx_lines_entry ON public.journal_lines(entry_id);
CREATE INDEX idx_lines_account ON public.journal_lines(account_id);

-- 6. ROW LEVEL SECURITY (RLS)
-- Crucial: Ensure users only see their own data

ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.accounts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.parties ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.journal_entries ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.journal_lines ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.assets ENABLE ROW LEVEL SECURITY;

-- Policies
CREATE POLICY "Users can all on own profile" ON public.profiles FOR ALL USING (auth.uid() = id);
CREATE POLICY "Users can all on own accounts" ON public.accounts FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own parties" ON public.parties FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own entries" ON public.journal_entries FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own lines" ON public.journal_lines FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users can all on own assets" ON public.assets FOR ALL USING (auth.uid() = user_id);

-- 7. TRIGGER (Auto-create Profile)
CREATE OR REPLACE FUNCTION public.handle_new_user() 
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (id, email)
  VALUES (new.id, new.email);
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE PROCEDURE public.handle_new_user();
```

