# Supabase Setup Guide

This guide provides the SQL scripts to set up your Supabase project.

There are two ways to store data in Tarmi FinTrack:
1. **JSON Sync (Default)**: Stores the entire app state in a single JSON blob. Simplest for offline-first sync.
2. **Relational Schema (Advanced)**: Stores data in normalized tables (Transactions, Accounts, etc.) for analytics.

## 1. Required Setup (JSON Sync)

**You MUST run this SQL block** to enable the core sync functionality of the app. Without this, the app will return "Missing Table" errors.

Copy and paste this into the Supabase SQL Editor:

```sql
-- 1. Create the main data storage table for the app
CREATE TABLE IF NOT EXISTS public.fintrack_data (
    id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,
    data JSONB NOT NULL,
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 2. Enable Row Level Security (RLS)
ALTER TABLE public.fintrack_data ENABLE ROW LEVEL SECURITY;

-- 3. Create Policy: Allow users to manage ONLY their own data
CREATE POLICY "Users can manage own data" ON public.fintrack_data
    FOR ALL
    USING (auth.uid() = id)
    WITH CHECK (auth.uid() = id);
```

---

## 2. Advanced Setup (Relational Schema)

**Optional:** Only run this if you intend to use the "Migration Tool" to convert your data into a relational format for connecting to external BI tools.

**Safe Script (Checks for existing types):**

```sql
-- 1. EXTENSIONS
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- 2. ENUMS (Safe Creation using DO block)
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'account_class') THEN
        CREATE TYPE account_class AS ENUM ('Assets', 'Liabilities', 'Equity', 'Revenue', 'Expenses');
    END IF;

    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'normal_balance') THEN
        CREATE TYPE normal_balance AS ENUM ('debit', 'credit');
    END IF;

    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'entry_status') THEN
        CREATE TYPE entry_status AS ENUM ('draft', 'posted', 'archived');
    END IF;

    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'party_type') THEN
        CREATE TYPE party_type AS ENUM ('customer', 'vendor', 'employee', 'other');
    END IF;
END $$;

-- 3. TABLES

-- PROFILES (Links to Supabase Auth)
CREATE TABLE IF NOT EXISTS public.profiles (
    id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,
    business_name TEXT,
    email TEXT,
    currency TEXT DEFAULT 'QAR',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- ACCOUNTS (Chart of Accounts)
CREATE TABLE IF NOT EXISTS public.accounts (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    code TEXT NOT NULL,
    name TEXT NOT NULL,
    class account_class NOT NULL,
    parent_id UUID REFERENCES public.accounts(id),
    level TEXT CHECK (level IN ('class', 'group', 'gl', 'sub_ledger')),
    normal_balance normal_balance NOT NULL,
    is_posting BOOLEAN DEFAULT TRUE,
    is_system BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, code)
);

-- PARTIES (CRM - Vendors/Customers)
CREATE TABLE IF NOT EXISTS public.parties (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    name TEXT NOT NULL,
    type party_type DEFAULT 'other',
    email TEXT,
    phone TEXT,
    tax_id TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- JOURNAL ENTRIES (Transaction Headers)
CREATE TABLE IF NOT EXISTS public.journal_entries (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    date DATE NOT NULL DEFAULT CURRENT_DATE,
    reference TEXT, -- Invoice #, Check #
    notes TEXT,
    status entry_status DEFAULT 'posted',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- JOURNAL LINES (Debits and Credits)
CREATE TABLE IF NOT EXISTS public.journal_lines (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    entry_id UUID REFERENCES public.journal_entries(id) ON DELETE CASCADE NOT NULL,
    account_id UUID REFERENCES public.accounts(id) NOT NULL,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL, -- Denormalized for RLS
    description TEXT,
    debit NUMERIC(15, 2) DEFAULT 0,
    credit NUMERIC(15, 2) DEFAULT 0,
    party_id UUID REFERENCES public.parties(id),
    CHECK (debit >= 0 AND credit >= 0),
    CHECK (debit > 0 OR credit > 0)
);

-- ASSETS (Fixed Assets Registry)
CREATE TABLE IF NOT EXISTS public.assets (
    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    name TEXT NOT NULL,
    purchase_date DATE NOT NULL,
    cost NUMERIC(15, 2) NOT NULL,
    salvage_value NUMERIC(15, 2) DEFAULT 0,
    useful_life_years INT NOT NULL,
    linked_gl_account_id UUID REFERENCES public.accounts(id),
    status TEXT DEFAULT 'active',
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 4. INDEXES (Safe creation)
CREATE INDEX IF NOT EXISTS idx_accounts_user ON public.accounts(user_id);
CREATE INDEX IF NOT EXISTS idx_entries_user_date ON public.journal_entries(user_id, date);
CREATE INDEX IF NOT EXISTS idx_lines_entry ON public.journal_lines(entry_id);
CREATE INDEX IF NOT EXISTS idx_lines_account ON public.journal_lines(account_id);

-- 5. ROW LEVEL SECURITY (RLS)
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.accounts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.parties ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.journal_entries ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.journal_lines ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.assets ENABLE ROW LEVEL SECURITY;

-- Policies (Drop first to avoid errors on re-run)
DROP POLICY IF EXISTS "Users can all on own profile" ON public.profiles;
CREATE POLICY "Users can all on own profile" ON public.profiles FOR ALL USING (auth.uid() = id);

DROP POLICY IF EXISTS "Users can all on own accounts" ON public.accounts;
CREATE POLICY "Users can all on own accounts" ON public.accounts FOR ALL USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can all on own parties" ON public.parties;
CREATE POLICY "Users can all on own parties" ON public.parties FOR ALL USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can all on own entries" ON public.journal_entries;
CREATE POLICY "Users can all on own entries" ON public.journal_entries FOR ALL USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can all on own lines" ON public.journal_lines;
CREATE POLICY "Users can all on own lines" ON public.journal_lines FOR ALL USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can all on own assets" ON public.assets;
CREATE POLICY "Users can all on own assets" ON public.assets FOR ALL USING (auth.uid() = user_id);

-- 6. TRIGGER (Auto-create Profile)
CREATE OR REPLACE FUNCTION public.handle_new_user() 
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (id, email)
  VALUES (new.id, new.email);
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Drop trigger first to avoid error
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE PROCEDURE public.handle_new_user();
```

import React, { useMemo, useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, isPast } from 'date-fns';
import { Calendar, FileText, Scale, Users, Download, Activity, Table, ScrollText } from 'lucide-react';
import { StatementOfAccount } from '../components/StatementOfAccount';
import { buildAccountTree, AccountNode } from '../utils/accountHierarchy';
import { Transaction } from '../types';

type ReportTab = 'income_statement' | 'balance_sheet' | 'cash_flow' | 'ar_ap' | 'trial_balance' | 'soa';

const formatCurrency = (amount: number) => {
  return amount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2});
};

export const Reports: React.FC = () => {
  const { state } = useFinance();
  const [activeTab, setActiveTab] = useState<ReportTab>('income_statement');
  const [dateRange, setDateRange] = useState({
    start: format(startOfMonth(new Date()), 'yyyy-MM-dd'),
    end: format(endOfMonth(new Date()), 'yyyy-MM-dd')
  });

  const transactionsInPeriod = useMemo(() => {
    return state.transactions.filter(t => {
      const d = parseISO(t.date);
      const start = parseISO(dateRange.start);
      const end = parseISO(dateRange.end);
      end.setHours(23, 59, 59, 999);
      return isWithinInterval(d, { start, end });
    });
  }, [state.transactions, dateRange]);

  // Build Hierarchy for Balance Sheet (Uses ALL transactions up to end date)
  const balanceSheetTree = useMemo(() => {
      // For Balance Sheet, we need cumulative balance up to End Date.
      const endDate = parseISO(dateRange.end);
      endDate.setHours(23, 59, 59, 999);

      const bsTransactions = state.transactions.filter(t => parseISO(t.date) <= endDate);

      // --- NET INCOME INJECTION ---
      // Calculate Net Income (Total Revenue - Total Expenses) up to this date
      // to inject into "Retained Earnings" so the Balance Sheet balances.
      let totalRevenue = 0;
      let totalExpenses = 0;

      state.accounts.forEach(acc => {
          if (!acc.isPosting) return;
          if (acc.class !== 'Revenue' && acc.class !== 'Expenses') return;

          let dr = 0; 
          let cr = 0;
          bsTransactions.forEach(t => {
             if (t.accountId === acc.id) dr += t.amount;
             if (t.paymentAccountId === acc.id) cr += t.amount;
          });

          if (acc.class === 'Revenue') {
              totalRevenue += (cr - dr); // Credit Normal
          } else {
              totalExpenses += (dr - cr); // Debit Normal
          }
      });

      const netIncome = totalRevenue - totalExpenses;

      // Find Retained Earnings Account (Standard code 32000 or by name)
      const retainedEarningsAcc = state.accounts.find(a => a.code === '32000' || a.name === 'Retained Earnings');

      let modifiedTransactions = [...bsTransactions];

      if (retainedEarningsAcc && Math.abs(netIncome) > 0.001) {
          // Create a virtual transaction to adjust Retained Earnings
          // If Profit (Positive NI): Credit Equity
          // If Loss (Negative NI): Debit Equity
          const isProfit = netIncome > 0;
          const virtualTx: Transaction = {
              id: 'virtual_ni_adjustment',
              date: endDate.toISOString(),
              type: 'income',
              amount: Math.abs(netIncome),
              currency: 'QAR',
              source: 'personal',
              // If Profit: Credit RE (paymentAccountId). If Loss: Debit RE (accountId).
              accountId: isProfit ? 'virtual_contra' : retainedEarningsAcc.id,
              paymentAccountId: isProfit ? retainedEarningsAcc.id : 'virtual_contra'
          };
          modifiedTransactions.push(virtualTx);
      }

      return buildAccountTree(state.accounts, modifiedTransactions);
  }, [state.accounts, state.transactions, dateRange.end]);

  // Flat Calculation for Income Statement (Period Only)
  const incomeStatement = useMemo(() => {
      const getPeriodBalance = (accountId: string, type: 'revenue' | 'expense') => {
          let bal = 0;
          transactionsInPeriod.forEach(t => {
              if (t.accountId === accountId) bal += t.amount; // Debit
              if (t.paymentAccountId === accountId) bal -= t.amount; // Credit
          });

          if (type === 'revenue') {
              // Forced Positive for Presentation
              // Uses Math.abs to ensure revenue is always shown as positive, even if data was entered with wrong sign.
              return Math.abs(bal); 
          } else {
              // Forced Negative for Presentation
              // Expenses are shown as negative values.
              return -Math.abs(bal);
          }
      };

      const revenueAccs = state.accounts.filter(c => c.class === 'Revenue');
      const expenseAccs = state.accounts.filter(c => c.class === 'Expenses');

      const revenueBreakdown = revenueAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'revenue') })).filter(i => Math.abs(i.amount) > 0.01);
      const expenseBreakdown = expenseAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'expense') })).filter(i => Math.abs(i.amount) > 0.01);

      const totalRevenue = revenueBreakdown.reduce((s, i) => s + i.amount, 0);
      const totalExpenses = expenseBreakdown.reduce((s, i) => s + i.amount, 0); // This sums negative numbers

      // Separate COGS if needed (based on code)
      const cogs = expenseBreakdown.filter(i => i.name.toLowerCase().includes('cost') || i.name.toLowerCase().includes('cogs'));
      const totalCOGS = cogs.reduce((s, i) => s + i.amount, 0); // Negative Sum

      // Net Income = Revenue (Pos) + Expenses (Neg)
      return { 
          revenueBreakdown, 
          totalRevenue, 
          expenseBreakdown, 
          totalExpenses, 
          grossProfit: totalRevenue + totalCOGS, 
          netIncome: totalRevenue + totalExpenses 
      };
  }, [transactionsInPeriod, state.accounts]);

  // Helper to render Tree Rows in Report
  const renderReportNode = (nodes: AccountNode[], indent = 0) => {
      return nodes.map(node => (
          <React.Fragment key={node.id}>
              {node.totalBalance !== 0 && (
                  <div className="flex justify-between py-1 border-b border-gray-100 last:border-0 hover:bg-gray-50">
                      <span className={`pl-${indent * 4} ${node.level === 'group' || node.level === 'class' ? 'font-bold text-gray-800' : 'text-gray-600'} text-sm`}>
                          {node.name}
                      </span>
                      <span className={`text-sm font-mono ${node.level === 'group' ? 'font-bold' : ''}`}>
                          {formatCurrency(node.totalBalance)}
                      </span>
                  </div>
              )}
              {node.children.length > 0 && renderReportNode(node.children, indent + 2)}
          </React.Fragment>
      ));
  };

  const getNodeTotal = (nodes: AccountNode[]) => nodes.reduce((s, n) => s + n.totalBalance, 0);

  // Balance Sheet Totals
  const totalAssets = getNodeTotal(balanceSheetTree['Assets']);
  const totalLiabilities = getNodeTotal(balanceSheetTree['Liabilities']);
  const totalEquity = getNodeTotal(balanceSheetTree['Equity']);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        {/* ... (Header & Tab Navigation same as before) ... */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 no-print">
