                            <span>NET INCOME</span>
                            <span className={incomeStatement.netIncome >= 0 ? 'text-emerald-400' : 'text-red-400'}>
                                {formatCurrency(incomeStatement.netIncome)}
                            </span>
                        </div>
                    </div>
                )}
            </div>
        )}
    </div>
  );
};
